// AUTO-GENERATED by scripts/gen-chapters.py — 正文逐字转录自 docs/，请勿手改。
import type { ChapterBody } from './types'

export const chapterBodies: Record<string, ChapterBody> = {
  "ch1": {
    title: "第一章：琥珀之门的咆哮",
    endMark: "【第一章 完】",
    blocks: [
      { kind: "p", text: "琥珀门的夜晚从来不会真正安静。潮声、船歌、码头上的咒骂、运河里咸湿的回响，一层叠着一层，像这座城市永远睡不着的呼吸。但今晚，在那些熟悉的喧嚣之下，还藏着某种更古老的东西——一种来自深海、来自先民遗迹、来自某股沉睡了上千年的愤怒的震颤。" },
      { kind: "p", text: "双卫星阿塔与艾蒂悬在云层之外，一明一暗，像两只窥视人间的眼睛。暗瞳格里人视三星连珠为吉兆，可今夜，阿格莫尼亚与双星之间隔着的不仅是浓雾，还有一种正在酝酿的、令人牙酸的不安。" },
      { kind: "p", text: "**微光鱿鱼旅馆**蜷缩在港口边缘，像一头被海水泡软了脊梁的老兽。它的外墙糊满风干海藻与贝壳灰，招牌上那只用荧光漆涂抹的巨型鱿鱼在夜风里吱呀摇晃，触手一摆一摆，仿佛想从木板上挣脱出来。旅馆内，壁炉里的炭火刚刚熄灭，余温里还煨着烤盐鱼的焦香、海藻麦酒的酸醇，以及暗瞳格里旅客们脱在门边的靴子里那股永不散去的咸腥。" },
      { kind: "p", text: "**露娜拉·布林德利昂**坐在靠窗的位置，指尖一遍遍擦过盾面。那面从星轮山带出来的旧盾已经补过三次，边缘的飞龙纹章被岁月磨得只剩模糊的轮廓。她银白色的长发垂在肩头，在昏暗烛光下像一泓被搅浑的月光；身后的尾巴——暗瞳格里人引以为傲的敏捷尾巴——正在椅子底下无意识地拍打地面，越拍越快，泄露了主人自己都未必肯承认的焦躁。" },
      { kind: "p", text: "三个月前，她还是布林德利昂家族的骑士统领，统率星轮山的家族卫队，一声令下便可调动整队披甲的骑士。她的母亲——那位统治家族的女主人——曾把两个姐姐嫁入豪门，用政治联姻为她们铺平继承人的道路；轮到露娜拉时，摆在桌上的也是同一套说辞：要“懂事”，要在需要的时候嫁给敌对家族的继承人，用一纸婚约换取领地或矿产。她拒绝了那场阴谋，策马离开星轮山，想为母亲争取一点周旋的时间。" },
      { kind: "p", text: "她回到星轮山时，只看见母亲倒在血泊中。而她，成了凶手。" },
      { kind: "p", text: "暗瞳格里贵族对待叛徒从不手软——一旦被捕，项上人头与身后的尾巴都难保。她别无选择，只能逃亡。温室里长大的贵族之女，如今穿着不合身的二手锁甲，兜里只剩几枚月光银，正一点点学着过贫穷流浪战士的日子：忍受旅馆的床虱、街头的臭气，以及那些把她当作普通佣兵呼来喝去的目光。三天前在码头上，一个醉汉抡起椅子砸在她的盾上，她默默受了。流亡的圣骑士没有追究的资格。她唯一不能丢的，是布林德利昂家族的名誉，以及寻回祖传“飞龙之鳞盾牌”的希望——那是证明她清白的唯一可能。" },
      { kind: "p", text: "窗外，琥珀门的运河泛着油腻的波光。远处渔民的号子突然断了，像是被某种力量掐住了喉咙。" },
      { kind: "p", text: "“……你们有没有觉得，”角落阴影里传来一个压低的声音，“今晚的鱼腥气里，混着点别的味道？”" },
      { kind: "p", text: "**祖法赛**缩在角落，珂蓝安人特有的淡蓝色皮肤在烛光下几乎透明，像一截被泡发的海草。他在凡提·玛夏克讨生活——那座竞争极其残酷的水下城市，整个泽布尔海邦利益驱动的缩影。尽管心灵感应的天赋让他与众不同，他谋得的差事却是审查外国文献——“真理赐者”所能担任的最低级职位：每天把别人写好的谎言盖上许可章，再领一份勉强够活命的薪水，日复一日。" },
      { kind: "p", text: "他的手指始终没有离开怀中那个用油布裹了三层的小包——里面藏着贝科拉之杖的第一块碎片。发现这柄古老法杖的秘密时，他第一时间算出的是它能值多少钱；可另一个念头也随之缠上了他：或许，该用它把人民从造物主的暴政下解放出来？毕竟，整个社会会不会一直建立在他亲手盖过章的那些谎言之上？这笔账，他至今没有算清。" },
      { kind: "p", text: "而现在，思缚者——那些为造物主佩桑娜效力的灵能秘密警察——正对他穷追不舍，要把碎片夺回去，献给他曾经效力的人。祖法赛把斗篷拢得更紧了些，在心里默默盘算：真被思缚者堵住的那一刻，是先跳进运河，还是先把手杖碎片塞进某个倒霉路人的口袋。这种本能早已刻进骨头——在泽布尔海邦的底层待久了，谁都得学会给自己留一条后路，最好是两条。" },
      { kind: "p", text: "“别问。”坐在他对面的**乔奈·贾维安**头也不抬。她没有摘头盔——那顶发光的头盔在昏暗的旅馆里像一盏不合时宜的灯笼，引得隔壁桌的暗瞳格里水手频频侧目，又被她周身那股生人勿近的气场逼了回去。" },
      { kind: "p", text: "她在琥珀门贫穷的暗瞳格里渔民中长大，自己却并非暗瞳格里人——事实上，没人知道她是什么种族，也没人知道她来自何方。唯一确定的是，她与艾伊恩和暗克苏两股魔法力量之间，似乎存在着某种特殊的联系。一位盲眼长者把她带大，教会她使用阿格莫尼亚几乎所有的武器。导师本希望她将一生奉献给对抗恶魔的事业；但对乔奈来说，先从那些榨取同胞苦难的罪恶领主手中，护住她的女友和街坊邻居，更要紧。" },
      { kind: "p", text: "于是夜里的琥珀门多了一位蒙面的暗影复仇者，专找罪恶领主的麻烦。那身发光的披风与头盔，正是她体内艾伊恩之力的显化。然而此刻，连艾伊恩的光芒都让她坐立难安——空气中那股气息不是普通的黑暗，而是某种更古老的东西正在苏醒。她放在桌下的手早已按上短剑柄，那是盲眼长者留给她的最后一把武器。" },
      { kind: "p", text: "“闻到了。不是鱼。是……门。”" },
      { kind: "p", text: "“门？”祖法赛挑眉。" },
      { kind: "p", text: "“琥珀之门。”乔奈的声音从头盔下传出，闷闷的，像隔着一层水，“它在呼吸。而且呼吸得很痛苦。”" },
      { kind: "p", text: "而**泰拉克斯**——那块会走路的石头——正站在门口，背对着所有人，像一堵听话的墙。奥古拉人不需要睡眠；他们的躯体是岩石，记忆本应一刀一刀刻在皮肤上。可泰拉克斯身上的符文已被磨平，他不知道自己是谁。导师们因背上生长出的魔法水晶惨遭杀害之后，他便踏上了寻找前世真相的旅程——那个秘密埋藏在失落的奥古拉城市洛克托尔，而世上只有他能找到那里，尽管他并不记得自己为什么能。" },
      { kind: "p", text: "此刻，他背脊上曾经生长奥古拉水晶的位置传来一阵隐隐的刺痛。水晶早已不在，被某个他记不清面容的人剜走了，只留下一道连岩石都无法自愈的旧伤。可那种遥远的共鸣还在——像有人在洛克托尔的深处呼唤他的名字，尽管他已经忘了那个名字。他伸出手，按在门柱那块风化的石雕上，试图从冰冷的石头里读出点什么。石头没有回答。只有本能告诉他：城门方向，有什么东西正在改变。" },
      { kind: "p", text: "他缓缓转过身，望向城市中心那个巨大的圆形通道。" },
      { kind: "p", text: "然后，**琥珀之门**被打开了。" },
      { kind: "p", text: "不是涨潮。不是暴雨。是某种沉睡千年的先民装置被意外激活——巨大的圆形通道喷涌出灰色的海水，仿佛整个泽布尔海邦被一只无形的巨手掀起，又狠狠砸向琥珀门。海水里卷着海藻、断桅、不知名的深海鳞片，以及一股腥甜的气息——乔奈头盔上的光芒，在闻到它的那一瞬骤然暗了暗。第一声轰鸣传来时，微光鱿鱼旅馆的地板猛地一跳，吧台后的酒瓶像受惊的鸟群般扑落，碎裂声还未散尽，便被紧随其后的第二声轰鸣整个吞没。" },
      { kind: "p", text: "“水！”有人尖叫。" },
      { kind: "p", text: "那是一堵裹挟着断木、死鱼和深海腥臭的灰色巨墙。旅馆的木质外墙发出令人牙酸的呻吟，地基在颤抖，墙壁在弯曲，天花板上的灰泥簌簌而下，像下了一场苍白的雪。碎裂的窗户外，冰冷的水浪劈头拍在露娜拉脸上，带着盐、腐木，以及某种她从未闻过的、属于先民机械的金属锈味。" },
      { kind: "p", text: "“撤离！”露娜拉的声音一刀切开混乱。她一跃而起，旧盾本能地护在身前，暗瞳格里人锋利的牙齿在怒吼中微露。骑士统领的本能压过了流亡者的疲惫——先救人，再问罪。这是母亲教她的第一课，也是流亡三个月来，她唯一没有丢掉的东西。" },
      { kind: "p", text: "门口还站着一名五瞳教派的祭祀——一个裹着深紫色长袍的暗瞳格里老人。五瞳教派自十余年前先民装置陆续启动后势力大增，信徒们坚信，在现代种族之前，这片土地上存在过更古老的主人。老人枯瘦的双手死死抱着一口沉重的铁箱，箱盖上刻着五只眼睛的图腾——那是先民遗物的标志。洪水已经漫过他的脚面，他却像生了根。" },
      { kind: "p", text: "“走！”露娜拉伸出手，但祭祀后退了一步。" },
      { kind: "p", text: "“这是先民圣物……不能落入洪水……”" },
      { kind: "p", text: "“听着，”露娜拉深吸一口气，星轮山布林德利昂家族传承的威严从她疲惫的躯壳里苏醒过来。她的尾巴停止了摆动，整个人像一柄缓缓出鞘的剑，“我不会碰它，我只帮你把它带到安全的地方。你的五瞳之神要的，是你活着守护它——不是抱着它一起烂在水里。”" },
      { kind: "p", text: "——何况，她心底有个声音在说，一件先民遗物，或许哪天能为她洗刷冤屈提供某种佐证。流亡者太需要任何形式的证据了。哪怕这箱子里装的只是五瞳教派的古董，它至少能证明：星轮山那一夜之后，她从未对别人的危难袖手旁观。" },
      { kind: "p", text: "祭祀终于颤抖着松开了手。露娜拉一把将沉重的铁箱扛上肩头——那重量压得她膝盖微微一弯，但圣骑士的脊梁没有弯。" },
      { kind: "p", text: "就在这时，吧台方向传来了一声细微的呜咽。" },
      { kind: "p", text: "旅馆侍女斯黛拉正跪在吧台下方，急得直掉眼泪。吧台的裂缝深处，缩着一只浑身覆盖发光菌丝的小东西——**觅奇兽**，一种以敏锐嗅觉著称、能透过土壤感知神秘能量的生物，此刻五只眼睛惊恐地圆睁。它感知到的东西比所有人都多：这不是普通的洪水，而是琥珀之门下先民能量的暴走。" },
      { kind: "p", text: "“小菌……它怕水，它从来不敢碰水……”斯黛拉颤抖着说。" },
      { kind: "p", text: "露娜拉蹲下身，将旧盾轻轻斜靠在裂缝旁，为它隔出一方干燥的小天地：“没事了，小菌。水不会碰到你。”" },
      { kind: "p", text: "也许是盾面挡住了水光，也许是那声音里的温柔穿透了恐惧。觅奇兽慢慢挪了出来，五只眼睛泪汪汪地仰望着露娜拉。她将它轻轻捧起，塞进斯黛拉怀里，然后重新扛起铁箱。" },
      { kind: "p", text: "“往上城走！”她回头对祖法赛喊道，“那边地势高！”" },
      { kind: "p", text: "“楼上那位朋友怎么办？”祖法赛指了指二楼，声音里带着珂蓝安人特有的算计，“救他有没有报酬？”" },
      { kind: "p", text: "“先救人，再谈钱！”露娜拉头也不回。" },
      { kind: "p", text: "二楼传来一声嘶哑的呼喊。一个独眼的焰龙蜥——**圣托尔·三羽**，后来他们才知道，这位竟是传说中的裂隙守护者、阿格莫尼亚英雄们的导师——正从客房窗口探出身子：" },
      { kind: "p", text: "“我的手稿！在马厩里！那卷羊皮手稿——请帮我取出来！”" },
      { kind: "p", text: "“马厩！”祖法赛抬头喊道，“我们这就去！”" },
      { kind: "p", text: "“先找船！”泰拉克斯的吼声从门口传来。奥古拉人已经冲到了码头——他背脊上曾经生长水晶的位置再次刺痛，像一枚指路的针：码头某处，有一件先民遗物。" },
      { kind: "p", text: "他看到了它：一叶**石质扁舟**，船头雕刻着奥古拉符文，半截埋在淤泥里，像一截被遗忘的骨头。泰拉克斯弯下腰，岩石手臂发力——" },
      { kind: "p", text: "“起！”" },
      { kind: "p", text: "被淤泥纠缠了不知多少年的扁舟被硬生生拽了出来。手掌触到船舷符文的一瞬，一阵刺痛般的熟悉感顺着手臂窜上脊背——那是奥古拉水晶驱动过的痕迹，是他失落的种族记忆，是他想不起名字、却刻在骨子里的故乡。他第一次觉得，用身体铸造武器、找回身份的那条路，或许正要从这一叶石舟开始。" },
      { kind: "p", text: "“别发呆！帮忙！”露娜拉护着斯黛拉、小菌和铁箱冲到码头边缘。泰拉克斯将扁舟推入水中——石船稳稳浮在浊浪之上，像一片拒绝沉没的叶子。" },
      { kind: "p", text: "“我宁可相信它沉不下去，”祖法赛一边把斯黛拉扶上船，一边嘀咕，“毕竟我没付船票。”" },
      { kind: "p", text: "“你现在欠它一条命。”乔奈从他身边掠过，发光的披风在雨幕中划出一道弧线。" },
      { kind: "p", text: "但还有人在旅馆里。" },
      { kind: "hr", text: "" },
      { kind: "p", text: "祖法赛站在马厩门口，水已经漫到腰际。珂蓝安人的心灵感应在洪水的咆哮中几乎失灵——太多恐惧，太多尖叫，太多濒死的念头，像碎玻璃一样扎进他的脑海。他的小腿被水流里的碎木撞得生疼，冰冷的液体灌进靴子，每一步都像在泥浆里拔桩。门后是一头**驼格尔**——那种长着驼峰、被视为贝纳姆共和国非官方象征的巨型驮兽——此刻正惊恐地尥着蹶子，蹄子把地面刨出一道道泥沟。" },
      { kind: "p", text: "“该死……”祖法赛低声咒骂。他回头看了一眼——旅馆主楼已经开始倾斜，像一只被水泡软的靴子。他在心里迅速拨起了算盘：救一头驼格尔，还是救自己？答案很快算了出来：楼上那位独眼客若有闪失，他们四个今晚谁都别想离开这座死城；而他的牲口、他的手稿，就是买通这条生路的筹码。这笔买卖，不得不做。" },
      { kind: "p", text: "“这边！”泰拉克斯的声音穿透了轰鸣。石头人指向马厩墙壁下方——一个被杂草遮掩的小洞，大小刚好够一个暗瞳格里人钻进去。" },
      { kind: "p", text: "“乔奈！”" },
      { kind: "p", text: "头盔下的乔奈没有半分犹豫。她像一道发光的影子掠过水面，矮身钻进那个散发着陈年马粪味的小洞。" },
      { kind: "p", text: "洞内昏暗潮湿，驼格尔那双比人头还大的眼睛正死死瞪着她。而在草料堆的角落里，她看到了那卷泛黄的羊皮手稿——圣托尔·三羽的研究心血。手稿上绘满复杂的符文与星图，边缘被水渍浸出褐色的痕，像一幅残缺的古地图。" },
      { kind: "p", text: "“泰拉克斯！”乔奈趴在洞口，将手稿从那个小洞里塞了出去，“接着！”" },
      { kind: "p", text: "洞外，泰拉克斯的岩石大手稳稳地接住。他小心翼翼地将手稿护在胸前，动作轻得像捧着一块蛋壳。" },
      { kind: "p", text: "乔奈转身用身体护住草料堆，免得受惊的巨兽把散落的纸页踏进泥里。与此同时，祖法赛从后门绕入，指尖泛起幽蓝的微光，将意识探入驼格尔混乱的思绪——安抚，不是控制。思缚者喜欢控制，但他不是思缚者。至少今晚不是。今晚他只是另一个想从洪水里活下来的人，一个还想活过明天的审查员。他在驼格尔的脑海里放下一个最简单的念头，简单得像一句哄孩子的话：跟眼前这个戴头盔的走，就能活。" },
      { kind: "p", text: "驼格尔停止了尥蹶子。" },
      { kind: "p", text: "乔奈在前牵引，祖法赛在侧护持，一人一心念，总算把巨兽从后门引了出来。泰拉克斯在关键时刻俯身探臂——岩石手臂插进驼格尔腹下，像撬动一块山岩般，硬生生将整头驮兽抬上了扁舟。石船剧烈一晃，吃水深得吓人，却奇迹般地没有倾覆。露娜拉在船尾稳住铁箱，用旧盾压住船舷，替所有人挡住劈头盖脸的浪头。" },
      { kind: "p", text: "“你猜它载重几吨？”祖法赛问。" },
      { kind: "p", text: "“现在不是问这个的时候！”露娜拉吼道。" },
      { kind: "p", text: "然而洪水不打算给他们喘息的机会。石质扁舟在狂暴的洪流中如同一片卷入漩涡的落叶，巨浪一次次将他们拍向倾斜的屋脊；冰冷的水花溅进船舱，咸腥的水气糊了每个人一脸。驼格尔不安地刨着蹄子，小菌的五只眼睛全部瞪圆，发出高频的尖啸——它还在感知那股暴走的先民能量，而且那能量越来越近。" },
      { kind: "p", text: "“撑不住了！”露娜拉死死抓住船舷，指节发白。" },
      { kind: "p", text: "“往高处划！”乔奈把短剑当作船桨，奋力拨开水面上的杂物，披风上的微光在雨幕里明明灭灭，像随时会熄灭。" },
      { kind: "p", text: "“往哪儿高？！”祖法赛抱着船舷，另一只手死死按住怀里的碎片，“这城里最高的地方是邓高特家族的船坞堡，你想去敲他们的大门吗？”" },
      { kind: "p", text: "“我宁可被邓高特家吊死，也不愿被淹死！”" },
      { kind: "p", text: "泰拉克斯没说话。他只是把岩石手臂横在船头与迎面撞来的一段断木之间。断木在他肩上崩裂，碎屑溅了他一脸。他连眼睛都没眨——反正也是石头做的。" },
      { kind: "p", text: "就在这时，天空传来一阵机械与魔法交织的嗡鸣。" },
      { kind: "p", text: "那不是雷声。那是“**小鸟号**”——一辆由黑铁与古木打造的飞行马车，两侧展开巨大的金属羽翼，每一次扇动都拖出淡蓝色的魔力尾迹。驱动它的核心，正是一颗**奥古拉水晶**。" },
      { kind: "p", text: "驾驶座上站着的正是圣托尔·三羽。她的独眼在风雨中燃烧着坚定的光芒——那是裂隙守护者的眼神。" },
      { kind: "p", text: "“看来，你们需要有人载你们一程！”" },
      { kind: "p", text: "绳梯抛了下来。泰拉克斯用岩石手臂锚住绳梯下端，任凭风浪撕扯也纹丝不动，让惊魂未定的普通人一个个攀上去。斯黛拉哭着抓住绳索，小菌把脸埋进主人的衣领。五瞳教派祭祀紧抱着他的先民铁箱，嘴里念念有词，不知是在祈祷，还是在道歉。" },
      { kind: "p", text: "“你先上。”露娜拉对祖法赛说。" },
      { kind: "p", text: "“为什么是我？”" },
      { kind: "p", text: "“因为你最会算账，”露娜拉面无表情，“如果我们中必须有人最后一个离开，我希望那个人能准确算出自己欠大家多少人情——一笔一笔，连本带利。”" },
      { kind: "p", text: "祖法赛翻了个白眼，攀上了绳梯。" },
      { kind: "p", text: "他最后一个离开扁舟。跃起的瞬间，他回头看了一眼——那艘刻有奥古拉符文的石船正缓缓沉入浑浊的漩涡，像一位完成使命的古老守护者，安安静静地回到了它沉睡的地方。" },
      { kind: "p", text: "“跳！”" },
      { kind: "p", text: "载上所有人后，马车明显往下一沉。圣托尔拉动操纵杆，车底的奥古拉水晶装置迸出耀眼的蓝光——那光芒的质地让泰拉克斯的岩石心脏猛地一缩。他太熟悉那种能量了，熟悉到像是长在骨髓里，就像洛克托尔大门上那些石脸的轮廓，闭上眼就能描出来。" },
      { kind: "p", text: "马车摇摇晃晃地爬升，掠过洪水肆虐的街道。下方，微光鱿鱼旅馆的招牌最后一次闪烁，随即熄灭。琥珀之门仍在喷涌海水，那巨大的圆形通道像一张愤怒的嘴，一口一口，把整座城市吞进腹中。" },
      { kind: "p", text: "马车飞向附近一座山城，把斯黛拉、小菌、五瞳教派祭祀和他的先民铁箱，连同其他惊魂未定的客人一一放下。落地之后，祭祀向啊对对队深深鞠了一躬——五瞳教派的古老礼节在雨水中显得格外庄重。" },
      { kind: "p", text: "“愿五瞳注视你们的道路。”" },
      { kind: "p", text: "“我更希望五瞳先告诉我们，那扇门为什么会突然喷水。”祖法赛小声嘀咕。" },
      { kind: "p", text: "然后，马车再次升空。" },
      { kind: "p", text: "这一次，车厢里只剩下啊对对队的四人，以及那位传说中的裂隙守护者。她背对着他们，操纵杆在她布满鳞片的双手间灵活移动。" },
      { kind: "p", text: "“我叫圣托尔·三羽。”她终于开口，声音低沉而沙哑，“你们救了我的心血，也救了我的雷久纳。这份人情，我记下了。”" },
      { kind: "p", text: "她回过头，独眼在月光下泛着金色的光泽。" },
      { kind: "p", text: "“我想邀请你们加入我的旅程，一同前往**符文谷**。”" },
      { kind: "p", text: "马车转向北方。下方的琥珀门在洪水中渐渐缩小，化作一片被月光浸泡的银色废墟。城市的钟楼歪斜着，钟摆在风中无力地摇晃——那声音一路追随着他们，像一曲为沉没之城送行的挽歌。" },
      { kind: "p", text: "露娜拉靠在车厢边缘，银发被高空的风吹得猎猎作响。她低头看着膝上那面二手旧盾——今晚，盾面上又添了几道新痕。她忽然觉得，寻找飞龙之鳞的路，似乎比想象中更加漫长。但至少，她不再是一个人逃亡了。她把旧盾抱进怀里，像抱着星轮山最后的体面。" },
      { kind: "p", text: "乔奈摘下了头盔，第一次让夜风吹拂她真实的面容。她的手指上还沾着草料和血迹，短剑鞘里插着几株被压扁的蘑菇——路过马厩时顺手采的，这是她改不掉的老习惯。她望向远方，披风上的微光在高空的风里黯淡下去，像一颗终于决定休息的星。她不知道自己是该继续做一名义警，守着女友和街坊，还是该回应导师的遗愿，去对抗恶魔。也许符文谷会给她答案，也许不会。但至少今晚，她护住了怀里的普通人，也找到了新的同伴。" },
      { kind: "p", text: "祖法赛把贝科拉之杖的碎片往怀里又塞深了一寸。**符文谷**——北贝纳姆最大的城镇，由两个曾经交战的城镇合并而成，如今由冠面客家族统治，教团、星象学家和地下势力在那里盘根错节。也许那里藏着更多关于手杖的秘密；也许那里布着更多思缚者的眼线。谁知道呢。但有一条账他算得很清楚：这块碎片，绝不能再回到造物主佩桑娜手里。他闭上眼，脑海里浮现出凡提·玛夏克那些排队领薪水的劳工。如果这柄法杖真能改变什么，他希望，至少改变的是他们的命运。" },
      { kind: "p", text: "泰拉克斯伸出手，触碰车厢内壁上镶嵌的奥古拉水晶残片。冰凉的能量顺着指尖流进岩石躯体，像一股久违的温泉。他不知道**洛克托尔**——那座封印着邪恶奥古拉独裁者索佐的失落城市——是否就在符文谷的方向，但他知道，答案正在这条路上等他。用身体铸造武器、找回身份的路，也许比他想象的更近。而他要做的，是在走到洛克托尔门前时，记起自己是谁。他低头看了看自己的岩石手掌，那上面还留着断木撞出的凹痕。他盯着那道凹痕看了很久，像在读一行刚刻上去、却还不认识的符文。" },
      { kind: "p", text: "马车扇动着金属羽翼，向北飞去。" },
      { kind: "p", text: "而在他们身后，琥珀门的警钟依旧在洪水中无力地悲鸣，像一场被遗弃的旧梦，渐渐消散在阿格莫尼亚厚重的夜幕里。" },
      { kind: "hr", text: "" },
    ],
    poem: ["琥珀门前浪拍天，", "微光旅馆水中悬。", "群雄共济求安渡，", "独眼驱车驾铁鸢。", "古教铁箱藏异变，", "高贤振翼授遗编。", "山城暂歇人初定，", "且向符文觅旧缘。"],
    battleReport: "（死亡物品清单：无。啊对对队，全员存活。额外收获：圣托尔·三羽的友谊×1、珍贵羊皮手稿×1、五瞳教派先民铁箱×1、刻有奥古拉符文的石质扁舟线索×1。下一站：符文谷。）",
  },
  "ch2": {
    title: "第二章：通往符文山谷之路",
    endMark: "【第二章 完】",
    blocks: [
      { kind: "p", text: "离开琥珀门后的第三天，世界仿佛被水洗过一遍，又被某种更晦暗的东西重新涂抹过。" },
      { kind: "p", text: "空气里少了海水的咸腥，多了树叶、腐殖质，以及某种说不清的、属于内陆森林的沉默。灵树林的边缘，阳光被高耸的羽叶与垂挂的真菌帘幕滤成碎金，斑斑驳驳地铺在路面上。这里的树木高大得近乎傲慢，树皮上缠绕着暗紫色的菌脉，在阴影里发出微弱的、类似呼吸的光——那是暗克苏魔法渗入大地后的痕迹。鸟鸣稀疏，仿佛整片林子都在屏息。" },
      { kind: "p", text: "“小鸟号”的奥古拉水晶耗尽时，马车发出了一声类似叹息的机械嗡鸣，那对巨大的金属羽翼缓缓收拢，车厢轻轻震颤，然后稳稳落在了灵树林边缘的道路上。" },
      { kind: "p", text: "越往林子深处去，光线便越稀薄，始终照不透盘踞在树根与菌毯之间那些黏糊糊的阴影。" },
      { kind: "p", text: "驼格尔“雷久纳”从车厢里钻了出来，温顺地蹭了蹭圣托尔·三羽的手掌。这头被视为贝纳姆共和国非官方象征的巨兽甩了甩尾巴，主动将牵引绳叼在嘴里，接过了前行的重担。它的蹄子踩在真菌覆盖的落叶上，发出湿润的咯吱声。" },
      { kind: "p", text: "“它可比某些队友靠谱多了。”祖法赛嘟囔着，从“小鸟号”的储物箱里翻出一袋风干肉和几件基础工具。他的手指在触到储物箱底部时停顿了半秒——那里藏着贝科拉之杖的第一块碎片，被几层油布裹着，像一颗随时会跳出来的心脏。思缚者不会追到灵树林来吧？他甩甩头，把这个念头按下去。" },
      { kind: "p", text: "“你指谁？”乔奈问。" },
      { kind: "p", text: "“我指所有会喘气还会顶嘴的生物。”" },
      { kind: "p", text: "每晚露营时，这位裂隙守护者都会坐在篝火旁，用沙哑的嗓音讲述自己的使命。先民在数千年前建造的信标，分散在阿格莫尼亚的各个角落，而她暗示自己是唯一能完成拯救重任的人。火焰在她独眼里跳动，像某种不肯熄灭的执念。每当祖法赛追问细节，她只是眨眨那只金色的独眼：“抵达符文谷后，我自会全盘托出。”" },
      { kind: "p", text: "“经典谜语人。”乔奈在头盔下小声吐槽。" },
      { kind: "p", text: "“我猜她的‘全盘托出’意思是再给我们一个新的谜语。”祖法赛往火堆里扔了根树枝，火星溅到他淡蓝色的手背上，烫得他缩了缩手，“而且谜语通常要收钱。”" },
      { kind: "p", text: "“你们俩话真多。”泰拉克斯盘腿坐在火堆另一侧，岩石躯体一动不动，“石头人就不说话。”" },
      { kind: "p", text: "“你刚才说了两句。”露娜拉提醒他。" },
      { kind: "p", text: "“那是石头人在叹气。”" },
      { kind: "p", text: "露娜拉没有加入斗嘴。她坐在一块被苔藓覆盖的石头上，用一块破布擦拭旧盾。月光透过树冠洒在她银白色的长发上，像一层冷霜。三个月前，她还睡在星轮山城堡的丝绸床单上，听着母亲和姐姐们讨论哪一家的联姻更有利可图；现在她睡在树根旁，听着虫子叫和队友拌嘴。奇怪的是，她并不觉得格外屈辱——至少在这里，没有人逼她嫁给一个她恨的人，也没有人用“懂事”两个字来绑架她的人生。" },
      { kind: "p", text: "乔奈则总是在营地边缘巡逻。她在琥珀门的渔民区长大，知道夜晚从不会真正安全。街头的帮派、收保护费的打手、醉醺醺的水手——她小时候见过太多。盲眼长者教她武器，是希望她能对抗恶魔；但她更想保护的，始终是那些像她女友和街坊一样，被领主和罪犯双重压榨的普通人。这种信念，让她在每一次选择中都倾向于先救人、先出手。她的披风在夜色里微微发光，那是艾伊恩之力在提醒她：黑暗从未走远。" },
      { kind: "p", text: "出发后的第二天清晨，圣托尔·三羽把四件用旧布包着的工具丢到他们脚边：一捆钩索、一把铁铲、一支火把、一柄手斧。" },
      { kind: "p", text: "“荒野不是旅馆。”她说，“别指望每次都有会飞的马车来接你们。”" },
      { kind: "p", text: "祖法赛掂了掂钩索的重量，满意地点头：“总算有点像样的人造物品了。”" },
      { kind: "p", text: "第三天的午后，空气里突然多了一丝焦糊味，像有什么东西在真菌覆盖的树根下闷燃。" },
      { kind: "p", text: "前方地平线上升起一抹不祥的红光，把整片灵树林的轮廓染成了病态的暗紫色。雷久纳立刻停下脚步，惊恐地呜咽着，驼峰上的鬃毛根根倒竖。圣托尔猛地攥紧缰绳，独眼眯成了一条缝。" },
      { kind: "p", text: "“恶兆已至，我必须先行调查。”她跳下车厢，取出一块刻有奇特印记的石头——**符文板块**，先民用作钥匙或密码的神器。石面上流转的古老纹路，在红光映照下仿佛活了过来。“保护好它。务必让雷久纳拉着‘小鸟号’和这块符文板块抵达那边的山丘。”她指向远方一座被灵树环绕的灰蓝色山丘，“我留下工具。鼓励雷久纳继续前进，它必须留在道路上。至于荒野……”她瞥了一眼右侧那片长满**刀锋荆棘**的陡峭悬崖——那种与暗克苏魔法增长有关的锋利灌木，“显然不是什么好去处。”" },
      { kind: "p", text: "话音未落，她的身影已化作暗红色残影，消失在灵树林深处，只留下空气中一丝烧焦的鳞片味。" },
      { kind: "p", text: "“所以我们的任务，”祖法赛看着圣托尔消失的方向，“就是把一辆飞不起来的魔法马车、一头情绪不稳定的驼格尔、一块可能价值连城的先民密码石，安全送到一个谜语人指定的地点？”" },
      { kind: "p", text: "“没错。”露娜拉说。" },
      { kind: "p", text: "“而她甚至连句‘谢谢’都没说。”" },
      { kind: "p", text: "“她说了‘保护好它’。”" },
      { kind: "p", text: "“那不算谢谢，那是命令。”" },
      { kind: "p", text: "灵树林的道路铺设齐整，但越靠近红光的方向，空气就越发沉闷。真菌在树干上蔓延成暗紫色的毯子，偶尔有孢子雾从菌毯上升起，在光线里像细小的尘埃恶魔。连最后几声鸟鸣也没了踪影。这不是寻常的安静，而是一种令人脊背发凉的死寂，连风穿过羽叶时都放轻了脚步。" },
      { kind: "p", text: "祖法赛取走钩索，攀上了南边的山丘。他淡蓝色的皮肤在树荫下几乎与苔藓融为一体。心灵感应如同涟漪般向四周扩散，在真菌弥漫的空气里，连思维的波纹都沾上了一层黏腻的暗色——然后他“看”到了。" },
      { kind: "p", text: "道路前方，一棵巨大的灵树横倒在路上，树干粗得需要三人合抱。这不是自然倒伏，断口处参差不齐，像被某种巨力硬生生折断。更糟的是，在倒树的阴影里，有什么东西正在移动。" },
      { kind: "p", text: "“糟了！”他的声音直接在队友脑海中响起，带着珂蓝安人心灵感应特有的冰冷回响，还夹杂着一丝不易察觉的颤抖，“路被堵死了！而且——有东西发现我们了！”" },
      { kind: "p", text: "那东西从树林深处涌出，像一股黑色的潮水。**疾行虫**——阿格莫尼亚荒野中最令人头疼的掠食者之一，六条节肢、镰刀般的前肢、复眼闪烁着饥饿的绿光。它们是**梵诺主母**的耳目，与她有着心灵感应。" },
      { kind: "p", text: "“守住车厢！”露娜拉举起旧盾，暗瞳格里人的吼声在林间炸开，惊起一片真菌孢子。骑士统领的本能让她第一时间挡在车厢前方——保护平民、保护任务目标、保护队友。这是她从小受训的秩序，也是她流亡生涯里唯一没有背叛的东西。" },
      { kind: "p", text: "乔奈一头扎进了北面的树林。盲眼长者教给她的不仅是战斗，还有如何在野外生存，如何在黑暗中分辨哪些影子是树，哪些影子是怪物。她的身影在灌木丛中时隐时现，短剑划过甲壳的脆响一声接着一声，密如急雨，披风上的艾伊恩微光在暗紫色的真菌间划出一道明亮的轨迹。她的动作没有多余的花哨，每一剑都精准地落在疾行虫的关节处，然后迅速移向下一处。" },
      { kind: "p", text: "“左侧三只！乔奈，别恋战！”露娜拉在盾后喊道，同时用盾面拍开一只扑向车厢的疾行虫。" },
      { kind: "p", text: "“我在采蘑菇！”乔奈的声音从某棵大树后传来，伴随着一声甲壳碎裂的闷响，“顺便杀虫！盲眼长者说过，能吃的就别浪费！”" },
      { kind: "p", text: "“她真的在采蘑菇。”泰拉克斯说，岩石手掌一捏，把一只疾行虫的脑袋捏成了甲壳渣。他没有用武器，他的手掌就是武器。" },
      { kind: "p", text: "“我也听见了。”露娜拉叹气，旧盾上又添了一道划痕。" },
      { kind: "p", text: "祖法赛没有冲上去。他攀在钩索上，用心灵冲击逼退一只试图爬上马车车顶的疾行虫，淡蓝色的额头渗出细密的汗珠。他的心跳很快，但每一次出手都计算过距离和角度——这是凡提·玛夏克教会他的生存法则：用最少的力气，解决最大的麻烦。" },
      { kind: "p", text: "第一只疾行虫突破防线扑向露娜拉时，她没有躲。她沉腰、转胯，旧盾迎着虫子的镰刀前肢砸下——那是三羽教给她的**刚毅重击**。盾面与甲壳相撞，发出一声闷雷般的巨响，疾行虫被硬生生砸退两步，复眼都黯淡了一瞬。" },
      { kind: "p", text: "乔奈那边也动了真格。她矮身躲过一只疾行虫的扑击，短剑在掌心转了个圈，剑刃上骤然亮起一线凝实的寒光——**真实打击**。剑锋落下，虫子的甲壳像纸一样被剖开，露出里面墨绿色的内脏。" },
      { kind: "p", text: "泰拉克斯则直接多了。他抓住一只疾行虫的后腿，把它抡起来砸向另一只，岩石手掌带着风声落下——**狂怒猛砸**。两只虫子同时变成了扁片。" },
      { kind: "p", text: "祖法赛在钩索上腾出一只手，指尖符文一闪，一道淡蓝色的光弹脱手而出——**符文投射**。光弹击中一只正准备偷袭露娜拉后背的疾行虫，把它炸成了碎片。" },
      { kind: "p", text: "“你们刚才用的，”祖法赛在钩索上喊道，“是三羽教的那些花招？”" },
      { kind: "p", text: "“花招能杀虫！”露娜拉吼回去。" },
      { kind: "p", text: "乔奈在灌木深处发现了一名砍柴的樵夫——一个裹着粗麻斗篷、胡须上挂着苔藓的暗瞳格里老人。他正惊恐地缩在一棵倒伏的橡树后，手里紧紧攥着一柄比他本人还高的锋利巨斧，斧刃在斑驳的光线下泛着冷冽的寒光。" },
      { kind: "p", text: "“别靠近那棵树！”樵夫嘶哑地喊道，独臂指向南方那棵横倒的巨树，“那树根下有**先民埋下的机关**！爆炸机关！我砍柴时亲眼看见过符文闪光！”" },
      { kind: "p", text: "乔奈心头一紧。她想起盲眼长者教她的第一课：武器是用来开路，不是用来结仇。“老人家，那把斧子——借我们用用，我们得砍开挡路的树让车过去。”" },
      { kind: "p", text: "樵夫抱紧了巨斧，眼神警惕如野兽：“不行！这是我祖传的命根子！我爷爷的爷爷用它砍过暗克苏怪物！”" },
      { kind: "p", text: "“那您爷爷的爷爷一定是个很会砍树的人，”乔奈试图让自己的声音听起来诚恳，“但如果我们过不去，您今晚就得和这些虫子一起过夜。”" },
      { kind: "p", text: "樵夫固执地摇头，胡须上的苔藓跟着颤动：“斧子不外借！借出去就收不回来了！上一个借我斧子的人是五十年前的邻居，到现在都没还！”" },
      { kind: "p", text: "乔奈还想再试，但连日奔波的疲惫让她的言辞失去了锋芒。她想起盲眼长者说过的话：“言语是最便宜的武器，也是最贵的。”她叹了口气，也许今天她的话已经用完了，剩下的只能交给手中的短剑。" },
      { kind: "p", text: "就在这时，露娜拉从北面赶来。她刚刚甩掉两只追击的疾行虫，银发上还挂着断裂的蛛网。她看了一眼僵持的乔奈，又看了一眼樵夫手中那柄泛着杀气的巨斧，立刻明白了局势。" },
      { kind: "p", text: "“让我来。”露娜拉深吸一口气，将旧盾插在地上，双手轻轻交叠于胸前。她闭上眼，意识沉入星轮山布林德利昂家族传承的意志之力，那股威严随之在她体内凝聚。当她再次睁开眼时，眸子里燃着令人无法直视的光。" },
      { kind: "p", text: "“老人家，”她的声音低沉而清晰，每一个音节都像是刻在石碑上的铭文，“我们不是强盗，我们是护送者。你的斧子不会丢失，它会砍开挡路的黑暗，然后回到你手中。我以布林德利昂家族的名誉起誓。”" },
      { kind: "p", text: "那股意志的光芒在她眼底一闪而逝。樵夫愣住了，他在这位银发战士身上看到了某种久违的、令人信服的东西——那是贵族的尊严，是承诺的分量，是在这个世道上已经快要绝迹的“一言九鼎”。" },
      { kind: "p", text: "最终，他颤抖着将那柄沉重的巨斧递了过来，斧柄上还残留着他手心的温度。" },
      { kind: "p", text: "“小心……那斧子很快。比我老婆翻脸还快。”" },
      { kind: "p", text: "然而，就在露娜拉接过巨斧的刹那，谁也没想到，樵夫那句警告会在几息之后变成现实。" },
      { kind: "p", text: "她扛着巨斧赶回倒树前，将斧子靠上道旁的岩石，双手扣住那需要三人合抱的树干断口：“泰拉克斯，搭把手！先把这棵拦路的家伙挪开，车才能过去！”" },
      { kind: "p", text: "泰拉克斯大步上前，岩石手掌扣进树皮的裂缝。石头人与圣骑士对视一眼，同时发力——" },
      { kind: "p", text: "“别碰那棵树！”乔奈和樵夫的喊声几乎同时炸响。" },
      { kind: "p", text: "晚了。" },
      { kind: "p", text: "树根下，暗红色的先民符文骤然亮起，像一双被惊醒的兽瞳。巨大的树干刚刚离地半尺——" },
      { kind: "p", text: "轰！！！" },
      { kind: "p", text: "巨响吞没了整片灵树林，浓烟从道路上升腾而起，像一道灰色的墙。爆炸的气浪将合力搬树的两人同时掀飞：泰拉克斯的岩石躯体撞上道旁的巨石，碎石屑从肩膀上崩落，发出沉闷的碎裂声；露娜拉双脚离地，在空中翻转，用旧盾护住身体，重重摔进灌木丛中，荆棘在手臂上划出几道血痕。热浪卷着碎石和真菌孢子横扫而过，打在每个人的脸上，火辣辣地疼。" },
      { kind: "p", text: "“露娜拉！泰拉克斯！”祖法赛的声音从山丘上焦急地传来。" },
      { kind: "p", text: "“活着！”露娜拉咳出一口带着铁锈味的血沫，从灌木丛中爬起来。旧盾上又多了一个深深的凹痕。她摸了摸自己的尾巴——还在。太好了。逃亡者的本能总是先确认这个，然后才轮到手里的盾。" },
      { kind: "p", text: "“我也活着，”泰拉克斯摇晃着脑袋，从碎石堆里站起来，肩膀上的石屑簌簌而落，“而且我的石头又薄了一层。恭喜我，减肥成功。”" },
      { kind: "p", text: "然而，前方的道路已经变成了一个冒着黑烟的巨坑，坑底还残留着燃烧的树根和暗红色的符文残渣。倒下的灵树横在坑边，像一道被截断的路标。雷久纳拉着“小鸟号”停在坑边，惊恐地打着响鼻，说什么也不肯再往前一步。而疾行虫的攻势越来越猛——它们似乎被爆炸声彻底激怒了，从四面八方围拢过来，复眼中闪烁着不自然的绿光，仿佛在执行某个更高意志的命令。空气中弥漫着烧焦的植物和暗克苏魔法特有的腐臭。" },
      { kind: "p", text: "“过不去了！”泰拉克斯盯着坑底，“坑太宽，车会掉下去！”" },
      { kind: "p", text: "“那就搭一座桥。”乔奈的声音突然从右侧传来。" },
      { kind: "p", text: "露娜拉将樵夫赠予的巨斧重重插在地上，斧刃没入泥土半寸：“用这个。比三羽给的手斧顺手。”" },
      { kind: "p", text: "泰拉克斯拔出巨斧，岩石手掌掂了掂分量。他大步走向右侧那片**刀锋荆棘**丛——枝条坚硬如铁，边缘锋利得能割开皮革。但在祖传巨斧面前，它们像枯草一样纷纷倒下。巨斧挥舞，带起呼啸的风声，每一次劈砍都溅起墨绿色的汁液，那汁液落在岩石上，发出轻微的腐蚀声，像某种酸性液体在侵蚀石头。" },
      { kind: "p", text: "乔奈把圣托尔给的手斧别在腰后，短剑开路，在坑洞两侧来回跳跃。火把被她插在坑边，橙红色的火光照亮了刀锋荆棘的影子，也吓退了几只试图摸上来的疾行虫。" },
      { kind: "p", text: "“盲眼长者说过，”乔奈将砍下的枝条拖到坑边，披风上的微光在黑暗中拉出一道弧线，“没有不能走的路，只有不敢砍的树。”" },
      { kind: "p", text: "“盲眼长者有没有说过，砍暗克苏植物的时候要注意汁液别溅到眼睛里？”祖法赛一边用心灵冲击逼退一只疾行虫，一边喊道。" },
      { kind: "p", text: "“他说过，”乔奈回答，“但我忘了。”" },
      { kind: "p", text: "泰拉克斯利用地卜师的本能感知这些植物的结构，将枝条压平、拼接，动作沉稳得像在雕琢一件武器。乔奈则凭借惊人的身手在坑沿与断枝之间攀援，将桥的两端牢牢绑在残留的树根上。如果没有这柄巨斧，他们根本无法在短时间内收集到足够的建材；如果没有乔奈的身手，他们根本无法把这座桥架在刀锋荆棘之上。" },
      { kind: "p", text: "一座临时吊桥，在战火中诞生了。" },
      { kind: "p", text: "“这桥稳吗？”祖法赛问。" },
      { kind: "p", text: "“比你的心灵防线稳。”泰拉克斯回答。" },
      { kind: "p", text: "“那是相当不稳。”" },
      { kind: "p", text: "“雷久纳，过来！”祖法赛从山丘上冲了下来，鼻子里还挂着蓝色的血丝。他挡在驼格尔面前，双手泛起幽蓝的心灵微光。他在雷久纳的脑海里描绘：前方是安全的，道路是平坦的，女主人正在等待，你是贝纳姆的象征，你不能在这里退缩。他想象着泽布尔海邦的水下都市里，那些在灯光下排队领薪水的劳工——恐惧是可以被安抚的，只要你给出一个足够体面的理由。" },
      { kind: "p", text: "雷久纳的鼻孔翕动着，大眼睛里倒映着祖法赛淡蓝色的面容。它犹豫了一瞬，然后，奇迹般地，它迈出了蹄子。" },
      { kind: "p", text: "“走！快走！”露娜拉和祖法赛并肩站在吊桥一侧，旧盾和心灵冲击构成了两道防线。疾行虫像黑色的浪潮一样涌来，圣骑士的盾面上布满了划痕，心灵术士的额头渗出了蓝色的血珠，顺着淡蓝色的皮肤滑落，像某种诡异的图腾。" },
      { kind: "p", text: "泰拉克斯和乔奈在吊桥另一侧接应，确保“小鸟号”的车轮不会卡进缝隙。雷久纳闭着眼睛，颤抖着，一步一步地走过了那座摇摇欲坠的吊桥。它的驼峰擦过了刀锋荆棘的枝条，留下几道浅浅的血痕，但它没有停下。" },
      { kind: "p", text: "当“小鸟号”的后轮终于碾上对岸的土地时，啊对对队已经精疲力竭。但他们没有时间休息。" },
      { kind: "p", text: "因为前方的山丘上，天空正在燃烧。" },
      { kind: "hr", text: "" },
      { kind: "p", text: "他们甩掉了最后一批疾行虫，冲过林缘，眼前的景象让所有人停住了脚步，连雷久纳的喘息都顿了一顿。" },
      { kind: "p", text: "山丘之上，天空被撕裂成红蓝两色。红色的邪恶能量像扭曲的闪电，蓝色的魔法光辉如凝固的冰川，两种力量在半空中激烈碰撞，爆发出震耳欲聋的轰鸣。先民废墟的断壁残垣在光芒中忽明忽暗。" },
      { kind: "p", text: "圣托尔·三羽悬浮在半空中，独眼中燃烧着决绝的蓝光，双手编织着复杂的符文，每一次出手都像是在撕扯天空的布料。她的对手——一名脚踏飞行圆盘的暗瞳格里巫师——兜帽下露出苍白的面容和一双泛着血色的眼睛。那巫师手中投射出的红色能量如同活物，扭曲着、嘶吼着，所过之处连真菌都瞬间枯萎。" },
      { kind: "p", text: "“是圣托尔！”乔奈喊道，头盔下的声音第一次带上了真正的焦急。" },
      { kind: "p", text: "那名巫师的身份已不言而喻——**磐怒客家族**的暗克苏法师，圣托尔·三羽的宿敌。在贝纳姆内战之前，磐怒客帝国曾是雄踞东北部的巨大独立王国，如今这个家族仍企图再次征服这片土地。而圣托尔，这位裂隙守护者、阿格莫尼亚英雄们的导师，此刻正在独自对抗这股黑暗，她的每一次施法都像是在为身后的平民争取一秒钟。" },
      { kind: "p", text: "雷久纳发出了凄惨的哀鸣，它认出了女主人的声音，也感知到了那致命的威胁。" },
      { kind: "p", text: "“稳住它！”露娜拉扑上去，用身体抵住雷久纳的脖颈，她的尾巴紧紧缠住驼格尔的缰绳，“别让它冲进去！现在冲进去，我们都得死！”" },
      { kind: "p", text: "祖法赛再次将心灵触须探入驼格尔的意识，构建了一道墙：信任、等待、女主人需要你活着。" },
      { kind: "p", text: "就在这时，暗瞳格里巫师注意到了地面的动静。" },
      { kind: "p", text: "他低头，血色的目光锁定了啊对对队，嘴角扯出一个残忍的弧度。他抬起手，一道猩红的魔法箭在掌心凝聚——那是**暗克苏**的力量，与黑暗、痛苦和诅咒相关的邪恶魔法。魔法箭周围的空间微微扭曲，连光线都被吸了进去。" },
      { kind: "p", text: "“散开！”泰拉克斯的吼声像岩石崩裂。" },
      { kind: "p", text: "但魔法箭的速度比声音更快。那尖锐的啸声撕裂了空气，像死神的哨音，直直地射向队伍中央——射向雷久纳，射向“小鸟号”，射向那块刻着先民符文的板块！" },
      { kind: "p", text: "生死就在一线之间。" },
      { kind: "p", text: "“跑！”露娜拉没有犹豫，她用盾面狠狠拍了一下雷久纳的驼峰，暗瞳格里人的吼声里带着不容置疑的命令，“冲向前面的废墟！快！”" },
      { kind: "p", text: "雷久纳终于动了。它爆发出惊人的力量，拉着“小鸟号”像一辆失控的战车般冲向山丘下方的先民废墟。啊对对队四人紧随其后：泰拉克斯用岩石身躯替车厢挡下横飞而来的碎石；露娜拉和祖法赛一左一右护住两翼，她的单手死死挽住缰绳，他的心灵冲击像鞭子一样抽打着试图扑上来的疾行虫；乔奈跑在最后，披风在身后拉出一道发光的轨迹，她不断回头，确保没有人被落下。" },
      { kind: "p", text: "魔法箭擦着泰拉克斯的肩膀飞过，击中了他们身后的灵树林。" },
      { kind: "p", text: "轰——！！！" },
      { kind: "p", text: "那不是普通的爆炸。暗克苏魔法在接触灵树的瞬间引发了连锁反应。巨大的灵树从内部崩裂，木屑和树皮化作致命的暴雨。更多的树木在冲击波中倾倒，地面裂开，烟尘冲天而起，将整条道路埋葬在崩塌的废墟之下。" },
      { kind: "p", text: "啊对对队没有回头。他们不能回头。" },
      { kind: "p", text: "他们冲进了先民废墟的阴影中，身后的世界在崩塌、在燃烧、在哀鸣。雷久纳的喘息声、车轮的颠簸声、以及每个人胸腔里如擂鼓般的心跳声，交织成一曲逃亡的乐章。先民的石碑在他们头顶轰然倒塌，扬起一片夹杂着真菌孢子的尘雾。" },
      { kind: "p", text: "当他们终于在一堵倒塌的石墙后停下时，天空中的魔法大战仍在继续。红蓝交织的光芒照亮了废墟的每一个角落。" },
      { kind: "p", text: "祖法赛瘫坐在一块先民石碑旁，蓝色的血液从鼻子里淌下来，在石碑上晕开一小片诡异的图案。他扶着额头，指尖还残留着心灵透支后的颤抖，脚边散落着钩索和已经卷刃的手斧：“所以……我们的送货任务……变成了……从裂隙守护者和磐怒客法师的魔法对轰里……活下来？这单子要是敢差评，我第一个不服。”" },
      { kind: "p", text: "“啊对对对。”乔奈靠在墙上，头盔下的声音带着劫后余生的沙哑，“而且我采的蘑菇全掉了。”" },
      { kind: "p", text: "泰拉克斯低头看着手中那柄从樵夫处得来的巨斧，斧刃上还残留着刀锋荆棘的墨绿色汁液。他忽然笑了一下——如果石头人那开裂的嘴角能算作笑的话：“但至少，我们多了把不错的斧子。用它砍柴，应该比用脸撞树强。”" },
      { kind: "p", text: "“前提是那老头别来找我们要回去。”祖法赛补充。" },
      { kind: "p", text: "露娜拉没有说话。她望着天空中那道蓝色的身影，握紧了旧盾。流亡的圣骑士在星轮山学过一条准则：当你无法判断谁是正义时，选择保护弱者。而此刻，圣托尔·三羽——这位阿格莫尼亚的英雄导师——正在为他们争取时间。" },
      { kind: "p", text: "“休息，”露娜拉最终开口，声音低沉而坚定，“然后，我们得想办法帮她。啊对对队从不欠人情，尤其是救命的人情。”" },
      { kind: "p", text: "“我同意，”乔奈摘下头盔，露出疲惫的面容，头盔内侧的艾伊恩微光在她脸上投下淡淡的光晕。她摸了摸腰间的小布袋，那里原本装着几株草药，现在只剩下几根断茎，“但能不能先让我找到我掉的蘑菇？里面有株枯萎菇，我追了它三条街。”" },
      { kind: "p", text: "“等我们活着离开这里再讨论蘑菇的事。”露娜拉说。" },
      { kind: "p", text: "祖法赛靠在石碑上，闭上眼。贝科拉之杖的碎片在怀中隐隐发热，像一颗不肯安分的心脏。符文谷——那里也许有其余碎片的线索，也一定有思缚者的眼线。他曾为造物主佩桑娜效力，传播过谎言；如今他要抢在佩桑娜之前，决定这柄法杖究竟该成为致富的工具，还是解放的武器。这个决定，比任何心灵冲击都让他疲惫。他想起凡提·玛夏克那些排队领薪水的劳工，想起他们麻木的眼睛。也许，法杖的力量应该属于他们。" },
      { kind: "p", text: "泰拉克斯则望向废墟深处。先民的石碑在震动中低语，仿佛沉睡千年的记忆正在被唤醒。他皮肤上的符文早已磨平，但此刻，某种比记忆更古老的东西正在回应他。洛克托尔就在这条路上的某个地方。他能感觉到。他甚至能感觉到，那座城市的大门上，有一张石脸正在注视着他。他下意识地摸了摸自己的后背，那里曾经生长着奥古拉水晶，如今只剩一片光滑的岩石。" },
      { kind: "p", text: "而在石碑的阴影里，**啊对对队**的四个人和一头驼格尔，正蜷缩在“小鸟号”的羽翼下，听着远处传来的喊叫、咒骂和爆炸声，等待着冲入那片红蓝交织的战场。" },
      { kind: "p", text: "三日来的跋涉、逃亡与战斗，像一把钝刀，慢慢磨开了他们身体里某些沉睡的东西。" },
      { kind: "p", text: "乔奈最先感觉到。她低头看着自己的手掌，短剑的握柄上还残留着疾行虫甲壳的碎屑。她忽然意识到，刚才在灵树林里，她不仅能更快、更准地刺出短剑，还能在剑刃触及目标的前一瞬，把艾伊恩的微光凝成一线。那不是盲眼长者教过的任何剑术，而是某种更古老、更温暖的东西在她体内苏醒——**米恩的守护者**，以及**引导能量**的法门。" },
      { kind: "p", text: "露娜拉也感觉到了。她握着旧盾，盾面上新增的划痕里还嵌着暗克苏魔法的余烬。她想起自己在洪水里用盾面护住觅奇兽，在灵树林里凝聚意志说服樵夫，在逃亡中用盾面拍醒雷久纳。她的治疗不再只依靠药水，她的打击不再只依靠力气。她学会了**快速治疗**，也学会了如何在守护与进攻之间切换的**英勇打击**。" },
      { kind: "p", text: "泰拉克斯的变化更直观。他的岩石手掌在握住樵夫巨斧时，感觉到了某种前所未有的契合。他不再只是用蛮力砸碎东西，而是学会了如何把全身的重量与愤怒集中在一点——**巨力碾压**；也学会了如何让每一块岩石都成为武器——**巨石打击**。" },
      { kind: "p", text: "祖法赛则发现，他的心灵力量不再只能安抚与冲击。他可以把符文能量像投射物一样甩出去，也可以把符文刻进队友的武器里，让凡铁变成利器——**符文冲击**与**赋能**。" },
      { kind: "p", text: "“我们好像变强了。”乔奈说。" },
      { kind: "p", text: "“变强的代价是免费打工。”祖法赛说。" },
      { kind: "p", text: "“闭嘴。”露娜拉说，但嘴角微微上扬。" },
      { kind: "p", text: "他们都知道，真正的考验还在后面。先民废墟的深处，圣托尔与磐怒客巫师的战斗仍在继续，而符文谷的阴影，已经比灵树林的真菌更加浓重。" },
      { kind: "hr", text: "" },
    ],
    poem: ["灵林路断鸟声寒，", "赤气遥腾上碧峦。", "古木横街藏烈爆，", "妖虫匝地起狂澜。", "长桥已架刀锋散，", "意定能平巨兽难。", "赤焰蓝芒山欲裂，", "群投古窟避凶端。"],
    battleReport: "（死亡物品清单：乔奈采集的蘑菇若干。啊对对队，全员存活。额外收获：锋利巨斧×1（樵夫赠予）、先民废墟入场券×1。新掌握：乔奈-米恩的守护者、引导能量；露娜拉-快速治疗、英勇打击；泰拉克斯-巨力碾压、巨石打击；祖法赛-符文冲击、赋能。下一站：先民废墟深处 / 符文谷。）",
  },
  "ch3": {
    title: "第三章：先民宝库的暗涌",
    endMark: "【第三章 完】",
    blocks: [
      { kind: "p", text: "魔力之箭的余威仍令露娜拉心悸不已。胸腔里那颗心跳得又急又重，像要撞断肋骨逃出去。她回头望了一眼：灵树林的边缘还在冒烟，几棵被暗克苏魔法点燃的灵树如同巨大的火炬，在暮色中噼啪炸裂。火星随风扑上她的发梢，她抬手拍灭，一股焦糊味顺势钻进鼻腔——那味道让她想起星轮山城堡被烧毁的那个夜晚。" },
      { kind: "p", text: "“别停下！”她吼道，声音在空旷的山道上撞出回音，也撞在她自己的耳膜上，“往前跑！那巫师还会再来一发的！”" },
      { kind: "p", text: "啊对对队四人沿着山道狂奔。乔奈的披风在身后拉出一道残光，她的呼吸短促而灼热，每一次吸气都像吞进一把碎玻璃；泰拉克斯的岩石脚掌把地面踏得咚咚作响，每一步都在碎石上留下浅坑；祖法赛把贝科拉之杖碎片死死抱在胸前，边跑边骂，肺像被一只无形的手攥住，每一次喘息都带着铁锈味：“我……我这辈子……没跑过……这么快的路！”" },
      { kind: "p", text: "“你昨天还说石头人跑得不慢！”乔奈在前面喊，声音里带着喘息的笑意。" },
      { kind: "p", text: "“石头人是石头人，我是我！”祖法赛喘得像一条离水的鱼，他的小腿肌肉在抽筋，但他不敢停，“珂蓝安人进化出鳃不是为了在陆地上冲刺的！”" },
      { kind: "p", text: "露娜拉没有回头。她的旧盾在背上颠簸，每一次落地都撞得肩胛骨生疼，像有人用锤子一下一下敲她的骨头。她想起三天前在微光鱿鱼旅馆，她也是这样背着盾逃跑——只不过那一次身后是洪水，这一次身后是一个随手就能把裂隙守护者扔进山里的暗克苏巫师。她的手指死死抠住盾带，指节发白。她不能停。她不能再逃了。至少这一次，她得跑到一个能回头的地方。" },
      { kind: "p", text: "前方，一座依环形山丘而建的异教城镇废墟映入眼帘。石墙倾颓，屋舍坍塌，像是被某种巨力从内部掏空过。没有炊烟，没有灯火，只有风穿过断壁时发出的呜咽，像无数冤魂在低声啜泣。山丘的形状透着说不出的古怪，像一只巨碗倒扣在大地上，边缘整齐得近乎人工，露娜拉甚至能看到山丘表面刻着的、已经风化的环形纹路——那不是自然形成的，是先民的手笔。" },
      { kind: "p", text: "而在山丘之巅，红蓝两色魔法仍在激烈交锋。" },
      { kind: "p", text: "圣托尔·三羽悬浮在半空，独眼燃烧着决绝的蓝光，双手编织着复杂的符文。她的焰龙蜥鳞片在魔力激荡中竖起，像一面面小小的盾牌。她的对手——那名磐怒客家族的暗瞳格里巫师——脚踏飞行圆盘，手中猩红宝珠散发出令人作呕的暗克苏气息。云层被两股魔力染成猩红，又转为蔚蓝，像一块被反复揉搓的破布。" },
      { kind: "p", text: "“是三羽！”乔奈喊道，声音里带着她自己都没察觉的颤抖。" },
      { kind: "p", text: "下一秒，巫师动了。他抬起手，动作优雅得像在指挥一场无声的交响乐。一道无形的力量突然攥住圣托尔，将她像一片叶子般猛然抛向山丘内部。蓝光在半空中划出一道弧线，消失在环形山丘的缺口里。没有惨叫，没有反抗，就像被一只无形的大手按进了水里。" },
      { kind: "p", text: "“不！”露娜拉的尾巴绷得笔直，她的脚已经冲了出去，旧盾在她背后撞出沉闷的响声。她心里只剩一个念头：不能再眼睁睁看着有人在自己面前被夺走。母亲是这样，如今圣托尔也是这样。" },
      { kind: "p", text: "“别去！”乔奈一把拽住她的披风，手指像铁钳一样扣进布料里，“现在冲过去，就是送死！”" },
      { kind: "p", text: "巫师转过头，血色的目光锁定地面上的四人。他手中的猩红宝珠光芒大盛，兜帽深处仿佛睁开了一只发光的红眼。那目光扫过露娜拉的旧盾，扫过乔奈的发光头盔，扫过祖法赛紧抱的胸口，扫过泰拉克斯岩石般的身躯。露娜拉感觉那目光像实质的针，刺进她的皮肤，她的血液在那一刻几乎凝固。" },
      { kind: "p", text: "他迟疑了片刻，兜帽下的手指微微收紧，似乎在酝酿某种足以将他们抹去的法术。但随即，他低头看了一眼宝珠，像是收到了某种警告或召唤。宝珠的红光在他掌心跳动了一下，又归于平静，像一头被勒住脖子的野兽。" },
      { kind: "p", text: "他没有攻击。他踏上金属圆盘，圆盘升空，载着他向北飞去，消失在暮色中。飞行圆盘划过天空时，留下一道淡淡的暗红色尾迹，像一道未愈合的伤口，久久不散。" },
      { kind: "p", text: "露娜拉这才发现自己的指甲已经掐进了掌心，留下四个月牙形的血痕。" },
      { kind: "p", text: "四人还没来得及松口气，一个奇异的幻象便在眼前浮现。" },
      { kind: "p", text: "是圣托尔。但比平时更虚幻，像是从很远的地方传来的回声。她的影像在空气中微微扭曲，边缘泛着淡蓝色的光晕，像水面下的倒影。" },
      { kind: "p", text: "“听着，”她的声音直接在他们脑海中响起，带着一种奇异的空灵，每一个字都像是从水底浮上来的气泡，“这座山丘乃先民所建，如今却充斥着那名巫师制造的暗克苏魔法。这股邪恶能量正与我的魔法剧烈冲突，即将引发一场内爆，污染整个地区。你们必须进入山丘，阻止浩劫发生。”" },
      { kind: "p", text: "幻象闪烁了一下，圣托尔的面容在痛苦中扭曲，她的独眼里映着某种他们看不见的东西。" },
      { kind: "p", text: "“我在里面，”她说，“但我的时间不多。快点。”" },
      { kind: "p", text: "幻象消散，像一滴水蒸发在热石头上，只留下空气中一丝若有若无的蓝光。" },
      { kind: "p", text: "四人面面相觑。风从山丘上吹下来，带着一股烧焦的鳞片味，以及某种从更深处泛上来的、属于先民机械的金属锈味——那本身就是一种古老的警告。" },
      { kind: "p", text: "“所以，”祖法赛喘着气，一屁股坐在地上，他的腿还在不受控制地发抖，“我们刚逃过魔法箭，现在又要主动跳进一个随时会爆炸的魔法坑里？”" },
      { kind: "p", text: "“没错。”露娜拉说，她的声音比她自己预想的要平静。" },
      { kind: "p", text: "“报酬呢？”" },
      { kind: "p", text: "“救下圣托尔，就是报酬。”" },
      { kind: "p", text: "“这买卖不划算。”祖法赛嘟囔，但还是爬了起来，拍了拍屁股上的尘土。他的手在抖，但他把那块贝科拉之杖的碎片握得更紧了，“不过我投赞成票。那巫师往北飞了，我们往南走，正好错开。”" },
      { kind: "p", text: "“他没有往南。”泰拉克斯说，岩石面孔上没有表情，但他的目光一直追随着巫师消失的方向，“他往北。符文谷在北边。”" },
      { kind: "p", text: "祖法赛的脸垮了下来：“……我就不能自欺欺人一下吗？”" },
      { kind: "p", text: "露娜拉没有说话。她只是握紧了旧盾，转身向山丘走去。她的脚步很稳，但只有她自己知道，她的腿也在抖。" },
      { kind: "p", text: "他们刚靠近山丘外围的废墟，地面就震颤起来。不是脚步的震颤，而是某种更深层的、从地底传来的脉动，像大地的心跳。裂缝中涌出无数黑影——**疾行虫**，比灵树林里更多、更密，像一股从裂隙深处倒灌而出的黑色潮水。节肢刮擦碎石，沙沙声令人牙酸，钻进祖法赛的耳朵里，像无数根细针反复扎着他的鼓膜。" },
      { kind: "p", text: "“又来？！”乔奈拔出短剑，手腕在发颤，她却硬把那份颤抖压进了剑柄里。" },
      { kind: "p", text: "“省点力气！”露娜拉举盾，“边打边往山丘里退！”" },
      { kind: "p", text: "战斗瞬间爆发。泰拉克斯的狂怒猛砸把第一只冲上来的疾行虫砸进地里，碎石飞溅，他的岩石手掌上沾满了墨绿色的体液，那体液腐蚀着他的石肤，发出轻微的滋滋声；乔奈的真实打击剖开第二只的甲壳，腥臭的浆液溅了她一身，那股熟悉的、混着铁锈味的气息直冲鼻腔，盲眼长者说过，那是死亡的味道；露娜拉的刚毅重击盾面拍飞第三只，旧盾上的飞龙纹章在血光中若隐若现，她的虎口被震得发麻，但她没有松手。" },
      { kind: "p", text: "祖法赛则以符文投射封住侧翼，淡蓝色的光弹在暮色中划出一道道短线，把试图包抄的漏网之鱼一只只钉回黑暗里。他的手指在发抖，不是因为恐惧，而是因为过度使用心灵力量带来的痉挛。每一次发射，他都能感觉到自己的意识被抽走一小片，像有人用钝刀慢慢割他的脑子。" },
      { kind: "p", text: "“这些虫子是从哪儿冒出来的？！”祖法赛一边射一边骂，他的声音在颤抖，“刚才巫师不是走了吗？！”" },
      { kind: "p", text: "“裂隙！”乔奈喊道，披风上的艾伊恩微光在黑暗中划出一道弧线，照亮她紧绷的下颌线，“暗克苏魔法把裂隙撕开了一道口子！”" },
      { kind: "p", text: "“所以现在是杀不完的？！”" },
      { kind: "p", text: "“杀到它们自己退回去为止！”" },
      { kind: "p", text: "露娜拉的脑海里闪过星轮山训练场的画面。她的教官曾经说过：当敌人杀不完时，不要想着杀光，想着活下去。她把旧盾举得更高，盾面上的凹痕在火光中像一张狞笑的脸。" },
      { kind: "p", text: "他们且战且退，向山丘外围的废墟移动。就在祖法赛绕过一堵断墙时，他踩到了什么。那是一块微微隆起的土包，表面覆盖着暗紫色的菌丝，在夕阳下泛着诡异的光泽，像某种活物的皮肤。他下意识用心灵感应探了一下——" },
      { kind: "p", text: "一股冰冷、庞大、充满恶意的意识猛地反噬回来，像一根冰锥扎进他的脑海。祖法赛的眼前炸开一片白光，他的膝盖一软，差点跪倒在地。那不是普通的恶意，而是某种古老的、饥饿的、视一切活物为食粮的存在。" },
      { kind: "p", text: "“我……我好像惹到什么东西了。”祖法赛脸色发白，脚步钉在原地，他的牙齿在打颤。" },
      { kind: "p", text: "地面裂开，一只体型堪比马车的巨大虫形生物从地底升起。**梵诺主母**。她的复眼闪烁着饥饿的绿光，镰刀般的前肢比乔奈的短剑还长，腹部下拖着一串半透明的卵囊，每一个卵囊里都蜷缩着一只未成形的疾行虫。她的出现让周围的空气都冷了下来，连疾行虫群都自动让开一条道路，像臣民给女王让路。" },
      { kind: "p", text: "“这就是你惹出来的？”露娜拉吼道，她的尾巴在身后炸毛。" },
      { kind: "p", text: "“我只是碰了一下！”祖法赛的声音在发抖，他的后背已经被冷汗浸透。" },
      { kind: "p", text: "“你管那叫碰？！”" },
      { kind: "p", text: "梵诺主母没有给他们争吵的时间。她发出一声低沉的嘶鸣，那声音不像虫子，更像某种古老的、地底深处的回响，震得四人胸腔共鸣。无数疾行虫在她身周盘旋，像一片活的乌云，向四人压来。祖法赛能闻到她身上那股腐臭，像腐烂的菌丝混合着血腥味，熏得他胃里翻江倒海。" },
      { kind: "p", text: "“乔奈！”祖法赛喊道，声音里带着他自己都没察觉的颤抖，“把你那道光借我一道！”" },
      { kind: "p", text: "乔奈没有犹豫。她咬破指尖，疼痛让她瞬间清醒。她将艾伊恩之力凝成一线，点在祖法赛后背——**引导能量**。淡蓝色的微光顺着她的指尖流入祖法赛体内，像一股温热的泉水注入干涸的河床。那不是简单的强化，而是乔奈把自己对艾伊恩的理解、对守护的信念、对盲眼长者的承诺，一并渡了过去。她的眼前闪过盲眼长者的脸，闪过琥珀门渔民区的灯火，闪过她女友的微笑。" },
      { kind: "p", text: "祖法赛双手前推，一道比之前粗壮数倍的心灵冲击轰向梵诺主母。他的意识在那一刻无比清晰，他能感觉到主母脑海中的混乱、饥饿、以及某种更深层的、对裂隙的忠诚。他把她所有的情绪拧成一股绳，狠狠抽了回去。" },
      { kind: "p", text: "与此同时，泰拉克斯从侧面跃起，岩石手掌带着全身重量砸下——**狂怒猛砸**。他的脑海里只有一个念头：保护身后的人。他不需要记忆，他只需要此刻。" },
      { kind: "p", text: "主母的甲壳碎裂了。她发出一声刺耳的尖啸，那声音震得四人耳膜生疼，连远处的废墟都簌簌落灰。她庞大的身躯轰然倒地，溅起一片尘土，卵囊破裂，未成形的疾行虫在尘土中扭动了几下，便不再动弹。她的复眼还睁着，绿光渐渐黯淡，像两盏熄灭的灯。" },
      { kind: "p", text: "疾行虫群瞬间失去指挥，像无头苍蝇一样四散奔逃，钻回地缝，消失不见。" },
      { kind: "p", text: "“我们……打赢了？”祖法赛喘着气，双手还保持着前推的姿势，鼻血流了下来——珂蓝安人的血是鲜蓝色的，滴进尘土，像一小片坠落的夜空。" },
      { kind: "p", text: "“你惹出来的，你负责收尾。”乔奈甩了甩剑上的虫液，脸色有些苍白。引导能量消耗了她不少体力，她的指尖还在微微发抖。" },
      { kind: "p", text: "“我这不是收尾了吗？”祖法赛指了指梵诺主母的尸体，然后腿一软，坐倒在地。" },
      { kind: "p", text: "他们在梵诺主母的巢穴里翻找。她的巢穴是一个半地下的坑洞，里面堆满了她吞食后又吐出来的残渣：甲壳碎片、骨头、菌丝，以及一块被菌丝包裹的、散发着微弱蓝光的晶体。" },
      { kind: "p", text: "“**奥古拉水晶**。”泰拉克斯说，岩石面孔上第一次出现了明显的情绪波动。他伸出手，小心翼翼地拂去水晶上的菌丝，像拂去一件圣物上的灰尘。" },
      { kind: "p", text: "“这玩意儿比蘑菇值钱。”乔奈把它丢给祖法赛。" },
      { kind: "p", text: "“废话。”祖法赛小心地收好，指尖传来一阵冰凉的能量感，“这可是奥古拉水晶。在泽布尔海邦，一块这么大的水晶能换一栋带水下花园的宅子。”" },
      { kind: "p", text: "“那你卖了它。”乔奈说。" },
      { kind: "p", text: "“……我说说而已。”" },
      { kind: "p", text: "露娜拉则在北面的废墟里发现了一处隐蔽的地下密室。那是一扇半埋在瓦砾下的石门，门上刻着已经模糊的异教图腾，图腾的眼睛部分被人为凿去，像某种刻意的亵渎。她率先跳下，旧盾护在身前，落地时膝盖微屈，缓冲了冲击。她的眼睛在黑暗中迅速适应，尾巴在身后保持平衡。" },
      { kind: "p", text: "密室里盘踞着几只疾行虫，但比起外面的虫潮，实在算不得什么。她用刚毅重击砸翻两只，盾面与甲壳相撞的闷响在密室里回荡；泰拉克斯下来补了一脚，把第三只踩成了薄片，碎石与虫壳碎裂的声音混在一起。" },
      { kind: "p", text: "密室的角落里，藏着两样东西：一颗在黑暗中散发七彩微光的**虹光珠宝**，以及一个表面刻满符文的立方体——**传送魔方**。珠宝的光芒在黑暗中流转，像把一小段彩虹封在了石头里；魔方则冰冷而沉重，符文在它表面缓慢地旋转，像某种沉睡的机械。" },
      { kind: "p", text: "“先民的东西。”泰拉克斯摸着魔方，岩石手指传来一阵刺痛般的熟悉感。他的声音很低，像是在对自己说话。他的眼前闪过一些破碎的画面：无数这样的魔方排列在一座巨大的厅堂里，奥古拉人围着它们吟唱大地之歌。" },
      { kind: "p", text: "“先收着。”露娜拉把珠宝和魔方都塞进背包，“出去再研究。”" },
      { kind: "p", text: "她注意到泰拉克斯的手指在魔方上停留了很久，久到不像一个失忆的人该有的反应。但她没有问。每个人都有自己的秘密——就像她从未告诉任何人，每当夜深人静，她都会把盾面上那枚磨得模糊的飞龙纹章擦了又擦，仿佛只要它还亮着，星轮山就还没有彻底抛弃她。" },
      { kind: "p", text: "乔奈没有进密室。她在宝库外围探索，沿着峡谷边缘寻找入口。她的指尖在岩壁上摸索，像盲眼长者教她的那样，用触觉代替视觉。突然，她触到一片松动的泥土。她用手斧挖开，露出下面刻着的**树叶符文**——一片石化的树叶，叶脉中流转着微弱的绿光。" },
      { kind: "p", text: "“找到了。”她把符文按进山丘北侧的石门凹槽。" },
      { kind: "p", text: "石门轰然开启，露出一条向下的阶梯。暗克苏魔法的气息扑面而来，像某种腐烂的甜香，熏得人眼睛发酸。" },
      { kind: "p", text: "“走。”露娜拉率先踏入。" },
      { kind: "p", text: "宝库内部比想象中更大。这是一个充满暗克苏魔法的空间，墙壁上流转着暗红色的纹路，像血管一样搏动，每一次搏动都让露娜拉的心跳漏一拍；地面是某种黑色的石头，每走一步都像踩在某种活物的皮肤上，传来微弱的震颤，那震颤顺着她的脚底板爬上来，让她的尾巴尖微微发麻。空气里弥漫着一股混合了铁锈、腐木和硫磺的气味，火把的光芒在这里被压缩成一小团，只能照亮身前三步，三步之外就是浓得化不开的黑暗。" },
      { kind: "p", text: "宝库的结构像一座被掏空的蜂巢。他们脚下的通道呈螺旋状向下延伸，墙壁上每隔一段就有一扇半掩的石门，门后传来滴水声、风声，或是某种更糟糕的、类似呼吸的声音。头顶的穹顶上垂挂着钟乳石般的暗色晶体，晶体里封存着已经凝固的暗红色闪电，像一条条被冻住的血河。地面上散落着不知年代的白骨，有些属于人类，有些属于他们从未见过的生物，骨骼上还留着被利器劈砍的痕迹。" },
      { kind: "p", text: "祖法赛感觉自己像被扔进了一个巨大的、正在腐烂的胃袋里。他的心灵感应在这里受到了严重的干扰，每一次探出意识，都像把手伸进沸腾的油锅。他不得不把大部分注意力用来屏蔽那些无孔不入的暗克苏低语，那些低语像无数只小虫在他的颅骨里爬行。" },
      { kind: "p", text: "露娜拉走在最前面，旧盾护在身前，她的眼睛在黑暗中努力分辨着地面的异常。突然，她停下脚步，尾巴绷得笔直。" },
      { kind: "p", text: "“停。”她压低声音。" },
      { kind: "p", text: "前方的通道里，传来了密密麻麻的振翅声。那声音像无数张砂纸在同时摩擦，从四面八方包围过来。" },
      { kind: "p", text: "“凌光。”乔奈的头盔下传来低沉的声音，“一大群。”" },
      { kind: "p", text: "阴影中，无数**凌光恶魔**倾巢而出。它们不再是零星的几只，而是像一股灰白色的潮水，从通道的前后两端同时涌来。半透明的翅膀在黑暗中连成一片，尖牙上滴落着腐蚀性的唾液，落在黑色石头上，发出嘶嘶的声响。" },
      { kind: "p", text: "“围在我身边！”露娜拉吼道，旧盾猛地插在地上，护住身前。" },
      { kind: "p", text: "第一波凌光撞在盾面上，像一场带着尖牙的暴雨。露娜拉感到盾牌上传来密密麻麻的撞击力，每一击都不重，但叠加在一起让她的手臂发麻。她的余光瞥见乔奈被三只凌光缠住，短剑虽然精准，但双拳难敌四手；泰拉克斯的岩石身躯上爬满了凌光，它们正在用尖牙啃咬他的石肤；祖法赛的符文冲击已经有些散乱，他的心灵力量在暗克苏环境中消耗得太快。" },
      { kind: "p", text: "露娜拉知道，再这样下去，他们会被冲散。" },
      { kind: "p", text: "她咬了咬牙，从背包里摸出那颗**虹光珠宝**。珠宝在她掌心流转着七彩微光，像一颗被囚禁的黎明。她想起母亲曾经说过：真正的骑士，不是在安全时挥剑，而是在绝境中抉择。" },
      { kind: "p", text: "她用力捏碎了珠宝。" },
      { kind: "p", text: "七彩光芒没有散开，而是像液体一样顺着她的手臂流遍全身。露娜拉感到一股奇异的能量注入她的四肢百骸，她的动作突然变得轻盈，思维突然变得清晰。那不是速度，而是某种更深层的、对时间本身的短暂掌控——仿佛一瞬被拉长，让她能在敌人反应过来之前，接连完成两次本不可能完成的动作。" },
      { kind: "p", text: "她做了两件事。" },
      { kind: "p", text: "第一件，她挥舞旧盾，用刚毅重击在身前划出一道弧线，将扑向祖法赛的一群凌光全部拍飞。盾面与恶魔碰撞，发出一连串脆响，像冰雹砸在铁皮上。" },
      { kind: "p", text: "第二件，她转身，用盾牌的边缘狠狠砸在泰拉克斯的肩膀上。不是攻击，而是借力。泰拉克斯会意，借着这股力量旋转身体，岩石手臂像风车一样扫过，将身上和周围的凌光全部甩飞。" },
      { kind: "p", text: "七彩光芒散去。露娜拉感到一阵虚脱，握着盾带的手指都在发麻，但她没有倒下。" },
      { kind: "p", text: "“刚才那是什么？”祖法赛瞪大眼睛。" },
      { kind: "p", text: "“先民的东西。”露娜拉喘着气，“别浪费。”" },
      { kind: "p", text: "凌光群被这突如其来的反击打乱了节奏，它们在空中盘旋，发出困惑的嘶嘶声，暂时不敢再靠近。" },
      { kind: "p", text: "他们继续前进。通道变得越来越窄，墙壁上的暗红色纹路越来越密集，搏动得也越来越急，像整座宝库的心跳正在加速。空气中的硫磺味更浓了，还混着一种甜腻的腐臭，像某种过熟的花朵。" },
      { kind: "p", text: "突然，地面塌陷了。" },
      { kind: "p", text: "不是缓慢的沉降，而是整段通道在他们脚下断裂。四人同时坠落，下方是一个深不见底的竖井，井壁上覆盖着黏糊糊的暗紫色菌丝。" },
      { kind: "p", text: "“传送魔方！”乔奈喊道。" },
      { kind: "p", text: "露娜拉在坠落中摸索背包，她的手指碰到了那个冰冷的立方体。她没有犹豫，用力按下魔方中央的一个凸起。" },
      { kind: "p", text: "魔方亮起，一道银白色的光芒包裹住四人。坠落感消失了，取而代之的是一种被挤压、被拉伸、被揉成一团又展开的怪异感觉。露娜拉感到自己的内脏像被一只大手翻搅，她的眼前闪过无数破碎的画面：星空、海洋、森林、沙漠，然后一切归于平静。" },
      { kind: "p", text: "他们落在了竖井底部的一个平台上。魔方在露娜拉手中碎裂，化成一堆无用的粉末。" },
      { kind: "p", text: "“又一个一次性用品。”祖法赛瘫坐在地上，胃里还在一阵阵抽搐。" },
      { kind: "p", text: "“但我们活着。”乔奈说，她的脸色也很苍白。" },
      { kind: "p", text: "随着时间推移，不断有**凌光恶魔**——最小的暗克苏恶魔——从阴影里钻出来骚扰他们。它们只有巴掌大，长着半透明的翅膀和细长的尖牙，成群结队地扑向火把的光芒，又像飞蛾一样被烧得吱吱作响，焦臭味混在空气里，让人作呕。" },
      { kind: "p", text: "“这些小家伙比疾行虫烦人。”祖法赛用符文冲击轰碎一只凌光，碎片像玻璃一样溅了一地，有一片划过了他的脸颊，留下一道细细的血痕。" },
      { kind: "p", text: "“但它们怕光。”乔奈的披风亮起艾伊恩微光，凌光恶魔纷纷退避，在黑暗中发出不甘的嘶嘶声。她的手臂已经酸了，维持艾伊恩之光在这里比平时消耗更多体力，就像逆着洪水游泳。" },
      { kind: "p", text: "他们在宝库中分头探索。宝库的通道像迷宫一样分叉，每条岔路尽头都可能有宝物，也可能有死亡。乔奈的身手让她在狭窄的通道里如鱼得水，她像一道影子一样在断柱与残墙之间穿梭，披风上的艾伊恩微光在黑暗中忽明忽暗。她的手指在墙壁上摸索，寻找着盲眼长者教她的那种“会呼吸的石头”——那种内部中空的暗格。" },
      { kind: "p", text: "她先在一根倒塌的石柱后面发现了一处暗格。石柱表面刻着一只已经模糊的眼睛，眼睛的瞳孔部分是可以按动的。她按下去，石柱内部发出咔哒一声轻响，露出一个拳头大小的空间，里面放着**太阳符文**——一块圆形的金属片，中央刻着放射状的纹路，摸上去有微微的温热，像一块被阳光晒过的鹅卵石。" },
      { kind: "p", text: "第二处暗格在一面看似完整的石墙上。乔奈用短剑柄轻轻敲击，听着回音的变化。在第七次敲击时，她听到了那种空洞的回响。她用手指抠住石缝，用力一掰，一块石板被她撬了下来，里面放着**四叶草符文**——一片薄薄的翡翠，四片叶子在黑暗中发出柔和的绿光，像一小片被凝固的森林。" },
      { kind: "p", text: "“找到了。”她把两枚符文收进怀里，动作轻得像在收藏两片羽毛。" },
      { kind: "p", text: "祖法赛则绕到了山丘的东北角。那里有一片焦土，焦土下是一个深不见底的大坑。坑壁上有明显的抓痕，像是某种巨物曾经从这里爬进爬出，抓痕里还残留着暗红色的、已经干涸的液体。他小心翼翼地攀着钩索下行，索子放到尽头仍差着一截，他索性松手跃下，落地时震得双膝发麻，脚踝处传来一声脆响——疼痛却迟迟没有跟上，像是被这片深渊暂时扣下了。" },
      { kind: "p", text: "他直接落到了宝库的最深处。" },
      { kind: "p", text: "他看到了圣托尔。" },
      { kind: "p", text: "她蜷缩在一个半透明的魔法气泡中，气泡表面不断有红色闪电和蓝色电弧撞击，像暴风雨中的一盏灯。那是唯一能保护她免遭室内狂暴能量侵袭的屏障。她的焰龙蜥鳞片失去了光泽，独眼紧闭，呼吸微弱得像随时会停止。她的身体周围，暗红色的暗克苏能量像毒蛇一样游走，时不时抽打在气泡上，溅起一片刺目的火花。" },
      { kind: "p", text: "“三羽！”祖法赛喊道，声音在空旷的地下空间里回荡，带着他自己都没察觉的哭腔。" },
      { kind: "p", text: "圣托尔抬起头，独眼里闪过一丝欣慰，但立刻被痛苦取代。“别过来……”她的声音直接在他脑海中响起，虚弱得像风中的蛛丝，“这里的能量会撕碎你……”" },
      { kind: "p", text: "祖法赛的喉咙发紧。他想起了在微光鱿鱼旅馆，她也是这样从窗口探出身子，让他们去救她的手稿。那时候她多么强大，多么不可一世。现在她被困在一个气泡里，像一只被关在瓶子里的萤火虫。" },
      { kind: "p", text: "祖法赛没有靠近。他环顾四周，发现这个地下空间的墙壁上刻满了十字箭头形状的暗克苏符文，像某种古老的警告。在一个角落里，他发现了一个小小的隔间，隔间里放着一枚**星芒符文**——一颗八角星形状的晶体，中央有一点蓝光在缓缓旋转。" },
      { kind: "p", text: "他小心地取下符文，又取出梵诺主母那里得来的奥古拉水晶，把它放在隔间中央的基座上。" },
      { kind: "p", text: "水晶亮起，发出慰藉人心的蓝光。那光芒穿透宝库的层层阻隔，像水波一样荡漾开来，洒在每一位英雄身上。露娜拉感到手臂上被荆棘划出的伤口不再刺痛，乔奈感到因引导能量而透支的体力迅速恢复，泰拉克斯感到岩石躯体里被爆炸震出的裂缝不再传来钝痛。" },
      { kind: "p", text: "“这是……”露娜拉惊讶地看着自己的手臂。" },
      { kind: "p", text: "“奥古拉水晶的治疗力场。”祖法赛的声音从深处传来，带着一丝疲惫的得意，“我找到三羽了，但我们都被困在这里。”" },
      { kind: "p", text: "他抬头，面前是一面由红色能量构建的**绯红光墙**，像一堵燃烧的墙，把整个地下空间一分为二。光墙表面不断有电弧跳动，发出噼啪的爆裂声。" },
      { kind: "p", text: "祖法赛深吸一口气，双手抬起，用强大的念力引导星芒符文。他的手臂在颤抖，不是因为恐惧，而是因为过度使用心灵力量带来的肌肉痉挛。符文在空中旋转，投射出星芒般的光束，与绯红光墙碰撞。光墙开始溶解，像冰块在热水中消融，发出嘶嘶的声响，那声音像无数条蛇在耳边吐信。" },
      { kind: "p", text: "他的眼前闪过思缚者的脸，闪过造物主佩桑娜的宫殿，闪过他在凡提·玛夏克审查文献的无数个日夜。如果他死在这里，那些秘密就永远只是秘密了。" },
      { kind: "p", text: "“走！”祖法赛喊道，声音嘶哑。" },
      { kind: "p", text: "他从深坑里爬回宝库主层，与另外三人汇合。他的淡蓝色皮肤上沾满了尘土，额头上挂着蓝色的血珠，但眼睛亮得吓人。" },
      { kind: "p", text: "“你看起来像是刚被一头驼格尔踩过。”乔奈说。" },
      { kind: "p", text: "“比那糟。”祖法赛说，“但我找到了圣托尔，还顺手做了笔一本万利的买卖。”" },
      { kind: "p", text: "乔奈用四叶草符文打开了一间密室。密室里放着一柄**仪式之矛**——矛身由某种暗色金属打造，矛尖刻着螺旋状的符文，在黑暗中泛着冷光；旁边还有一瓶**治疗药剂**，液体呈淡金色，轻轻摇晃时会发出细碎的铃音。" },
      { kind: "p", text: "“武器归我，药剂归团队。”乔奈把药剂丢给露娜拉。" },
      { kind: "p", text: "“你打算一直带着它？”祖法赛问，“矛可不像短剑那么好藏。”" },
      { kind: "p", text: "乔奈把仪式之矛斜背到身后，短剑仍握在手里，像是不想完全放开旧习惯：“我用短剑。但这柄矛既然是从先民密室出来的，我也不会让它吃灰——等到了开阔地方，它比我顺手。”" },
      { kind: "p", text: "露娜拉接过药剂，塞进背包。她没有说话，但她的尾巴在身后轻轻摆动，那是她心情不错时的表现。" },
      { kind: "p", text: "乔奈又用太阳符文打开了宝库中的符文磨坊。磨坊的门上刻着一轮太阳，太阳的每一道光芒都是一道锁。乔奈把太阳符文按进中央的凹槽，符文与门上的纹路完美契合，发出一声清脆的咔哒声。" },
      { kind: "p", text: "门后是一个圆形的厅堂，厅堂中央有一个巨大的磨盘控制机关，被蓝色能量封锁着，像被冰封住的齿轮。机关的表面刻满了先民符文，那些符文与泰拉克斯皮肤上的某些残留痕迹隐隐相似。乔奈再次将引导能量注入泰拉克斯体内，泰拉克斯走上前，岩石双手握住机关，用力掰动。" },
      { kind: "p", text: "机关发出刺耳的摩擦声，像一头沉睡的巨兽在呻吟。泰拉克斯的手臂肌肉——如果岩石也有肌肉的话——绷得笔直，他的脚下，黑色的石头被踩出了两个浅坑。蓝色能量的封锁被解除了，磨盘缓缓转动，发出低沉的轰鸣，像某种古老的歌谣重新开始吟唱。" },
      { kind: "p", text: "“还差最后一间。”露娜拉说。" },
      { kind: "p", text: "她和祖法赛奔向宝库最深处的中央密室。乔奈和泰拉克斯则守在门口，拖住不断涌来的疾行虫和凌光恶魔。通往中央密室的通道比之前的都要宽阔，但也更加危险。墙壁上刻满了十字箭头形状的暗克苏符文，那些符文在他们经过时会微微发亮，像无数只眼睛在注视着他们。地面上散落着更多的白骨，有些白骨的手中至今还握着已经锈蚀的武器，像是在死前还在战斗。空气中的暗克苏气息浓得化不开，每一次呼吸都像在吞咽某种辛辣的液体。" },
      { kind: "p", text: "密室中，所有积聚的魔能汇聚成一个强力能量球，悬浮在房间深处，噼啪作响。那球体大约有三人合抱那么大，表面不断有红色和蓝色的电弧窜动，像一颗被困在笼子里的微型太阳。空气中弥漫着烧焦尘土的刺鼻气味和震耳欲聋的魔力鸣响，那鸣响不是声音，而是直接作用于骨髓的震颤，让露娜拉的牙齿都在打颤。致命的闪电无规律地劈向四周的墙壁与地板，每一次劈落都留下一个焦黑的坑洞，坑洞里还冒着青烟。密室的穹顶上刻满了先民的星图，但那些星星正在被暗红色的纹路侵蚀，像一片被污染的天空。" },
      { kind: "p", text: "能量球陷入了自我充能的恶性循环，随时可能引发内爆。" },
      { kind: "p", text: "“我们得让它停下来。”露娜拉说，旧盾在她手中微微颤抖，她不是在害怕，她是在计算——计算如果失败，他们还有几次呼吸的时间可以逃出去。" },
      { kind: "p", text: "“怎么停？”祖法赛问，他的声音在魔力鸣响中显得有些单薄，像一张被风吹走的纸。" },
      { kind: "p", text: "“不是用蛮力。”露娜拉伸出手，闭上眼睛。她的睫毛在颤动，她的呼吸在放缓，她在把自己沉入星轮山法师们教她的那种冥想状态，“用心。”" },
      { kind: "p", text: "祖法赛明白了。他也伸出手，两人的心灵感应交织在一起，像一张网，缓缓包裹住那个狂暴的能量球。他能感觉到露娜拉的意识，像一把出鞘的剑，坚定而锋利；他自己的意识则像一片深海，沉静而包容。两种截然不同的心灵技巧，在这一刻奇异地融合了。" },
      { kind: "p", text: "“安静。”露娜拉在意识里说，她的意识像一块投入沸水的冰。" },
      { kind: "p", text: "“我们不想伤害你。”祖法赛在意识里补充，他的意识像一阵穿过针眼的风。" },
      { kind: "p", text: "能量球剧烈地颤动了一下，一道闪电劈在露娜拉脚边，火星溅到她的锁甲上，烫出几个小洞。她没有退缩，她的脚趾在靴子里蜷起，但她的脊背挺得更直了。" },
      { kind: "p", text: "“安静。”她又说了一遍，声音在意识里像一面旗。" },
      { kind: "p", text: "祖法赛的额头渗出蓝色的血珠，顺着他的鼻梁滑落，滴在脚下的黑色石头上，发出轻微的嘶嘶声。他咬紧牙关，感觉自己的意识像被放在磨盘上碾压，每一次碾压都带来一阵钝痛。但他没有松手。他想起了凡提·玛夏克的劳工，想起了那些麻木的眼睛，想起了贝科拉之杖的碎片在他怀中发烫。如果这里爆炸了，那些劳工永远不会有改变命运的机会。他还想到了造物主佩桑娜的脸，那张永远带着微笑的、冷酷的脸。他不能在这里倒下。" },
      { kind: "p", text: "两人的心灵力量像两只手，轻轻按住了那个即将爆炸的心脏。露娜拉感觉到能量球内部的混乱，像无数头困兽在互相撕咬；祖法赛感觉到能量球深处的恐惧，像一个被遗弃的孩子在黑暗中哭泣。他们不是在对抗它，而是在安抚它，像安抚一头受伤的野兽。" },
      { kind: "p", text: "能量球的嗡鸣渐渐低了下去。它仍偶有闪电泄出，但自我充能的恶性循环已被掐断。那鸣响继续退去，一波弱过一波，终归于无。露娜拉感到一阵虚脱，她的膝盖一软，但她用旧盾撑住了身体。祖法赛则直接跪倒在地，他的意识像被榨干的柠檬，连抬手的力气都没有了。" },
      { kind: "p", text: "随着那些吸引并激怒怪物的魔力消散，疾行虫和凌光恶魔仿佛同时失去了目标，像被剪断了提线的傀儡，三三两两退入阴影深处。" },
      { kind: "p", text: "相互冲突的魔法能量，就此被他们联手抚平。最后几缕魔法闪电没入大地，隆隆巨响化作一声悠长的低语，散在了黑暗里。" },
      { kind: "p", text: "在宝库的中央密室中，圣托尔静静躺着，气息微弱。环绕她的魔法气泡正逐渐消散，像晨雾在阳光下蒸发。" },
      { kind: "p", text: "她喘着粗气，转过头看着他们，满脸痛苦且精疲力竭，却仍挤出一个疲惫的微笑。她的焰龙蜥鳞片失去了大部分光泽，像被水洗过的旧铜器。" },
      { kind: "p", text: "“世上仅存的裂隙守护者，恐怕只剩我一人了。”她说，声音沙哑得像砂纸摩擦，“现在，你们必须替我完成使命。拿着，用这把钥匙去开启符文谷的**裂天者**。那是你们必须点亮的信标之一，用以阻止暗克苏从裂隙侵入阿格莫尼亚。”" },
      { kind: "p", text: "她把一枚古老的钥匙塞进露娜拉手里。钥匙很重，表面刻着与符文板块相似的纹路，在火光中泛着淡淡的蓝光。" },
      { kind: "p", text: "“期待与你们再次相见，守护者们。”" },
      { kind: "p", text: "她似乎耗尽了最后一丝魔力。周围的世界开始旋转，她的身体像被风吹散的沙一样，渐渐消散开来，只留下一件空荡的长袍，轻轻落在地上。" },
      { kind: "p", text: "露娜拉怔怔地捧着钥匙，手指微微颤抖。她的尾巴垂在身后，一动不动。" },
      { kind: "p", text: "“她……死了吗？”乔奈轻声问。" },
      { kind: "p", text: "“没有。”泰拉克斯说，他的岩石手掌按在圣托尔消失的地方，那里还残留着一丝温度，“我感觉到了。她只是……去了另一个地方。”" },
      { kind: "p", text: "就在这时，墙上雕刻的巨大石首竟活了过来。它冰蓝的眼眸凝视着他们，声音低沉洪亮，却毫无威胁之感。相反，它的存在令他们倍感安宁，像冬日里的一盆火。" },
      { kind: "p", text: "“阿格莫尼亚的命运，如今掌握在你们手中。”它宣告道，“你们每一个人都拥有改变局势的力量，但也都有偏离光明的可能。你们的命运尚未书写，却终将在岁月中交织。你们的每一次选择，无论是出于个人还是源于团队，都将决定万物的归宿。”" },
      { kind: "p", text: "这是**艾伊恩之声**，与暗克苏及其恶魔对立的正义能量。它的声音不再在密室中回荡，而是直接响彻在他们脑海深处。" },
      { kind: "p", text: "然后，每个人都看到了属于自己的幻象。" },
      { kind: "p", text: "露娜拉看到了星轮山。不是现在的星轮山，而是三个月前的星轮山。她看到了母亲的血，那血不是红色的，而是暗瞳格里人特有的、在月光下泛着银光的蓝。她看到了那面她一直在寻找的飞龙之鳞盾牌，盾牌后面站着一个她看不清面容的人。那个人伸出手，像是在邀请她，又像是在警告她。" },
      { kind: "p", text: "然后，画面变了。她不再站在城堡的走廊里，而是站在一条泥泞的小巷中。她穿着破烂的衣裳，手里没有盾，只有半块发霉的面包。周围的人在咳嗽，在争吵，在为了几枚铜币打得头破血流。她闻到了贫穷与肮脏的味道，那是她从未真正理解过的味道。" },
      { kind: "p", text: "一个声音在她脑海中响起：你生于权贵，却失去了一切。你寻求的是重掌大权，还是赋予他人力量的机会？无论哪种，只要你还是被追捕的亡命徒，就都无法实现。" },
      { kind: "p", text: "她的右手掌心突然发烫。她低头，看见一个发光的印记正在她皮肤上浮现——**艾伊恩的标记**。那标记像一颗微缩的星辰，又像一只睁开的眼睛。" },
      { kind: "p", text: "让它指引你的探索，赐予你智慧。一旦找到盾牌，你将亲眼见证艾伊恩与飞龙之间古老的羁绊。但最重要的是，你现在必须成为一名裂隙守护者。" },
      { kind: "p", text: "画面碎裂了，只剩下那个掌心印记在黑暗中发光，像母亲临终前的眼睛，温柔而悲伤。而当光芒渐渐收敛，露娜拉发现自己的左手心里多了一样东西——一枚银质的徽章，正面刻着一只睁开的眼睛，背面是布林德利昂家族的飞龙纹章。那徽章入手温热，像一颗被握住的心脏，又像母亲最后残留在她掌心的温度。艾伊恩的恩赐。她立刻明白了它的名字与用途：在每次陷入绝境的危急时刻，它可以治愈一名同伴，将生命从死亡边缘拉回来。这不是权力的象征，而是守护的证明。" },
      { kind: "p", text: "乔奈看到了琥珀门的渔民区。不是现在的渔民区，而是她小时候的样子。她看到了她的女友，看到了盲眼长者站在一片光芒中，向她伸出手。但长者的眼睛不再是盲的，而是充满了星光。" },
      { kind: "p", text: "然后，她看到了另一幅画面。她看到自己站在一片陌生的海岸上，身上裹着襁褓，四周是陌生的面孔。她意识到，自己不是出生在这里的。她是在襁褓中便被流放至阿格莫尼亚的，是同类中的唯一幸存者。" },
      { kind: "p", text: "一个声音在她脑海中响起：艾伊恩之力在你体内流淌，至今仍能显现出那些古老的暗影。你过往的秘密就藏在你遗失的那顶王冠之中。找到王冠，你便能解开身世之谜。" },
      { kind: "p", text: "画面切换，她看到了符文谷的一家店铺，店主人是一个矮小的系诺克人，店里摆满了奇异的商品。在店铺的最深处，一顶王冠在黑暗中发光。" },
      { kind: "p", text: "去符文谷寻找王冠吧，就在那名系诺克人的店里。至于你现在戴的这一顶，不过是那件神器的虚影罢了。" },
      { kind: "p", text: "她低头，发现自己戴着的发光头盔正在变得透明，像一层即将消散的雾。" },
      { kind: "p", text: "声音再次响起：你在琥珀门受过一位裂隙守护者的训练，就是那个被你唤作“卵石”的人。他曾告诉你，你的使命是与恶魔战斗，而非对付普通的罪犯。当裂隙恶魔发动攻击时，谁控制着贫民窟便无关紧要。你必须学会放手。" },
      { kind: "p", text: "她看到了卵石——不是盲眼长者，而是另一个模糊的身影，站在琥珀门的码头上，背对着她。" },
      { kind: "p", text: "但最重要的是，你现在必须成为一名裂隙守护者。" },
      { kind: "p", text: "画面消散，只剩下她手中的短剑在黑暗中微微发烫，剑柄上仿佛还残留着某种她从未真正拥有过的温度。乔奈下意识地抬手触碰头盔，却发现那顶发光头盔之上，竟浮现出一顶更为古老、更为真实的王冠虚影。它不是金属，不是宝石，而是由纯粹的艾伊恩之光凝结而成——以太王冠。它没有重量，却散发着比任何王冠都沉重的存在感，仿佛承载着某个她尚未想起的王国。盲眼长者曾说过，真正的王冠从不彰显权力，只守护佩戴者的心智。乔奈忽然明白，当她抵御魔法攻击时，这顶王冠将为她多争取一线生机，让她在黑暗洪流中多看清一秒真相。" },
      { kind: "p", text: "祖法赛看到了凡提·玛夏克的水下都市。不是现在的都市，而是他从未见过的、没有造物主也没有思缚者的都市。他看到了贝科拉之杖完整的模样，那法杖不是武器，而是一把钥匙，一把打开水下都市所有牢笼的钥匙。" },
      { kind: "p", text: "一个声音在他脑海中响起：你在寻找贝科拉之杖，那是一件圣物，诞生于泽布尔海邦之前，甚至早于造物主与“追求繁荣”的时代。" },
      { kind: "p", text: "画面分裂成两条道路。一条路上，他手持完整的法杖，站在造物主的宫殿里，脚下堆满了金币与宝石，他成为了最强大的造物主；另一条路上，他手持法杖，站在劳工中间，他们的眼睛里不再是麻木，而是某种他不敢承认的东西——希望。" },
      { kind: "p", text: "它可以成为你解放被奴役的珂蓝安人、摆脱造物主枷锁的强力工具。或者，你也可以利用它让自己变得极其富有，甚至成为最强大的造物主。这取决于你的抉择，但若无法集齐法杖的所有碎片，一切皆为空谈。" },
      { kind: "p", text: "画面再次切换，他看到了符文谷的北门区，那里有一群珂蓝安人聚居。在他们中间，另一块碎片正在发光。" },
      { kind: "p", text: "去符文谷北门区的珂蓝安人那里寻找另一块碎片吧。只可惜，被你夺走法杖碎片的那个造物主，正与一股超乎想象的强大势力结盟，务必小心。" },
      { kind: "p", text: "他看到了造物主佩桑娜的脸，那张脸不再微笑，而是扭曲着，与某种更庞大、更黑暗的阴影重叠在一起。" },
      { kind: "p", text: "但最重要的是，你现在必须成为一名裂隙守护者。" },
      { kind: "p", text: "画面碎裂，只剩下他怀中的碎片在黑暗中跳动，像一颗不肯安分的心脏，像他自己那颗一半想致富、一半想解放的心。祖法赛低头，发现自己的腰带上不知何时挂着一只小巧的海螺。那海螺通体洁白，螺壳上流转着与贝科拉之杖碎片相似的深海纹路，在黑暗中泛着珍珠般的微光。当他用心灵感应轻触它时，一股温润的力量回应了他，仿佛整片泽布尔海邦的海水都在其中低语、涌动、等待被召唤。贝科拉的海螺。这是一件逃遁之宝，能在每次陷入绝境时，为他打开一条逃出生路的缝隙——无论多远，海水都会把使用者卷到安全的地方。祖法赛握紧它，心想：这或许是他这辈子最奢侈的备选方案。" },
      { kind: "p", text: "泰拉克斯看到了洛克托尔。不是现在的洛克托尔，而是它还未失落时的样子。他看到了那扇大门上的石脸，看到了一个与他长得一模一样的奥古拉人，正在用锤子敲打自己的胸膛，从身体里取出一块奥古拉水晶。" },
      { kind: "p", text: "一个声音在他脑海中响起：你究竟是谁？是纯良的泰拉克斯，还是曾降下无尽毁灭的索佐？" },
      { kind: "p", text: "画面切换，他看到了索佐——那个邪恶的奥古拉独裁者，站在洛克托尔的城墙上，脚下是无数跪伏的奴隶。索佐转过身，那张脸与泰拉克斯一模一样。" },
      { kind: "p", text: "你石肤上曾经刻满的符文如今已被磨平。你遗忘了如此多的记忆，或许这未尝不是件好事。让你的武器成为一面镜子，映照出你的新生，以及那个尚待成就的自我。" },
      { kind: "p", text: "他看到了两条道路。一条路上，他成为了泰拉克斯，用身体铸造武器，保护被奴役的苦难者；另一条路上，他变回了索佐，再次统领军队，将所有人踩在脚下。" },
      { kind: "p", text: "你会成为泰拉克斯，还是变回索佐？你会救助被奴役的苦难者，还是会再次奴役他们？你会再次统领索佐的军队吗？在符文谷寻找你过去的答案，然后决定该如何抉择。" },
      { kind: "p", text: "画面消散，只剩下他背脊上那片光滑的岩石，在黑暗中隐隐作痛。他第一次意识到，那片空白可能不是失去，而是某种保护——保护他不记起自己可能是谁。泰拉克斯低头，发现自己的手中多了一柄战锤。那战锤的握柄由某种他认不出的黑色岩石打造，锤头沉重，表面刻满了与他背脊上曾经符文相似的纹路——不是他认识的任何一种奥古拉文字，却比任何文字都更接近他的骨骼。泰拉克斯之锤。它不像樵夫的巨斧那样粗糙，也不像先民的仪式之矛那样纤细，它是一件属于他自己的身体延伸。每一次握紧它，他都能感受到其中沉睡的力量：只要挥出，便会比以往的任何一击都更加致命。它是镜子，也是答案；它映照的，是他尚未选择的自己。" },
      { kind: "p", text: "但最重要的是，你现在必须成为一名裂隙守护者。" },
      { kind: "p", text: "幻象消散。四人沉默地站在原地，谁也没有说话。火把的光芒在石壁上跳动，把他们的影子拉得很长，像四个被钉在地上的幽灵。" },
      { kind: "p", text: "露娜拉低头看着自己的右手掌心。那里什么也没有，但她分明记得刚才有一个发光的印记烙印在那里。她握了握拳，又松开。她看到了贫穷与肮脏，看到了那个关于“重掌大权还是赋予他人力量”的质问。她不知道自己想要哪一个，但她知道，只要她还是被追捕的亡命徒，就两者都得不到。" },
      { kind: "p", text: "乔奈的短剑还握在手里，剑刃上倒映着她自己的眼睛。她看到了襁褓中的自己，看到了那顶在系诺克人店里发光的王冠，看到了那个被称为“卵石”的裂隙守护者。她摸了摸头上的发光头盔，那头盔忽然变得陌生起来——它只是一件虚影，一件她失去之物的影子。而她甚至不知道那东西原本属于谁。" },
      { kind: "p", text: "祖法赛怀里的碎片还在发烫。他看到了两条道路，一条通往财富与权力，一条通往解放与希望。他还看到了佩桑娜与那股超乎想象的黑暗势力结盟的画面。他忽然意识到，自己偷走的不仅仅是一块碎片，而是点燃了一场他无法控制的战争的火种。" },
      { kind: "p", text: "泰拉克斯的岩石手掌还按在墙上，他的背脊传来一阵空落落的疼。他看到了索佐，看到了那张与自己一模一样的脸。他第一次意识到，自己背脊上被磨平的符文可能不是意外，而是某种刻意的遗忘——为了保护他，或者为了保护这个世界。" },
      { kind: "p", text: "“你们……看到了什么？”乔奈最终问，声音很轻，像怕惊动什么。" },
      { kind: "p", text: "“以后再说。”露娜拉说，她的声音有些沙哑。她不知道该怎么描述掌心的印记，就像她不知道该怎么描述这三个月来的逃亡。" },
      { kind: "p", text: "“同意。”祖法赛说，他第一次没有接茬开玩笑。他第一次觉得，有些秘密太重，重到连玩笑都托不起来。" },
      { kind: "p", text: "泰拉克斯没有说话。他只是把新得的战锤握得更紧了一些，像握着一面镜子——一面他还不敢照见自己的镜子。" },
      { kind: "p", text: "他们转身离开宝库。外面的天色已经暗了下来，夕阳在他们左侧沉落，将天空染成青色与玫瑰色交织的画卷。灵树林的方向还有零星的火光，但已经小了很多，像几粒即将熄灭的炭。空气里的焦糊味淡了些，但依然存在，像某种不肯散去的记忆。" },
      { kind: "p", text: "雷久纳和“小鸟号”一直在路边的安全处等待。驼格尔焦躁不安地刨着蹄子，它的眼睛在黑暗中睁得很大，鼻孔不断翕动，它察觉到了主人的离去。它的驼峰上，圣托尔留下的毯子还整整齐齐地叠在那里，像在等待一个不会回来的人。" },
      { kind: "p", text: "“嘘——”祖法赛走上前，用心灵感应安抚它。他的意识很疲惫，但他还是挤出一丝温柔，“她会回来的。她只是先走一步。”" },
      { kind: "p", text: "雷久纳安静下来，用脑袋蹭了蹭祖法赛的手。它的眼睛湿润了，如果驼格尔会哭的话。祖法赛忽然意识到，这头巨兽可能比他们所有人都更早地理解了什么是失去。" },
      { kind: "p", text: "他们协助雷久纳拉着“小鸟号”，向符文谷进发。车轮在碎石路上发出吱呀的声响，像某种古老的挽歌。雷久纳走得很慢，它的头低垂着，但它没有停下。" },
      { kind: "p", text: "每个人都在默默思索着圣托尔的命运，以及目睹的那场奇异幻象，犹豫着是该与他人分享，还是独自保守这个秘密。露娜拉握着那枚古老钥匙，钥匙的纹路硌着她的掌心，像某种无声的质问；乔奈摸着仪式之矛的矛身，感受着上面符文的凹凸，那些符文在她指尖下微微发烫，像有生命一般；祖法赛把贝科拉之杖的碎片和奥古拉水晶分开收藏，像收藏两个互相矛盾的梦，一个关于财富，一个关于解放；泰拉克斯则时不时回头望向山丘的方向，岩石面孔上没有任何表情，但他的脚步比平时更沉，像每一步都在往地里扎根。" },
      { kind: "p", text: "在地平线上，他们已能看见符文谷烟囱中升起的袅袅炊烟。那是一座城市的味道，是文明的味道，是无数普通人正在做饭、吵架、相爱的味道。那味道让祖法赛想起了凡提·玛夏克，想起了那些他以为自己已经忘记的、属于生活的气味。" },
      { kind: "p", text: "随着旅途继续，有一件事对他们而言已无比清晰：阿格莫尼亚的命运，正掌握在他们手中。而他们每个人心里，都多了一个不能说出口的秘密。" },
      { kind: "hr", text: "" },
    ],
    poem: ["余烟未尽照残阳，", "赤浪蓝涛卷古冈。", "圣托遭擒千仞险，", "妖虫匝地战三强。", "符文五启幽扉路，", "晶座能平沸血狂。", "巨灵降谕承圣命，", "同擎密钥向天阊。"],
    battleReport: "（死亡物品清单：无。啊对对队，全员存活。额外收获：仪式之矛×1、治疗药剂×1、古老钥匙×1、奥古拉水晶×1（已用于激活基座）。消耗：虹光珠宝×1（用于凌光围攻中争取一线先机）、传送魔方×1（用于坠落逃生）。下一站：符文谷。）",
  },
  "interlude": {
    title: "幕间：觅奇兽之月",
    endMark: "【幕间 完】",
    blocks: [
      { kind: "p", text: "觅奇兽之月升上符文谷的夜空时，城南的繁花在一夜之间尽数开放，甜腻的香气顺着河风漫过屋顶，钻进每一条街巷。" },
      { kind: "p", text: "啊对对队从南门步入城中，首先映入眼帘的，是盘踞在门内广场上的一尊巨大蛇形雕像——石鳞被岁月磨得光滑，蛇口大张，像是在无声地嘶吼。河对岸隐隐传来阵阵刺耳的尖啸，那声音不像风声，也不像兽鸣，倒像某种金属与魔法相互摩擦生出的、令人牙酸的高频震颤，顺着脊骨一路爬上后颈。" },
      { kind: "p", text: "“裂天者。”露娜拉抬头望向声音传来的方向。那座古老的巨塔矗立在崇高河岸的尽头，塔身缠绕着暗色的符文，塔顶没入低垂的云层。那就是艾伊恩之声指引他们前来的地方。她的尾巴在斗篷下不安地蜷了蜷。" },
      { kind: "p", text: "“先去安顿。”她说，“雷久纳和小鸟号需要休息。”" },
      { kind: "p", text: "他们把驼格尔和飞行马车寄存在了贪食飞龙酒馆。这座四层高的木结构建筑立在凡俗河岸的港口附近，是符文谷规模最大的客栈。招牌上画着一只展翅的虚空吐息巨兽——飞龙，那种至今仍栖息于人迹罕至山巅的稀有生物。这家店对异乡人和宠物的包容在符文谷堪称一股清流，马厩里甚至为雷久纳准备了专门的草料槽。" },
      { kind: "p", text: "“照顾好它。”祖法赛把一袋月光银塞给马厩伙计——分量他掂过，不多不少，“它要是瘦了，我唯你是问。”" },
      { kind: "p", text: "“您放心。”伙计掂了掂钱袋，笑得见牙不见眼。" },
      { kind: "p", text: "城里到处都是人。祭祀、商人、星象学家、守卫、罪犯、艺人、术士和旅者在街道上摩肩接踵，各色的口音与气味搅成一团。居民大多是暗瞳格里人，但也混杂着不少帕天甘人与珂蓝安人，他们大多从事搬运、清洁、叫卖之类的卑微营生。街角的阴影里，总有眼睛在掂量外来者的钱袋。" },
      { kind: "p", text: "“冠面客家族在这里疏于管治。”一个从琥珀门逃难来的老渔民告诉他们，“影幕会和黑貂王冠两大帮派把城市撕成了两半。提防扒手和劫匪。有人说这都怪磐怒客家族，他们正处心积虑地削弱冠面客的权威。”" },
      { kind: "p", text: "“看来我们来得不是时候。”祖法赛说。" },
      { kind: "p", text: "“我们什么时候来得是时候过？”乔奈反问。" },
      { kind: "p", text: "他们在凡俗河岸的圆形市场买了些食物和草药，又在奥古拉铁砧添置了些补给。炉火熊熊，锤声叮当，铁砧铺的主人——极光·奇灵思——听说他们曾在琥珀门的微光鱿鱼旅馆救过她的哥哥（那位五瞳教派的祭祀），执意给了他们折扣。" },
      { kind: "p", text: "“救命之恩，没齿难忘。”她说，铁锤在砧上敲出清脆的节奏。" },
      { kind: "p", text: "随后，四人分头行动，各自去追自己那条线索。" },
      { kind: "hr", text: "" },
      { kind: "h2", text: "露娜拉：匿名的星辰" },
      { kind: "p", text: "流放生涯把露娜拉带到了符文谷。这里有盘根错节的势力，理应能查到黑貂王冠的底细，以及飞龙之鳞盾牌的下落。但她也清楚，城里那些贵族和星象学家，如今想必已获悉她背负的谋杀指控。" },
      { kind: "p", text: "她摘下布林德利昂家族的徽章，塞进贴身的口袋；换上一顶朴素的兜帽，把银白色的长发拢进阴影里。此后，她混迹于地下巢穴和愤世嫉俗之徒常去的所在，在烟雾缭绕的角落里倾听醉汉的呓语，在赌桌旁观察赌徒的眼神，在码头边与搬运工交换只言片语。" },
      { kind: "p", text: "三天下来，她听到了不少传闻：黑貂王冠在城南有一个据点，由一个叫凯隆的强盗统领；冠面客家族的始祖达斯特罗的雕像在胜利公园里被人泼了红漆；紫晶教团的卡德法尔要塞最近加强了戒备；而关于飞龙之鳞盾牌，没有人听说过它的下落。" },
      { kind: "p", text: "这天傍晚，她正准备返回“舞动鸣炙”——那家常有艺术家、反叛者、异教徒和学生光顾的酒馆——一个洪亮的声音骤然在她身后炸响：" },
      { kind: "p", text: "“星辰露娜拉·布林德利昂！今日，以贝纳姆共和国之名，在全知天穹之下，你被捕了！”" },
      { kind: "p", text: "露娜拉的血液在那一瞬间凝固了。" },
      { kind: "p", text: "她转过身，看见了星辰玛丽昂·马达克——她认得这个女人：自己前侍从的姐姐，也是大姐的贴身护卫队长。对方穿着布林德利昂家族的制式铠甲，胸口的飞龙纹章在夕阳下泛着冷光；身后跟着几名家族士兵，那些士兵的脸上带着掩饰不住的不安与犹豫。" },
      { kind: "p", text: "露娜拉的母亲遇害后，显然她的大姐已经掌权，并且认为仅仅流放她还不够。倘若落在他们手里，她不只身首异处，连尾巴都保不住；更重要的是，她将永远无法找回盾牌，永远无法洗刷冤屈。" },
      { kind: "p", text: "“抱歉，”露娜拉对星辰玛丽昂说，她的手已经按在了军刀的刀柄上，“我还有些未了之事。”" },
      { kind: "p", text: "星辰玛丽昂身后的士兵面面相觑，神色不安。他们中许多人曾在露娜拉麾下服役，深知她在战场上的可怕——见过她单手劈开磐怒客的重甲，也见过她在星轮山训练场上连败七名骑士。" },
      { kind: "p", text: "“我不想伤害你，星辰露娜拉。”星辰玛丽昂说，但她的手也按在了剑柄上。" },
      { kind: "p", text: "“哼，痴心妄想。”" },
      { kind: "p", text: "露娜拉没有拔刀——拔刀就输了。她猛地转身，一头冲进了“舞动鸣炙”。" },
      { kind: "p", text: "“城卫队来了！”她一边跑一边大喊，“他们来抓你们了！”" },
      { kind: "p", text: "酒馆里瞬间炸开了锅。二十几个惊慌失措的学生、星象学家、邪教徒、异教徒、农奴、作家和艺术家像受惊的羊群一样向门口涌去。星辰玛丽昂和她的士兵跟着冲进来时，迎面撞上了这股恐慌的人潮。桌椅被撞翻，酒杯被踩碎，有人尖叫，有人咒骂，有人干脆直接从窗户翻了出去。" },
      { kind: "p", text: "露娜拉从后门溜出，穿过两条小巷，没入夜色。兜帽被风吹落，银白色的长发在月光下像一面旗帜。她的心脏在胸腔里狂跳，不是因为恐惧，而是因为愤怒——她的亲姐姐派人来抓她了。那个曾经和她一起在星轮山的星空下许下诺言的人，如今想要她的命。" },
      { kind: "p", text: "她设法查到了星辰玛丽昂的住处——崇高河岸的一家客栈——并于深夜潜入，没有惊动任何人。士兵们的战袍被她尽数卷走，塞进了城市深处的下水道。第二天星辰玛丽昂醒来时，她的士兵看上去与寻常雇佣兵无异，贵族家臣特有的体面与特权荡然无存。置办新制服总要些时日，这足以让星辰玛丽昂暂时消停一阵。" },
      { kind: "p", text: "“这只是拖延。”露娜拉站在屋顶上，望着远处的裂天者，尾巴在夜风里绷得笔直，“我需要更快。”" },
      { kind: "hr", text: "" },
      { kind: "h2", text: "乔奈：王冠的线索" },
      { kind: "p", text: "乔奈步入符文谷时，即便遮住了面容，路人仍对她侧目而视。他们从未见过、也无法想象她这般的存在——既像暗瞳格里人，又带着某种说不清的异域气息。她早已习惯了围观与辱骂，心境很难再起波澜。至少，不似从前那般在意了。" },
      { kind: "p", text: "她来符文谷是为了寻找一名系诺克人。幻象中的声音告诉她，那个系诺克人曾从琥珀门的黑帮“老板娘”手中买下了她的艾伊恩头盔。而正是那个“老板娘”，在她孩提时代从家中偷走了它。" },
      { kind: "p", text: "符文谷只住着一位系诺克人，所以这谜题的第一部分很容易解开。" },
      { kind: "p", text: "里亚博在崇高河岸城区售卖魔法神器。乔奈走进“里亚博圣物堂”，却发现店里一片狼藉：稀世珍宝在空中慵懒地漂浮，打开的罐子散落一地，五颜六色的粉尘四处喷涌，里亚博本尊正倒挂悬浮于天花板上，试图控制这混乱的局面。" },
      { kind: "p", text: "“噢，感谢三圣一体，你终于来了。”它看到乔奈时说道。" },
      { kind: "p", text: "乔奈以前只远远见过几个系诺克人，但它们总是三个一群出现，而且个头比里亚博小得多。里亚博沿着缓慢的螺旋轨迹飘落，来到她面前，依然微微悬浮于地面之上。" },
      { kind: "p", text: "“你不是符文谷城防队的萨吉塔里昂中士。”它说。" },
      { kind: "p", text: "“显而易见。”乔奈回答。" },
      { kind: "p", text: "“里亚博已经很久没见过像你这样的生灵了。”" },
      { kind: "p", text: "“你见过我的同类？”乔奈的心跳漏了一拍。" },
      { kind: "p", text: "“没时间解释了。里亚博的店遭到了袭击。恶魔崇拜者偷走了一个珍贵的重力魔方，现在整个地方都乱套了。”" },
      { kind: "p", text: "乔奈说明来意——十五年前它买下的那顶头盔——但里亚博此刻显然无暇翻旧账。" },
      { kind: "p", text: "“那不是头盔，是王冠。”里亚博说，它的三只眼睛同时眨了眨，“你把重力魔方拿回来，里亚博就跟你谈那顶王冠的事。”" },
      { kind: "p", text: "“是谁拿走的？”" },
      { kind: "p", text: "“德拉维丝·怒爪，一个恶魔邪教徒。”里亚博随后告诉她，该邪教正藏身于怒爪家族的一座城内宫殿中。" },
      { kind: "p", text: "乔奈来到怒爪家族的宫殿前。门楣上刻着家族纹章——阿格莫尼亚双月中较小的那一颗，艾蒂。尽管院外有守卫把守，她还是很快断定：邪教徒在二楼设了一间仪式大厅，而且他们此刻就在那里。" },
      { kind: "p", text: "她像一片影子贴在怒爪宫殿外的墙上，默默记下邪教徒的出入路线与破绽：换岗的间隙、巡逻的盲区、门窗的松动程度。时机一到，她果断出手。" },
      { kind: "p", text: "她披着厚重的斗篷伪装自己，将其中一人扔进了河里。另一个被她丢进了正义之塔的废墟中。第三个则被她捆起来挂在了灯柱上，像一面奇怪的旗帜。不到天黑，邪教徒的骨干便已尽数落网。" },
      { kind: "p", text: "她换上从其中一人身上剥下的长袍与兜帽，念出偷听来的口令，混进了怒爪宫殿。登上楼梯，仪式大厅里，黑暗主教德拉维丝·怒爪正捧着那枚重力魔方。" },
      { kind: "p", text: "“以格拉兹纳克之名，”她咒骂道，“你们怎么这么慢？其他人呢？”" },
      { kind: "p", text: "乔奈压低嗓音说楼下有急事找她，指望把人支开、留下魔方。黑暗主教狐疑地上下打量她。" },
      { kind: "p", text: "“是吗？告诉我，我们的计划是什么来着？”" },
      { kind: "p", text: "“嗯。当然是将恶魔引入这个世界，然后彻底毁灭它。”乔奈面不改色。" },
      { kind: "p", text: "德拉维丝一个字也没信。她的手指骤然扣紧了重力魔方。" },
      { kind: "p", text: "乔奈没有犹豫，整个人欺身抢上，试图将魔方从她手中夺过来。德拉维丝反应不慢，但乔奈更快——短剑没有出鞘，剑柄狠狠砸在对方的腕骨上。魔方脱手飞起，乔奈一把捞住，转身就跑。" },
      { kind: "p", text: "她抱着重力魔方冲出怒爪宫殿，怒爪士兵在身后紧追不舍。所幸里亚博圣物堂离此不远，她一头扎进店里，追兵也跟着涌了进来。" },
      { kind: "p", text: "“快！把魔方给里亚博！”里亚博喊道。" },
      { kind: "p", text: "乔奈把魔方扔给里亚博。它立刻激活了魔方，追赶的士兵被吸到了空中，像被无形的手攥住的苍蝇，无法靠近她。她趁机缴了他们的械，把人一个个拖出了店门。" },
      { kind: "p", text: "“你做得不错。”里亚博说，店里的漂浮物终于开始缓缓降落，“现在里亚博要告诉你关于王冠的事了。”" },
      { kind: "p", text: "乔奈在圣物堂的后屋坐下。里亚博递来一杯热气腾腾的蓝色饮料，她婉谢了——说不清那是什么泡的，只闻到一股蘑菇混着矿石的气味。" },
      { kind: "p", text: "里亚博记得那顶王冠。它是从一个来自琥珀门的暗瞳格里女人手里买下的，那女人的长指甲涂成了绿色。那肯定是“老板娘”。" },
      { kind: "p", text: "“那个王冠让里亚博想起了家乡。”里亚博说，它的三只眼睛同时眯起，像是在回忆，“它非常有价值。里亚博把它卖给了一个专门收集这类物品的商人。”" },
      { kind: "p", text: "它给了乔奈一个名字和一个地址：卡德法尔要塞附近，一个暗瞳格里女人。" },
      { kind: "p", text: "终于，乔奈有线索了。" },
      { kind: "p", text: "她走出圣物堂时，夜色已深。她抬手摸了摸头上的发光头盔——月光下，它显得格外虚幻。如今她知道了，这只是一道影子，一件失去之物的投影。而真正的王冠，正在这座城市的某个角落等着她。" },
      { kind: "hr", text: "" },
      { kind: "h2", text: "祖法赛：旱行者" },
      { kind: "p", text: "符文谷是一座暗瞳格里人的城市，虽然也有其他种族的小型聚居点，但祖法赛在街头几乎见不到珂蓝安同胞的身影。这并不奇怪，毕竟这是一座只有一条河流穿过的内陆城市。珂蓝安人需要水，需要盐，需要那种水下都市特有的、带着压力的湿润空气。" },
      { kind: "p", text: "他在这里只见过两个显眼的珂蓝安人：一位是八贤议会第二环的术士，另一位是地渊的酒馆老板。但他找的并不是他们。" },
      { kind: "p", text: "幻象中的声音告诉他，贝科拉之杖的另一块碎片在符文谷北门区的珂蓝安人那里。他循着这条线索，找到了一群“旱行者”——那些离开水下都市、在陆地上出卖劳力的珂蓝安人——就在北门区贫民窟的一间大劳役所里干活度日。" },
      { kind: "p", text: "祖法赛没有直接闯进去，而是先伏在暗处观察了半日。那是一栋低矮的木屋，门口堆满空罐子。劳作的珂蓝安人极少离开木屋，只在卸下马车运来的蛇根草菇和空罐时现身；等罐子在劳役所里装满了，他们再将其搬出来。活计日夜不休，他们轮班睡觉。" },
      { kind: "p", text: "显然，这些湿马克人在为某位造物主卖命。但祖法赛从未见过那人的真面目。“旱行者”珂蓝安人也能成为造物主吗？成为那种赐予他人工作与意义、将成功福泽大众的至高存在？不太可能。不过，他们一定知道关于贝科拉之杖的线索。" },
      { kind: "p", text: "祖法赛在劳役所外截住了其中几个人，小心翼翼地探查他们的思想。若对方把他当作同类，或许会把一切和盘托出。" },
      { kind: "p", text: "他们的思想比想象中更难侵入。那不是普通的戒备，而是某种被灵能篡改过的痕迹——就像有人用钝刀在他们的意识里刻下了屏障。但祖法赛还是做到了。他的心灵触须像水一样渗透进去，找到了缝隙。" },
      { kind: "p", text: "一旦进入对方的意识，他就让他们相信：他是他们的老朋友兼老同事，而且——他们还欠着他一笔逾期未付的工钱。" },
      { kind: "p", text: "“你终于来了。”一个珂蓝安人对他说，他的眼睛里带着祖法赛从未见过的疲惫，“老板说下个月就发。”" },
      { kind: "p", text: "“我等不了了。”祖法赛说，他的声音在对方脑海里像是从很远的地方传来，“告诉我，老板是谁？”" },
      { kind: "p", text: "“穆多克先生。”对方说，眼神变得恍惚，“他不是造物主。他甚至不是珂蓝安人。他是暗瞳格里人，一个药剂商人。”" },
      { kind: "p", text: "祖法赛走进了劳役所。他看清了那些珂蓝安人如何榨取蛇根毒液：草菇投进石臼，用木杵捣碎，再把毒液一滴滴挤进罐子里。他们的手指被毒液蚀得发黑，却仿佛感觉不到疼痛；眼睛空空的，像两口干涸的井。" },
      { kind: "p", text: "“他对你们做了什么？”祖法赛问。" },
      { kind: "p", text: "“穆多克先生说，这是为了我们的好。”对方机械地回答，“他说，只要我们工作够努力，他就会带我们回泽布尔海邦。”" },
      { kind: "p", text: "祖法赛胃里一阵翻腾。这哪里是雇佣，分明是心灵控制。穆多克对这些湿马克人施加了某种灵能篡改，让他们变成了只会工作的傀儡。这意味着他掌握着某种强大的心灵力量来源——很可能就是贝科拉之杖的一块碎片。" },
      { kind: "p", text: "“他在哪里？”祖法赛问。" },
      { kind: "p", text: "“穆多克先生不住在这里。”对方说，“他只在月底来收罐子。”" },
      { kind: "p", text: "祖法赛退出了对方的意识。他站在劳役所的阴影里，看着那些珂蓝安人像工蚁一样忙碌。他想起了凡提·玛夏克的劳工，想起了那些排队领薪水的麻木面孔。这里和那里，有什么区别？" },
      { kind: "p", text: "他需要找到穆多克。但在此之前，他需要更多情报，也需要一个周密的计划——如果穆多克真的握有贝科拉之杖的碎片，他就拥有与祖法赛相当的心灵力量，甚至可能更强。贸然冲进去，血本无归。" },
      { kind: "p", text: "“我会回来的。”祖法赛低声说，不知是说给空气，还是说给自己，“而且会连本带利。”" },
      { kind: "hr", text: "" },
      { kind: "h2", text: "泰拉克斯：苔石酒馆" },
      { kind: "p", text: "泰拉克斯一度遗忘了自己作为独裁者索佐的过去，但现在往事已然觉醒。数百年前，无数人因他而丧命或被奴役。离奇的梦境与记忆纠缠着他，压得他日渐沉重。他会在半夜惊醒——如果奥古拉人也会睡觉的话——发现自己的岩石手掌在颤抖。他看见那些被他踩碎的城池，听见那些被他奴役之人的哭喊，嗅到那些被他焚烧的村庄飘出的焦烟。" },
      { kind: "p", text: "若要成为一名裂隙守护者，他必须彻底忘掉自己曾是索佐。" },
      { kind: "p", text: "他在符文谷与五瞳教派的星象学家和祭祀交谈，但他们拿不出任何对策，甚至无法理解他的困扰。一个奥古拉人怎么会被自己的记忆折磨？石头不是应该永恒不变吗？" },
      { kind: "p", text: "“你们不懂。”泰拉克斯说。他转身离开时，脚步声比平时更沉。" },
      { kind: "p", text: "他意识到，他需要和其他奥古拉人谈谈。" },
      { kind: "p", text: "符文谷里的奥古拉人凤毛麟角，大多都在为紫晶教团效力。他在街上拦住了一个。对方身穿教团的灰紫色长袍，背脊上的奥古拉水晶被精心打磨过，在阳光下闪着骄傲的光。" },
      { kind: "p", text: "“如果需要一种‘液体解法’来帮助你，你应该去苔石酒馆。”那个奥古拉人在继续赶路前对他说道，声音低沉得像两块石头在摩擦。" },
      { kind: "p", text: "循着这条指点，泰拉克斯揣着暴君过往的可怕记忆，在北门区的一个地窖里找到了苔石酒馆。这里竟既是酒吧，也是刻纹馆。馆内光线昏暗，只有零星的奥古拉水晶闪烁着光芒。空气中弥漫着一股酸味，四周充斥着如低雷般的沉闷轰鸣，那是顾客们低沉的歌声。放眼望去，这里似乎全是奥古拉人。" },
      { kind: "p", text: "角落里，一个年迈的奥古拉人正在某人的石背上雕刻符文。刻纹师抬起头，打量了泰拉克斯片刻，随后回过神来说道：" },
      { kind: "p", text: "“你好，朋友。我是奥莫克斯，这里是苔石酒馆。要来‘喝’点溶液吗？”" },
      { kind: "p", text: "“只要水就好，谢谢。”泰拉克斯说。" },
      { kind: "p", text: "“水？那可给不了你想要的‘解决办法’。”奥莫克斯说着从雕刻台起身，走到了吧台后面。" },
      { kind: "p", text: "泰拉克斯现在明白了。这些顾客寻求的并非启迪，而是想让那些饮品溶解自己的内脏，最终让自己也化作一摊溶液，这便是“解法”。持光者一向鄙视那些通过饮用溶液或食用虚空之花来麻痹心智的奥古拉人。导师们教导他要冥想、要铭记，但泰拉克斯此刻只想遗忘。" },
      { kind: "p", text: "他朝那位年迈的奥古拉人走近了几步，看到他石灰岩构成的躯体中布满了不知名海洋生物的化石。这让他的面容显得有些扭曲，但也让泰拉克斯意识到，这里就是寻找答案的地方。" },
      { kind: "p", text: "泰拉克斯在苔石酒馆只点了杯水——他感觉到四周投来几道侧目的目光。" },
      { kind: "p", text: "“你不是那些在异变之地游荡的宗教团体的一员吧？”奥莫克斯问道。" },
      { kind: "p", text: "“我曾经是。”泰拉克斯承认道，“但现在只剩我一个了。”" },
      { kind: "p", text: "“想跟我说说发生了什么吗？”" },
      { kind: "p", text: "泰拉克斯告诉奥莫克斯影幕会是如何袭击他的，以及那如何触发了他想彻底遗忘的往昔旧梦。他没有说出索佐这个名字，但他说得已经够多了。" },
      { kind: "p", text: "“那你的符文呢？”奥莫克斯问，“它们在哪儿？”" },
      { kind: "p", text: "“我不知道。”泰拉克斯说，他的背脊传来一阵空落落的疼，“它们被磨平了。”" },
      { kind: "p", text: "“听起来，你已经在快速遗忘的路上了。”" },
      { kind: "p", text: "“你能帮我吗？”" },
      { kind: "p", text: "奥莫克斯沉默了片刻。他石灰岩的面孔在昏暗的光线里像一尊古老的雕像。" },
      { kind: "p", text: "“我们的族人一向执着于铭记，”酒保奥莫克斯说道，“但我看得出，你需要的是遗忘。办法倒是有一个，只是过程既困难又危险。我只见人做过一次，那是很久以前的事了。”" },
      { kind: "p", text: "泰拉克斯告诉他，只要能达成目的，他愿意付出任何代价。" },
      { kind: "p", text: "“有一种酸，若与磨碎的奥古拉粉末混合，能摧毁你的记忆。”奥莫克斯说，“但要调制这种酸，我需要氢氟酸。玻璃吹制工或药剂师那里可能有。运输时，你必须把它包裹在冰里，以免它沸腾汽化。千万别让它受潮，否则它会腐蚀透任何东西。要弄到它可能需要花点时间，但当你拿到后，就回来找我。”" },
      { kind: "p", text: "“我会的。谢谢你，奥莫克斯。”" },
      { kind: "p", text: "“在你寻找这种物质的时候，请慎重考虑这是否真的是你想要的。”奥莫克斯说，他那双嵌着化石的眼睛在黑暗中幽幽发亮，“如果你让那种酸液溶解了记忆，你可能永远也找不回它了。”" },
      { kind: "p", text: "泰拉克斯再次向他道谢，离开了苔石酒馆。他走在符文谷的夜色里，岩石脚掌踩在石板路上，发出一声声闷响。他摸了摸自己的背脊，那片光滑的岩石在月光下像一面空白的盾牌。" },
      { kind: "p", text: "很快，他就能彻底忘掉那段可怕的过去了。" },
      { kind: "p", text: "但问题是，他真的想忘掉吗？" },
      { kind: "p", text: "他站在街心想了很久，久到觅奇兽之月在头顶挪过了一指宽。" },
      { kind: "hr", text: "" },
      { kind: "h2", text: "收束：各自的秘密" },
      { kind: "p", text: "四人在贪食飞龙酒馆的大厅里重聚时，已经是三天后的夜晚。" },
      { kind: "p", text: "公共大厅里，一个暗瞳格里乐师拨弄着某种弦乐器，歌声低沉而忧伤。酒馆里挤满了客商、冒险者和形形色色的访客，空气中弥漫着烤盐鱼、麦酒和汗水的气味。" },
      { kind: "p", text: "露娜拉坐在角落里，兜帽压得很低。她的旧盾靠在桌边，盾面上的飞龙纹章在烛光下若隐若现。她的左手无意识地摩挲着掌心那道银亮的烙印——艾伊恩的恩赐，那印记在酒馆温暖的空气中微微发热，像一颗提醒她不要忘记守护承诺的心脏。她告诉队友们她遇到了布林德利昂家族的追兵，但她没有说她藏起了星辰玛丽昂士兵的战袍。那是她的秘密，也是她的保险。" },
      { kind: "p", text: "乔奈坐在她旁边，头盔放在桌上。头盔上方，那顶只有她能看见的以太王冠虚影在烛光中若隐若现，像一道来自过去的叹息。她告诉队友们她找到了王冠的线索，但她没有说那个王冠在卡德法尔要塞附近的一个暗瞳格里女人手里。她需要时间去查清楚，在没有把握之前，她不想让任何人失望。" },
      { kind: "p", text: "祖法赛坐在对面，面前摆着一杯没动的麦酒。他的手指无意识地拨弄着腰间那枚贝科拉的海螺，螺壳上的深海纹路在昏暗灯光下泛着幽蓝。他告诉队友们他找到了贝科拉之杖碎片的线索，但他没有说那个穆多克先生可能拥有与他相当的心灵力量。在算清这笔账之前，他不会轻举妄动。" },
      { kind: "p", text: "泰拉克斯坐在最远的位置，岩石身躯在烛光下像一尊沉默的雕像。泰拉克斯之锤斜靠在他手边，锤头上的符文在烛光中偶尔闪过一道暗芒，像某种尚未决定的命运。他告诉队友们他找到了遗忘过去的方法，但他没有说那个方法需要氢氟酸，也没有说他正在犹豫是否要真的遗忘。他的岩石手指在桌面上轻轻敲击，像在打某种只有他自己能听到的节拍。" },
      { kind: "p", text: "“我们接下来怎么办？”乔奈问。" },
      { kind: "p", text: "“等。”露娜拉说，“等星辰玛丽昂的风头过去，等你的王冠线索更清晰，等祖法赛找到穆多克，等泰拉克斯做出决定。”" },
      { kind: "p", text: "“然后呢？”" },
      { kind: "p", text: "“然后，”露娜拉抬起头，兜帽下的眼睛在烛光中闪烁，“我们去点亮裂天者。”" },
      { kind: "p", text: "酒馆的音乐换了一首曲子，更加低沉，更加忧伤。四人都沉默了。他们每个人都有自己的秘密，每个人都在等待。觅奇兽之月在他们头顶缓缓移动，像一颗巨大的、发亮的眼睛，注视着这座城市的每一个角落。" },
      { kind: "p", text: "而在城市的另一端，裂天者仍在发出刺耳的尖啸，像某种古老的警告，也像某种急切的召唤。四条线索都已在夜色里埋下了头，剩下的，只是等它们破土而出的那一天。" },
      { kind: "hr", text: "" },
    ],
    poem: ["古月临城万籁寒，", "尖声裂夜彻云端。", "银徽深敛藏身影，", "暗市穿行探宝冠。", "默坐深渊谋胜算，", "岩躯独对旧瘢残。", "灯昏酒醒风初静，", "且抱幽情待更阑。"],
    battleReport: "（死亡物品清单：无。啊对对队，全员存活。额外收获：星辰玛丽昂士兵战袍×若干（已藏匿）、王冠线索×1、穆多克先生线索×1、氢氟酸线索×1。下一站：符文谷深处 / 裂天者。）",
  },
  "ch4": {
    title: "第四章：暮光守望",
    endMark: "【第四章 完】",
    blocks: [
      { kind: "p", text: "贪食飞龙酒馆的公共休息室里，一群熟客模样的平民正围着角落的桌子争论，声音压得极低。但露娜拉那双暗瞳格里人的耳朵，还是捕捉到了几个词：货物、黑貂王冠、影幕会、不能让他们知道。" },
      { kind: "p", text: "随后，那群平民愤然离席，只留下一个戴着月光银耳环的男子自斟自饮。他穿着一件看似普通、剪裁却极为精良的深色外套，手指修长，指甲修剪得整整齐齐。他的笑容很和善，但那双眼睛——那双在昏暗烛光下依然明亮的眼睛——却像两把藏在丝绒里的匕首。" },
      { kind: "p", text: "酒馆老板擦着杯子悄声透露，此人常与一些来路不明的家伙厮混，甚至有人听见他谈论禁忌之神。" },
      { kind: "p", text: "那名神秘男子轻抿一口劣酒，察觉到了他们的目光。他露出一抹了然的微笑，抬手示意他们入座。" },
      { kind: "p", text: "“今日星辰眷顾，让我得以结识各位。”他说道，声音低沉而富有磁性，“我叫凯隆。我手头正缺些帮手，如果各位有兴致，我这儿有份差事。绝不犯法，只是过几天里挑一个晚上，去替我守一夜仓库。这钱很好赚，只要别在岗上打瞌睡就行。”" },
      { kind: "p", text: "祖法赛立刻警觉起来。他的心灵感应像触须一样悄悄探过去，但凯隆的意识像一堵光滑的墙，什么都探不到。" },
      { kind: "p", text: "“什么样的货物？”露娜拉问，她的兜帽压得很低。" },
      { kind: "p", text: "“合法的货物。”凯隆微笑，“只是需要合法的人在合法的时间看守。”" },
      { kind: "p", text: "“那为什么要深夜看守？”乔奈问。" },
      { kind: "p", text: "“因为白天太忙。”凯隆说，“而且有些货物，在月光下比在阳光下更安全。”" },
      { kind: "p", text: "泰拉克斯没有说话。他的岩石面孔在烛光下像一尊雕像，但他的目光一直停留在凯隆的月光银耳环上。那耳环在晃动时，会反射出一种他熟悉的光芒——奥古拉水晶的光芒。" },
      { kind: "p", text: "“报酬多少？”祖法赛问。" },
      { kind: "p", text: "凯隆说了一个数字。祖法赛在心里计算了一下，那足够他们在符文谷舒舒服服地住上半个月。" },
      { kind: "p", text: "“成交。”祖法赛说，但他在桌子底下踢了踢露娜拉的脚，示意她小心。" },
      { kind: "hr", text: "" },
      { kind: "p", text: "薄暮时分，他们随凯隆走出贪食飞龙酒馆。夕阳把符文谷的屋顶染成金红色，河面上漂浮着晚归船只的灯火。他们沿街穿过圆形市场，商贩们正在收摊，空气中残留着烤盐鱼和香料的气味。" },
      { kind: "p", text: "朝着连接凡俗河岸与北门区的石桥走去时，光线迅速黯淡下来。北门区是一片破败的贫民窟。野狗在露天下水道旁饮水，瘾君子歪坐在每一处门槛上，眼神空洞地望着天空。阴暗的巷弄里，影影绰绰的家伙们正进行着各种可疑交易。空气中弥漫着一股混合了污水、劣质酒精和某种更黑暗的东西的气味。" },
      { kind: "p", text: "祖法赛隐约感到有人正暗中窥视，甚至尾随其后。他的心灵感应不断捕捉到零星的恶意，像雨点一样打在他的意识上。他靠近露娜拉，低声说：“至少有五个人在跟踪我们。”" },
      { kind: "p", text: "“我知道。”露娜拉说，她的手始终按在军刀柄上，尾巴在身后轻轻摆动，保持着暗瞳格里人特有的平衡与警觉。" },
      { kind: "p", text: "一瞬间，祖法赛闪过一个念头：若凯隆想对他们下杀手，这里便是最理想的埋骨之地。狭窄的小巷，无人的夜晚，四个外来者——尸体到早上都不会被发现。" },
      { kind: "p", text: "然而，凯隆只是悠闲地并肩而行，口中哼唱着古老的歌谣，诉说着昔日暗瞳格里女神的往事。他的声音在夜色中飘荡，像某种古老的咒语，又像某种无害的消遣。" },
      { kind: "p", text: "“你们知道吗，”他说，“拉尼莫拉曾经在这座城市里拥有无数信徒。她的雕像曾遍布河岸，如今大多被拆毁了，可总有几尊还立在不起眼的角落里。有些人，还记得。”" },
      { kind: "p", text: "“你是异教徒？”露娜拉问。" },
      { kind: "p", text: "“我是记得的人。”凯隆说，“记住过去，不等于背叛现在。”" },
      { kind: "p", text: "他们穿过整个北门区，最终在一座紧靠城墙、平平无奇的木屋前驻足。木屋的墙壁被潮气和煤烟熏得发黑，门口挂着一盏昏黄的油灯，灯芯噼啪作响，像某种垂死的昆虫。" },
      { kind: "p", text: "“到了。”凯隆说道。" },
      { kind: "p", text: "他引着他们从正门入内。屋内回荡着野兽般的粗重低吼，弥漫着腥臊气息，仿佛误入马厩。然而此处并无驼格尔的踪影，唯有一辆手推车停在后方层叠的木箱之间。木箱在昏暗的灯光下像一座座沉默的墓碑，每一座都刻着冠面客家族的徽记。" },
      { kind: "p", text: "“我的人会在午夜时分来搬运这些木箱，”凯隆说，“你们只需据守此地直至那时。若有变故，随机应变。我不希望这座仓库暴露。”" },
      { kind: "p", text: "他离去后，四人面面相觑。" },
      { kind: "p", text: "“合法的货物？”祖法赛挑眉。" },
      { kind: "p", text: "“合法的人在合法的时间看守？”乔奈重复。" },
      { kind: "p", text: "“我们被卷进什么事了？”露娜拉问。" },
      { kind: "p", text: "泰拉克斯走到一个木箱前，岩石手指在箱面上敲了敲。那声音沉闷，像敲在某种金属上。" },
      { kind: "p", text: "“不管是什么，”他说，“不会是好东西。”" },
      { kind: "hr", text: "" },
      { kind: "p", text: "仓库里有着大量的木箱，每个箱子上都烙着冠面客家族的徽记——一只戴着冠冕的飞鸟。在昏暗的油灯光线下，那些徽记仿佛无数只从暗处窥视的眼睛。" },
      { kind: "p", text: "“冠面客家族的货物，”露娜拉说，“为什么会在这里？”" },
      { kind: "p", text: "“黑貂王冠劫的。”乔奈说，“我听说过，冠面客家族最近丢了不少东西。”" },
      { kind: "p", text: "带着同样的疑问，露娜拉用军刀撬开了最近一只箱子的锁。箱盖掀开的瞬间，一道柔和的银白色光芒从缝隙里漏出来——箱子里整整齐齐码着**拉尼姆锭**，那种可以锻造魔法武器的贵重金属。每一块锭子表面光滑如镜，在微光中流转着细密的符文纹路，摸上去有一种奇特的温热，像某种沉睡的脉搏。拉尼姆锭旁边是几卷**库提鸦丝绸**，那种用于制作魔法卷轴和昂贵衣物的珍贵织物。丝绸在指尖滑过，凉得像深井里的水，又轻得像蜘蛛丝。" },
      { kind: "p", text: "“这够买下半个符文谷。”祖法赛吹了声口哨。" },
      { kind: "p", text: "他们继续开箱。有些箱子里码着同样的货物，有些空空如也，还有一些，则藏着更不友好的东西。" },
      { kind: "p", text: "露娜拉在打开第三个箱子时，箱盖突然弹出一根细针，擦过她的手腕。她迅速缩手，但针尖还是在她皮肤上留下了一道血痕。她闻到一股淡淡的甜味——是毒药。" },
      { kind: "p", text: "“小心。”她说，用布条缠住手腕，“有些箱子有机关。”" },
      { kind: "p", text: "泰拉克斯在搬动另一个箱子时，箱底突然弹出一排铁刺。他的岩石手掌挡住了大部分，但有一根刺穿了他的指缝，在石肤上留下了一个凹痕。他皱了皱岩石眉头——如果那也能叫皱眉的话——把铁刺拔出来，那铁刺在他掌心像一根脆弱的牙签。" },
      { kind: "p", text: "“我也挂彩了。”他说。" },
      { kind: "p", text: "“你们俩没事吧？”乔奈问。" },
      { kind: "p", text: "“小伤。”露娜拉说，但她的尾巴绷得笔直，“但说明这些货物很重要，重要到要下毒。黑貂王冠不会无缘无故把这些东西藏在这里。”" },
      { kind: "p", text: "祖法赛用心灵感应扫过剩余的木箱，像用指尖掠过一片带刺的灌木。大多数箱子是安全的，但西南角有三个箱子散发出一种冰冷的恶意——那是陷阱特有的情绪残留。" },
      { kind: "p", text: "“那边三个别碰。”他指了指角落。" },
      { kind: "p", text: "他们正准备继续深入时，外面传来了声响。" },
      { kind: "p", text: "不是凯隆的人。是靴子踩在碎石上的声音，是武器出鞘的声音，是压低的、带着杀意的呼吸声。" },
      { kind: "p", text: "“有人来了。”乔奈说，她反手抽出背上的仪式之矛，矛尖的螺旋符文在黑暗中亮起一线冷光，披风上的艾伊恩微光随之起伏，像一簇即将被风吹灭的火苗。" },
      { kind: "p", text: "仓库的门被一脚踹开。" },
      { kind: "p", text: "四名劫匪冲了进来——两个手持短弓的家伙，箭镞上泛着幽蓝的光，帮里管他们叫“剃刀之箭”；另两个抡着短斧的壮汉，臂上肌肉像岩石一样隆起，号称“剃刀暴徒”。他们的眼神里没有普通劫匪的贪婪，只有某种被训练出来的、对杀戮的麻木。" },
      { kind: "p", text: "“剃刀翼龙帮。”祖法赛认出了他们手腕上那道剃刀形状的刺青，“影幕会的走狗。”" },
      { kind: "p", text: "“看来他们也不想让我们暴露这座仓库。”露娜拉说，旧盾已经举在身前。" },
      { kind: "p", text: "战斗瞬间爆发。" },
      { kind: "p", text: "乔奈如一缕贴地的阴影掠过箱顶，矛尖一挑，离她最近的那名剃刀之箭弓弦应声而断。那劫匪愣了一瞬；下一瞬，露娜拉的旧盾已挟着刚毅重击拍在他脸上，将他整个人掀飞出去，撞在墙上昏死过去。" },
      { kind: "p", text: "另一名剃刀之箭见状急退，重新搭箭上弦。他的动作很快，但祖法赛更快——一枚符文投射自黑暗中激射而出，淡蓝色的光弹正中他的手腕。弓脱手，箭矢斜斜钉入天花板。那劫匪捂着手腕还想弯腰去捡，泰拉克斯之锤已裹挟着远超往常的沉重符文之力轰然砸落，将他连人带弓砸进地板，木屑飞溅。" },
      { kind: "p", text: "两名剃刀暴徒从两侧包抄过来。其中一名高举短斧劈向露娜拉，露娜拉举盾格挡，斧刃在盾面上砍出一道火星，震得她手臂发麻。另一名剃刀暴徒则扑向乔奈，短斧划出一道弧线。乔奈侧身避开，但斧刃还是擦过了她的披风，撕下一角布料。她头盔上的以太王冠虚影微微一闪，那道本可能更深的伤口被某种无形的力量偏转，只在她肩头留下一道浅痕。" },
      { kind: "p", text: "乔奈没有理会肩头的伤。她旋身欺近，矛尖狠狠刺入那名剃刀暴徒的肋下。" },
      { kind: "p", text: "泰拉克斯转过身，岩石手臂像铁锤一样挥出，正中扑向露娜拉的那名剃刀暴徒的胸口。那人倒飞出去，撞翻了两个木箱，拉尼姆锭滚了一地。" },
      { kind: "p", text: "四名劫匪很快尽数倒地，仓库里只剩下粗重的喘息，和拉尼姆锭在地上滚远的闷响。乔奈抖落矛尖的血珠，耳朵仍竖着。" },
      { kind: "p", text: "“只是前锋。”她说，“他们在试探我们有多少人。”" },
      { kind: "p", text: "“希望后面没有更多。”祖法赛说，但他的表情说明他自己也不信。" },
      { kind: "p", text: "露娜拉走到那名被她拍晕的剃刀之箭身边，用剑尖挑开他的衣领。他的锁骨下方纹着一只展翅的翼龙，翼龙的眼睛是一颗血红色的宝石。" },
      { kind: "p", text: "“影幕会不只是雇佣了他们，”她说，“他们是剃刀翼龙帮的核心成员。后面来的人会更强。”" },
      { kind: "hr", text: "" },
      { kind: "p", text: "他们继续搜查仓库。在成排的货物与腐朽的支架之间，露娜拉和祖法赛注意到仓库深处有两个笼子。笼子被一块肮脏的帆布半掩着，帆布下传来细微的颤抖声。" },
      { kind: "p", text: "一个笼子里关着一只**月浣兽**——那种长着月亮般圆脸的可爱生物，此刻正蜷缩在角落里，眼睛里满是恐惧。它的毛皮本该是银白色的，现在却沾满了污垢和干涸的血迹。另一个笼子里关着一只**绯嘶翼龙**——这只看起来更年轻，翅膀上还带着未褪尽的绒毛，像一团被强行拔下的羽毛。" },
      { kind: "p", text: "“秘密魔兽贸易。”祖法赛说，声音里压着怒火，“看来传闻是真的。这些混蛋不只是劫匪，还是奴隶贩子。”他想起北门区劳役所铁栏后那些珂蓝安劳工的眼神——和笼子里这两双眼睛，一模一样。" },
      { kind: "p", text: "祖法赛撬开笼门，把月浣兽抱了出来。那小东西立刻钻进他怀里，把脸埋进他的斗篷，发出呜呜的哭声。它的项圈上刻着一个名字和地址，字迹已经磨损，但仍能辨认。" },
      { kind: "p", text: "“我们会带你回家的。”祖法赛说，他的声音比平时温柔。他轻轻把它放进一个空的木箱里，箱底铺上了自己的斗篷一角。" },
      { kind: "p", text: "露娜拉打开另一只笼子，放出了绯嘶翼龙。那年轻的翼龙起初十分警惕，双翼张开，喉咙里滚出威胁的低吼。但露娜拉没有退缩。她伸出手，掌心向上，像在等待一只受惊的鸟。" },
      { kind: "p", text: "“我们不会伤害你。”她说，“我们只是路过。”" },
      { kind: "p", text: "绯嘶翼龙盯着她看了很久，然后，慢慢收起了翅膀。它走到露娜拉面前，用鼻子蹭了蹭她的手。至少在今夜，它不再是敌人。" },
      { kind: "p", text: "“看来你也有温柔的一面。”祖法赛说。" },
      { kind: "p", text: "“闭嘴。”露娜拉说，但她的嘴角微微上扬。她把年轻的翼龙安置在另一个木箱里，用一块干净的丝绸盖住它的背，让它保持温暖。" },
      { kind: "p", text: "他们安顿好两只被救的生物，继续向仓库深处走去。脚下的木地板越来越旧，每一步都发出不堪重负的呻吟。空气中那股腥臊味更浓了，还混着一种来自暗克苏魔法的、令人牙酸的甜腻气息。" },
      { kind: "p", text: "就在这时，第二个人影从阴影中浮现。" },
      { kind: "p", text: "他叫加利姆，是剃刀翼龙帮的高级成员，来自琥珀门。他的身形瘦削，像一把被磨得太薄的刀，双手各持一柄短刃，刃上涂着某种让伤口无法愈合的毒药。只有一个人，但他比之前的四个加起来都危险。" },
      { kind: "p", text: "“你们动了我的货物。”加利姆说，他的声音像砂纸摩擦，“还放走了我的牲口。”" },
      { kind: "p", text: "“它们不是货物。”祖法赛说。" },
      { kind: "p", text: "“那不重要。”加利姆说，“重要的是，你们现在也要死。”" },
      { kind: "p", text: "加利姆的速度很快。他的短刃在黑暗中划出两道寒光，直取露娜拉的咽喉。露娜拉举盾格挡，但加利姆的刀刃突然变向，像一条毒蛇一样绕过盾面，划向她的手腕。她感到一阵刺痛，毒药顺着伤口渗入，她的手臂开始发麻。" },
      { kind: "p", text: "但就在毒素即将扩散的瞬间，她狠狠咬破舌尖，剧痛劈开了麻木。布林德利昂家的骑士不会倒在阴沟里的毒药上——她凭着这口气，硬生生把最致命的那缕毒意压回了伤口边缘。" },
      { kind: "p", text: "“有毒！”她喊道，但她的声音比预想中更稳。" },
      { kind: "p", text: "乔奈从侧面扑来，仪式之矛直刺加利姆的后心。加利姆转身，用短刃格挡，但乔奈的真实打击已经发动。矛尖穿透了他的防御，在他肩膀上留下一道深深的伤口。黑血涌出，散发出一股腐臭。" },
      { kind: "p", text: "加利姆后退，他的眼睛在黑暗中闪烁着疯狂的光。他舔了舔伤口上的血，露出一个扭曲的笑容。" },
      { kind: "p", text: "“你们有点意思。”他说，声音里多了一层血腥的黏腻。" },
      { kind: "p", text: "他再次扑来，这次的目标是祖法赛。一记心灵冲击轰然推出，但加利姆似乎对心灵攻击有某种抵抗力，只是晃了晃，继续冲来。短刃直取胸口，祖法赛踉跄后退，撞翻了一只木箱，拉尼姆锭滚落一地。" },
      { kind: "p", text: "泰拉克斯的巨石打击自侧面砸来，逼得加利姆闪身躲避。泰拉克斯之锤带着符文之力砸在地板上，木板碎裂，差点让他跌进裂缝。露娜拉趁势抢上，旧盾狠狠撞在他的侧腹。他闷哼一声，立刻反击，短刃在露娜拉的锁甲上划出一道火花。" },
      { kind: "p", text: "“乔奈！”露娜拉喊道，“他的腰！”" },
      { kind: "p", text: "乔奈会意。她矮身从加利姆的攻势下穿过，矛刃划向他的腰侧。加利姆想要回防，但祖法赛的符文冲击已经轰在他的膝盖上，让他的动作慢了半拍。矛尖入肉，加利姆发出一声痛吼。" },
      { kind: "p", text: "泰拉克斯抓住机会，岩石手臂锁住加利姆的脖子，将他按倒在地。加利姆挣扎着，短刃在泰拉克斯的石肤上划出几道白痕，但无法造成实质伤害。" },
      { kind: "p", text: "露娜拉退后半步，以快速治疗封住伤口，同时握紧掌心的艾伊恩的恩赐。银质徽章在她手中变得滚烫，一道温暖的蓝光顺着手臂游走，将残留的毒素彻底焚净。力量重新涌回她的指尖。" },
      { kind: "p", text: "“结束了。”泰拉克斯说，手臂收紧。" },
      { kind: "p", text: "加利姆的眼球突出，喉咙里发出咯咯的声音，最终昏死过去。泰拉克斯把他扔在地上，像扔一袋破旧的谷物。" },
      { kind: "p", text: "“第二波。”祖法赛喘着气，低头看着加利姆，“希望这家伙的值钱程度配得上他的麻烦。”" },
      { kind: "p", text: "“他不会是最后一个。”泰拉克斯说，他的岩石面孔上没有任何表情，但他的身体已经转向了仓库更深处。" },
      { kind: "hr", text: "" },
      { kind: "p", text: "他们继续前进，在仓库最深处发现了一辆冠面客马车。马车周围并没有拉车的驼格尔，它孤零零地停在那里，像一具被遗弃的棺材。车辕上还残留着干涸的血迹，像是有人曾在这里粗暴地卸下了驾车的驼格尔。" },
      { kind: "p", text: "“我记得，”露娜拉说，“冠面客家族在遭遇黑貂王冠匪帮袭击时，丢失了一辆类似的马车。”" },
      { kind: "p", text: "乔奈将引导能量凝成一线，点在泰拉克斯后背。艾伊恩之力如温热的溪流注入他的岩石躯体，让他的每一块肌肉——如果岩石也能称为肌肉——都充盈着额外的韧性。泰拉克斯低吼一声，笨重的马车在他掌下发出刺耳的摩擦声，被一寸寸推开，在木地板上犁出两道深深的痕迹。" },
      { kind: "p", text: "马车后面，藏着两样东西。" },
      { kind: "p", text: "一个加装了金属包角和厚重大锁的**保险箱**。乔奈用短剑撬开锁，里面装满了金银珠宝、地契，以及几封盖有磐怒客家族印章的信件——正是磐怒客失窃的那批财物。" },
      { kind: "p", text: "“看来黑貂王冠不仅劫冠面客，也劫磐怒客。”乔奈说。" },
      { kind: "p", text: "另一个是一个冒着烟、散发出邪恶暗克苏能量的**禁忌木箱**。祖法赛用布包着手打开它，里面有三样东西：一颗巨大而尚有余温的**恶魔之眼**，那眼睛还在微微转动，像是在寻找什么；一块**血水晶**，在黑暗中散发着不祥的红光；以及一个散发出令人作呕邪气的**盒子**，那盒子表面刻满了扭曲的符文，像某种活物的皮肤。" },
      { kind: "p", text: "“这些东西……”祖法赛说，他的声音在发抖，“比贝科拉之杖的碎片还危险。”" },
      { kind: "p", text: "“我们得带走它们。”露娜拉说。" },
      { kind: "p", text: "“带到哪里去？”乔奈问。" },
      { kind: "p", text: "“不知道。”露娜拉说，“但不能留在这里。”" },
      { kind: "p", text: "他们刚把恶魔之眼与血水晶收好，仓库深处便传来铁链拖曳的声响，以及某种大型生物粗重的呼吸。那呼吸声带着一股腐肉的腥臭，越来越近。" },
      { kind: "p", text: "第三波来了。这次是两个高级成员：班杰斯，一个身材魁梧的暗瞳格里人，以及一只**绯嘶翼龙**——那种生活在倒影山脉的空中掠食性蜥蜴，此刻正被铁链拴着，眼睛里闪烁着饥饿的红光。" },
      { kind: "p", text: "“看来他们连宠物都带来了。”乔奈说。" },
      { kind: "p", text: "班杰斯的武器是一柄巨锤，锤头比露娜拉的旧盾还宽，每一击都带着千钧之力。绯嘶翼龙则像一道红色的闪电，在仓库里横冲直撞，翅膀刮过木箱，将箱盖撕成碎片。" },
      { kind: "p", text: "战斗比前两波更加激烈。" },
      { kind: "p", text: "班杰斯的巨锤砸在露娜拉的旧盾上，盾面发出不堪重负的呻吟。巨力透过盾牌灌进手臂，她的虎口当场震裂，鲜血顺着盾沿淌下。她咬紧牙关稳住身形，觑准班杰斯收锤的空当，一记英勇打击奋力劈出，军刀在他的护臂上撕开一道伤口。" },
      { kind: "p", text: "绯嘶翼龙则扑向乔奈，利爪在她的披风上撕出一道口子。乔奈翻滚避开，矛尖划向翼龙的腹甲，但那鳞片硬得像铁，只留下一道白痕。" },
      { kind: "p", text: "祖法赛用符文冲击轰击绯嘶翼龙，光弹在那怪物的鳞片上溅起几点火花。它愤怒地转头，张开嘴，一道暗红色的酸液喷向祖法赛。祖法赛向侧面扑倒，酸液落在他身后的木箱上，木箱立刻冒出青烟，发出刺鼻的焦臭味。" },
      { kind: "p", text: "泰拉克斯举起泰拉克斯之锤，锤头符文亮如星火，狠狠砸向班杰斯。班杰斯横锤格挡，两股巨力相撞，爆出一声震耳欲聋的巨响。泰拉克斯的臂骨里泛起细密的震颤，但他没有退。第二锤紧随而至，正砸在班杰斯的膝盖上。班杰斯一个踉跄，巨锤脱手。" },
      { kind: "p", text: "露娜拉抓住机会，军刀在班杰斯的腿上留下一道深深的伤口。班杰斯跪倒在地，泰拉克斯的巨力碾压跟上，把他压倒在地。班杰斯还想挣扎，但泰拉克斯用膝盖压住他的后背，岩石手臂扼住他的后颈，直到他昏死过去。" },
      { kind: "p", text: "绯嘶翼龙见主人倒下，发出一声愤怒的尖叫，转而扑向祖法赛。他连番催动心灵之力，识海已近枯竭，那怪物的利爪几乎要碰到他的咽喉。千钧一发之际，他腰间的贝科拉的海螺发出一声低沉的嗡鸣，深海纹路亮起湛蓝的微光。下一瞬，祖法赛的身影像被潮水卷走般向后滑出数丈，堪堪避开那致命的一扑。" },
      { kind: "p", text: "但他没有逃离战场。海螺的力量只是把他送到了仓库的另一侧，与绯嘶翼龙拉开了距离。那怪物转过头，红眼睛锁定了露娜拉——她原本蹲在被救的年轻翼龙身旁，此刻缓缓站起身，挡在了它与年轻翼龙之间。" },
      { kind: "p", text: "她没有后退，也没有用盾。她伸出双手，直视绯嘶翼龙的眼睛。她的意志像一堵墙，像一座山，像星轮山布林德利昂家族传承的、面对任何野兽都不退缩的勇气。" },
      { kind: "p", text: "“停下。”她说，声音低沉而坚定。" },
      { kind: "p", text: "绯嘶翼龙停下了。它的红眼睛盯着露娜拉，翅膀还在扑腾，但身体已经不再前进。" },
      { kind: "p", text: "“我们不是你的敌人。”露娜拉说，“你的主人已经倒下了。你可以走了。”" },
      { kind: "p", text: "绯嘶翼龙歪了歪头，喉咙里发出一阵低低的呜咽。然后，它转身，撞破仓库的窗户，飞向夜空。" },
      { kind: "p", text: "“第三波。”露娜拉说，她的手臂在颤抖。" },
      { kind: "p", text: "“结束了？”祖法赛问，他的声音还有些发虚。" },
      { kind: "p", text: "“暂时。”乔奈说。" },
      { kind: "hr", text: "" },
      { kind: "p", text: "正当城中的钟声敲响子夜，凯隆带着他的人手归来。" },
      { kind: "p", text: "他们发现袭击者的尸体横陈满地，意识到啊对对队遭遇的麻烦远比预想中更为棘手。当其他人将尸体与木箱搬上马车，凯隆走向他们。他的月光银耳环在火把下闪烁，脸上的表情既像是欣慰，又像是某种早有预料的平静。" },
      { kind: "p", text: "“感谢星辰保佑，你们没事！”他说，“早知影幕会来袭，我就不该留下你们孤军奋战。但看来，你们守住了阵地。”" },
      { kind: "p", text: "“你早就知道会有袭击。”露娜拉说，她的声音很冷。" },
      { kind: "p", text: "“我怀疑过。”凯隆承认，“但我不确定。影幕会最近一直在追查这批货，我只是没想到他们敢在今晚动手。”" },
      { kind: "p", text: "“所以你让我们当诱饵？”祖法赛问。" },
      { kind: "p", text: "“我让你们当守卫。”凯隆说，他的语气里没有歉意，只有一种近乎冷酷的诚实，“诱饵和守卫的区别在于，诱饵知道自己会死，守卫知道自己会活。你们活着，我也活着，这买卖就成了。”" },
      { kind: "p", text: "“你知不知道里面有什么？”露娜拉指着禁忌木箱的方向，“恶魔之眼。血水晶。还有那个打不开的邪气盒子。这些东西不是普通的赃物。”" },
      { kind: "p", text: "凯隆的笑容第一次僵住了。他看向那个方向，眼神变得复杂。" },
      { kind: "p", text: "“我们知道冠面客和磐怒客丢了什么。”他说，“但我们不知道具体是什么。影幕会在找这些东西，我们只是想抢先一步。”" },
      { kind: "p", text: "“为什么？”乔奈问。" },
      { kind: "p", text: "“因为不能让影幕会拿到。”凯隆说，“他们是磐怒客和紫晶教团的狗。如果这些黑暗玩意儿落到他们手里，北门区会变成人间地狱。”" },
      { kind: "p", text: "“所以你劫富济贫？”乔奈问。" },
      { kind: "p", text: "“我们劫富。”凯隆说，“济贫是顺便的。但今晚，我们确实欠你们一条命。这些——”他指了指被搬走的木箱，“——我会处理。你们拿不到的，也不会想知道下落。”" },
      { kind: "p", text: "在亡命徒们搬走四人守了一整夜的赃物时，凯隆支付了劳务费。那是一袋沉甸甸的月光银，比承诺的还要多。" },
      { kind: "p", text: "“若你们不介意与我等为伍，日后或许还有差事相托。”他说，“我们在飞龙酒馆见。天佑众生。”" },
      { kind: "p", text: "他们离开仓库，穿过北门区的贫民窟。夜色更深了，但空气中的恶意似乎淡了一些。祖法赛怀里抱着月浣兽，那小东西已经睡着了，发出细微的呼噜声。" },
      { kind: "p", text: "“我们刚刚帮黑貂王冠守了一夜的赃物。”祖法赛说。" },
      { kind: "p", text: "“我们刚刚杀了一波剃刀翼龙帮的劫匪。”乔奈说。" },
      { kind: "p", text: "“我们刚刚发现了一箱恶魔之眼和血水晶。”露娜拉说。" },
      { kind: "p", text: "“我们刚刚卷入了一场我们完全不了解的战争。”泰拉克斯说。" },
      { kind: "p", text: "四人都沉默了。他们心中思忖着，自己究竟又卷入了何等新的祸端。" },
      { kind: "hr", text: "" },
      { kind: "p", text: "第二天清晨，他们根据月浣兽项圈上刻着的名字和住址找到了它的主人。那是一位住在气派宅邸里的老太太，宅邸位于崇高河岸，与昨夜的贫民窟只隔一条河，却像是两个世界。她的头发像雪一样白，眼睛像两颗黯淡的蓝宝石。" },
      { kind: "p", text: "“我的月亮。”老太太看到月浣兽时，眼泪立刻流了下来。她紧紧抱着那只小生物，像抱着失而复得的孩子。" },
      { kind: "p", text: "作为谢礼，她将亡夫留下的遗物赠给了他们——一枚**湮灭魔方**。" },
      { kind: "p", text: "“这是我丈夫生前最珍爱的东西。”她说，“他常说，这是一件能在绝境中救命的武器。不到万不得已，千万不要使用它。”" },
      { kind: "p", text: "那魔方只有拳头大小，表面刻满了细密的符文，在晨光下泛着淡淡的银辉。祖法赛接过它时，掌心里能感到某种不稳定的能量在缓缓搏动，像一场被强行压缩的风暴。" },
      { kind: "p", text: "“这是炸药？”祖法赛问。" },
      { kind: "p", text: "“比炸药更糟。”老太太说，“这是湮灭。它能把周围的一切都抹掉，包括使用它的人。”" },
      { kind: "p", text: "他们小心地收好湮灭魔方。那是一件一次性的、毁灭性的武器，不到生死关头，绝不能动用。" },
      { kind: "p", text: "他们走出老太太的宅邸，在附近的客栈里整理这一夜的收获。那枚从仓库禁忌木箱里取出的**邪气盒子**摆在桌上，扭曲的符文在灯影里仿佛仍在缓慢蠕动。" },
      { kind: "p", text: "他们尝试了很多办法也不能打开它。露娜拉用军刀撬，乔奈用短剑刺，祖法赛用心灵感应探，泰拉克斯用岩石手掌捏。但盒子纹丝不动，像一块实心石头。更糟的是，每当他们试图强行打开它，那盒子就会散发出一股令人作呕的邪气，让他们的手不由自主地颤抖。" },
      { kind: "p", text: "“也许需要特定的钥匙。”乔奈说。" },
      { kind: "p", text: "“也许需要特定的时间。”祖法赛说。" },
      { kind: "p", text: "“也许需要特定的人。”露娜拉说。" },
      { kind: "p", text: "他们最终决定暂时将它保留。也许有一天，他们会找到打开它的方法；但现在，只能把它和那枚湮灭魔方一起，小心地收进背包的最深处。" },
      { kind: "p", text: "他们来到城市的边缘。露娜拉从木箱里抱出那只年轻的绯嘶翼龙，托在自己的手臂上。它稳稳站着，翅膀微微张开，像是在适应自由的风。" },
      { kind: "p", text: "“去吧。”露娜拉说，“别再被抓住了。”" },
      { kind: "p", text: "绯嘶翼龙发出一声欢快的尖叫，冲向云霄。它的身影在夕阳中越来越小，像一颗红色的流星。就在即将消失在视野尽头时，它回过头来，仿佛在向四人致谢，又像是在记下他们的样貌，以备来日重逢。" },
      { kind: "p", text: "露娜拉望着它消失的方向，很久都没有说话。" },
      { kind: "p", text: "“你在想什么？”乔奈问。" },
      { kind: "p", text: "“我在想，”露娜拉说，“有些东西，一旦自由了，就再也回不去了。”" },
      { kind: "p", text: "她摸了摸自己的口袋，那里装着布林德利昂家族的徽章。她想起了母亲，想起了星轮山，想起了那面她一直在寻找的飞龙之鳞盾牌。" },
      { kind: "p", text: "“我们也会自由的。”乔奈说。" },
      { kind: "p", text: "“也许吧。”露娜拉说。" },
      { kind: "p", text: "他们转身，向贪食飞龙酒馆的方向走去。夕阳在他们身后沉落，把天空染成一片血红。城市的灯火在前方次第亮起，像无数双注视的眼睛。" },
      { kind: "hr", text: "" },
    ],
    poem: ["暮光初照北门尘，", "仓门深锁掩奇珍。", "凶徒三犯惊更鼓，", "两兽开笼感意新。", "马车暗藏磐怒宝，", "木箱邪聚恶魔身。", "凯隆一语天机泄，", "谁是叛徒谁是臣？"],
    battleReport: "（死亡物品清单：无。啊对对队，全员存活。额外收获：月浣兽×1（已归还主人）、绯嘶翼龙×1（已释放）、湮灭魔方×1（一次性爆炸武器）、劳务费×1袋。无法打开：邪气盒子×1（仓库禁忌木箱中获得）。消耗：无。下一站：符文谷深处 / 飞龙酒馆。）",
  },
  "ch5": {
    title: "第五章：先民宝库",
    endMark: "【第五章 完】",
    blocks: [
      { kind: "p", text: "走向裂天者之塔的路上，谁都没有说话。" },
      { kind: "p", text: "那座塔就矗立在崇高河岸的尽头，塔身缠绕着暗色的符文，塔顶没入低垂的云层。它发出的尖啸极其骇人，像无数把钝刀同时刮擦着玻璃，又像某种远古巨兽在云层中哀嚎。符文谷的居民早已习惯了这声音，但每当夜深人静，仍有人会从噩梦中惊醒，梦见自己被那尖啸撕成碎片。" },
      { kind: "p", text: "“圣托尔就是在这种地方守护了十几年。”祖法赛说，他的声音压得很低，仿佛怕被塔听到。" },
      { kind: "p", text: "“她一个人。”乔奈说。" },
      { kind: "p", text: "“现在轮到我们了。”露娜拉说。" },
      { kind: "p", text: "泰拉克斯没有说话。他的岩石面孔上没有表情，但他的目光一直停留在塔身上。他能感觉到，那座塔在呼唤他背脊上那片光滑的岩石，像呼唤一个失散多年的孩子。" },
      { kind: "p", text: "随着他们靠近，圣托尔授予的那把先民钥匙开始在露娜拉的掌心发烫。那热度不是灼烧，而是一种奇异的共鸣，像钥匙在回应某种只有它能听见的低语。原本光滑的石壁上浮现出一扇门，随后是锁孔。" },
      { kind: "p", text: "露娜拉把钥匙插入锁孔。钥匙与锁孔完美契合，发出一声清脆的咔哒声。" },
      { kind: "p", text: "大门开启。" },
      { kind: "p", text: "那撕裂天空的尖啸声平息下来，化作一阵抚慰人心的鸣响，像风暴过后的第一缕风，像母亲哼唱的摇篮曲。四人惊讶地对视一眼，然后小心翼翼地踏入塔内。" },
      { kind: "p", text: "大门在他们身后关闭，发出沉闷的轰响。眼前是一段顺时针缓缓盘旋的楼梯，石阶上刻满了与先民宝库中相似的符文。楼梯在绕行整整一圈后，将他们带向一间圆形的宝库。" },
      { kind: "p", text: "他们曾在一尊巨大的石首前与圣托尔失散。而此处竟有三尊石首，皆沉默无言，神色威严可怖。左侧石首的面容带着一种古老的悲悯，眉骨深陷，嘴唇紧闭，风化的石纹从眼角蜿蜒而下，像一道干涸了千年的泪痕，又像在强忍某种沉重的秘密；右侧石首则显得更为冷峻，下颌线条锋利如刀，嘴角微微下撇，鼻梁上横着一道旧裂，仿佛对凡人抱有永恒的怀疑；中央石首最为庞大，双肩几乎抵住密室的拱顶，额头中央刻着一只闭合的眼睛——那眼睛并非雕刻，而是一块微微凸起的暗色水晶，像一颗尚未睁开的第三只眼。" },
      { kind: "p", text: "石首的眼睛是空洞的，但那种空洞比任何目光都更有压迫感，像三个正在审判他们的神祇。" },
      { kind: "p", text: "整间密室宛如一座魔法阵，正静待某种古老仪式的开启。地面由黑白两色的石板铺成，组成复杂的几何图案。中央那三个半球形容器显然是其中的一部分——它们由某种半透明的晶体打造，在黑暗中发出微弱的蓝光。容器之间悬浮着一个金属圆盘，直径足有两人多高，表面刻满了明灭不定的符文，像一枚被冻结的月亮。" },
      { kind: "p", text: "可若这就是信标，他们却完全不知道该如何点亮它。" },
      { kind: "p", text: "“现在怎么办？”祖法赛问。" },
      { kind: "p", text: "“找线索。”露娜拉说。" },
      { kind: "hr", text: "" },
      { kind: "p", text: "他们还没来得及散开，房间中央的金属圆盘便有了异动。" },
      { kind: "p", text: "那些符文被不断变换的诡异黑影所遮蔽，黑影在圆盘上方汇聚凝结，像一滴墨水滴入清水，像一团烟雾凝成实体。然后，它化作了人形。" },
      { kind: "p", text: "一个带着兜帽的身影悬浮在圆盘上方，兜帽的阴影里燃着两点幽绿的光芒。而阴影更深处，隐约浮出一张模糊的面孔——每个注视它的人，都在那张脸上看见了自己的轮廓。它的身体半透明，像被水冲淡的墨，像被风吹散的烟。它没有脚，下半身与黑影融为一体，随着圆盘的转动而微微摇曳。" },
      { kind: "p", text: "**还魂者**。" },
      { kind: "p", text: "“什么东西？”乔奈反手将仪式之矛从背后抽出，矛尖横在身前。" },
      { kind: "p", text: "“死人的影子。”祖法赛说，他的心灵感应像被针扎了一样刺痛，“不对，比那更糟。它不只是影子，它是某种……被囚在这里的意志。”" },
      { kind: "p", text: "还魂者没有说话。它飘向他们，兜帽下的绿光锁定了最近的泰拉克斯。泰拉克斯没有退缩，他的狂怒猛砸直接轰向那个幽灵般的身影。" },
      { kind: "p", text: "岩石手掌穿过了还魂者的身体，像穿过一团雾。但还魂者的回击也同时到来——一股无形的力量顺着他的手臂反震回来，泰拉克斯感到自己挥出的每一分力道，都原封不动地砸回了自己身上，碎石屑从他的肩膀上崩落。那不是简单的反弹，而是某种古老的诅咒：你加诸它的，它必如数奉还。" },
      { kind: "p", text: "“它在记账！”祖法赛喊道，声音发紧，“挨多少，还多少——这是复仇的诅咒，谁动手，谁就得吞下同样的伤！”" },
      { kind: "p", text: "“那我们怎么打？”乔奈问。" },
      { kind: "p", text: "“用意志。”露娜拉说，“或者找到别的方法。”" },
      { kind: "p", text: "还魂者再次扑来。这次它的目标是乔奈。乔奈的真实打击划过它的身体，矛尖像穿过空气一样没有阻力。但还魂者的反击也精准地落在乔奈身上，她的披风被一股无形的力量撕裂，肩上出现了一道血痕。她咬紧牙关。以太王冠在她头盔上泛起一层几乎不可见的微光，硬生生将那道本可深可见骨的伤口卸去了几分——幻象赠予的王冠，在第一次实战里便证明了它并非虚影。" },
      { kind: "p", text: "“这他妈的怎么打？！”祖法赛骂道。" },
      { kind: "p", text: "“别硬碰！”露娜拉说，“找它的弱点！”" },
      { kind: "p", text: "他们且战且退，还魂者紧追不舍。每当他们以为甩掉了它，它就会从金属圆盘的方向重新凝聚，像一滴永远滴不完的水。泰拉克斯试图用身体挡住它的路径，但还魂者直接穿过他的岩石躯体，让他的背脊感到一阵刺骨的寒意。" },
      { kind: "p", text: "“它……又聚回来了。”泰拉克斯说，岩石面孔上第一次出现了明显的焦虑。" },
      { kind: "p", text: "“它们不会真正死去。”祖法赛说，他的心灵感应捕捉到了还魂者消散与重聚之间的节奏，“每次被击溃后，过一小会儿就会重新凝聚。我们必须在它们重聚之前做点什么。”" },
      { kind: "p", text: "“做什么？”乔奈问。" },
      { kind: "p", text: "“找威力宝珠。”露娜拉说，“圣托尔说过，点亮信标需要威力宝珠。一定有办法让这鬼东西停下来。”" },
      { kind: "hr", text: "" },
      { kind: "p", text: "祖法赛在左侧墙壁上发现了用魔法写成的字迹。那些字迹在黑暗中发出微弱的蓝光，像被冻住的火焰，笔画古老得不像任何现存种族的文字。他挥舞着火炬，勉强辨认：" },
      { kind: "p", text: "**“二位石首之语恒真，一位石首之语永伪，孰真孰伪，吾不能辨。”**" },
      { kind: "p", text: "“谜语。”祖法赛说，“又是谜语。”" },
      { kind: "p", text: "“三尊石首，两真一假。”乔奈说，“我们需要分辨哪尊说真话。”" },
      { kind: "p", text: "“或者，”露娜拉说，“我们不需要分辨。我们只需要问对问题。”" },
      { kind: "p", text: "祖法赛走向左侧的石首。那石首的面容威严而古老，眼睛是两个深不见底的黑洞。当他靠近时，石首的眉骨微微颤动，像某种沉睡的东西正在醒来。他深吸一口气，将手放在石首的额头上，用意志与之沟通。" },
      { kind: "p", text: "刹那间，一股沉重的压力压在他的意识上。那不是攻击，而是一种审视，像有人把他的灵魂放在天平上称量。祖法赛看到了凡提·玛夏克的水下街道，看到了那些被造物主压迫的珂蓝安人麻木的眼睛，也看到了自己怀中贝科拉之杖碎片散发出的幽光。石首在问他：你为何而来？为权力，还是为救赎？" },
      { kind: "p", text: "祖法赛咬紧牙关，将所有的算计与恐惧压下，只剩下一个最纯粹的念头：为了阻止暗克苏，为了保护那些无法保护自己的人。" },
      { kind: "p", text: "压力消散了。" },
      { kind: "p", text: "石首没有说话，但一个声音直接在他脑海中响起，像两块石头在摩擦：" },
      { kind: "p", text: "**“不要把威力宝珠放到左侧的容器内。”**" },
      { kind: "p", text: "祖法赛睁开眼睛，后退一步，额头上渗出了蓝色的汗珠。" },
      { kind: "p", text: "“它说，不要放左边。”" },
      { kind: "p", text: "露娜拉走向右侧的石首。她也把手放在石首的额头上，闭上眼睛。她的意志像一把出鞘的剑，坚定而锋利。但右侧石首的考验更为凌厉——它直接刺入她最柔软的伤口。她看到了星轮山的大火，看到了母亲倒在血泊中的背影，看到了自己被诬陷为凶手时姐姐们冷漠的脸。石首的声音像冰锥一样刺进她的脑海：你凭什么守护他人？你自己都是逃犯。" },
      { kind: "p", text: "露娜拉的尾巴绷得笔直，指甲抠进掌心。她在心中回答：正因为我是逃犯，我才更清楚无辜者被碾碎是什么滋味。正因为失去过一切，我才不会让别人也失去一切。" },
      { kind: "p", text: "石首的冷峻面容似乎柔和了一瞬。" },
      { kind: "p", text: "它的声音在她脑海中响起：" },
      { kind: "p", text: "**“请把威力宝珠放到左侧的容器内。”**" },
      { kind: "p", text: "露娜拉睁开眼睛，皱起眉头。" },
      { kind: "p", text: "“它说，放左边。”" },
      { kind: "p", text: "“矛盾了。”乔奈说，“一个说放左边，一个说不放左边。”" },
      { kind: "p", text: "“还有第三尊。”泰拉克斯说。" },
      { kind: "p", text: "露娜拉点头。她向房间正中的石首走去，但就在她走到一半时，脚下的地板突然发生了大面积的龟裂。裂缝像蜘蛛网一样蔓延，黑色的深渊在裂缝下张开嘴，发出某种低沉的呜咽，像大地本身在警告她不要靠近。" },
      { kind: "p", text: "露娜拉眼疾手快，纵身一跃，跳过了裂隙。她的尾巴在身后保持平衡，落地时膝盖微屈，缓冲了冲击。" },
      { kind: "p", text: "“泰拉克斯，”她回头喊道，“别过来！这地板撑不住你！”" },
      { kind: "p", text: "泰拉克斯低头看了看自己的岩石脚掌，又看了看那道裂缝，明智地停下了脚步。" },
      { kind: "p", text: "“如果是你，”祖法赛说，“肯定要直接跌落到底层了。”" },
      { kind: "p", text: "“谢谢提醒。”泰拉克斯说。" },
      { kind: "p", text: "露娜拉继续前进，来到中央石首面前。这尊石首最为沉默，但当她的手触碰到它额头中央的闭合之眼时，那只眼睛突然睁开了——不是实体上的睁开，而是某种意识上的觉醒。露娜拉感到自己被拉入了一片星海，无数先民的记忆像流星一样从她身边划过。她看到了先民建造裂天者的场景，看到了他们如何将艾伊恩宝珠放入中央容器，又如何用三尊石首守护这个秘密。" },
      { kind: "p", text: "中央石首没有问她问题。它只是让她看，让她感受，让她自己选择是否愿意承担这份使命。" },
      { kind: "p", text: "露娜拉在星海中站稳了脚跟。" },
      { kind: "p", text: "石首的声音在她脑海中响起，比其他两尊更为悠远，像从时间的尽头传来：" },
      { kind: "p", text: "**“请把威力宝珠放到中央的容器内。”**" },
      { kind: "p", text: "就在此时，又一团黑影在露娜拉身后凝聚成形。它从金属圆盘的方向飘来，兜帽下的绿光锁定了她的后背。" },
      { kind: "p", text: "“露娜拉！”乔奈喊道。" },
      { kind: "p", text: "露娜拉转身，旧盾已经举在身前。还魂者的冲击撞在盾面上，她感到一股寒意顺着盾面传到她的手臂，像被冰锥刺入骨髓。" },
      { kind: "p", text: "“中央石首说，放中央。”她喊道。" },
      { kind: "p", text: "“左侧说不放左，右侧说放左，中央说放中央。”祖法赛的指尖在空气中飞快地划动，像在核对一笔账目，“听着——左边这两句针锋相对：一句说不许放左，一句说必须放左。它们不可能同真，也不可能同假，必定一真一假。”" },
      { kind: "p", text: "“而说假话的只有一尊。”露娜拉接道，眼睛亮了起来。" },
      { kind: "p", text: "“对。那尊撒谎的石首，就藏在左边这两尊之间。”祖法赛指向中央，“所以中央石首说的，必定是真话——我们根本不需要分清左边谁真谁假。”" },
      { kind: "p", text: "“所以是中央。”乔奈说，“威力宝珠，放中央容器。”" },
      { kind: "hr", text: "" },
      { kind: "p", text: "乔奈没有参与石首的考验。她探索了金属圆盘周边，在阴影中发现了一具穿着华服的骸骨。那骸骨已经不知多少年了，衣服已经腐朽，但依然能看出曾经的华贵。骸骨的手指紧紧扣着一件折叠整齐的长袍——**守护者长袍**，以及一颗散发着柔和蓝光的宝珠——**艾伊恩宝珠**。" },
      { kind: "p", text: "“找到了。”乔奈说，她的声音有些颤抖。那具骸骨可能是一位古代的裂隙守护者，像圣托尔一样，为了守护某个秘密而死在这里。她仿佛能看到那位守护者临终前的姿态：不是倒在敌人手中，而是耗尽了自己的一切，只为让宝珠不被黑暗玷污。" },
      { kind: "p", text: "就在她拿起宝珠的瞬间，第三个还魂者在她身后的阴影里凝聚成形。" },
      { kind: "p", text: "“乔奈！”祖法赛喊道。" },
      { kind: "p", text: "乔奈没有回头。她抱着长袍和宝珠，向团队的方向跑去。还魂者在她身后紧追不舍，绿光像两把匕首刺向她的后背。乔奈能感觉到那股寒意越来越近，但她没有停下。盲眼长者曾说过，当你背负使命奔跑时，背后的风声只是催促你更快。" },
      { kind: "p", text: "“接着！”她把艾伊恩宝珠抛给露娜拉。" },
      { kind: "p", text: "露娜拉接住宝珠，那宝珠在她掌心发出温暖的蓝光，像一颗小小的太阳。与此同时，她腰间的银质徽章——艾伊恩的恩赐——也微微发亮，仿佛在回应同源的力量。" },
      { kind: "p", text: "“现在我们有宝珠了。”她说，“但还有三个还魂者在追我们。”" },
      { kind: "p", text: "“四个。”泰拉克斯说，他的目光投向金属圆盘。第四个还魂者正在凝聚。" },
      { kind: "p", text: "“我们得快点。”露娜拉说。" },
      { kind: "hr", text: "" },
      { kind: "p", text: "露娜拉在右侧发现了一处角落里有个符文的微光。那微光很弱，像一颗即将熄灭的星星，嵌在一块已经松动的石板后面。她俯身辨认了许久，指尖拂过那些几乎磨平的刻痕，才读懂那出自很久以前一位裂隙守护者之手的咒语——足以在同一瞬间重创所有还魂者，但咒力只够倾泻一次，用过便永远沉寂。" },
      { kind: "p", text: "“只能使用一次的咒语。”祖法赛说，“必须用在最关键的时刻。”" },
      { kind: "p", text: "“什么时候用？”乔奈问。" },
      { kind: "p", text: "“等它们凑到一处的时候。”露娜拉说。" },
      { kind: "hr", text: "" },
      { kind: "p", text: "团队制定了计划。" },
      { kind: "p", text: "“泰拉克斯牵制住三名还魂者。”露娜拉说，“你的岩石身躯能扛下那诅咒的反噬。”" },
      { kind: "p", text: "“明白。”泰拉克斯说，握紧了泰拉克斯之锤。锤头上的符文在黑暗中微微发亮，像沉睡的火焰被唤醒。" },
      { kind: "p", text: "“露娜拉提供保护和治疗。”祖法赛说。" },
      { kind: "p", text: "“明白。”露娜拉说。" },
      { kind: "p", text: "“乔奈在身后策应，找机会重创它们。”露娜拉说。" },
      { kind: "p", text: "“明白。”乔奈说。" },
      { kind: "p", text: "“祖法赛帮助大家稳住伤势、恢复气力，”露娜拉说，“以及在还魂者最虚弱、形体最稀薄时用意志力发动古老的咒语。”" },
      { kind: "p", text: "“明白。”祖法赛说。" },
      { kind: "p", text: "战斗开始。" },
      { kind: "p", text: "泰拉克斯站在房间中央，像一座不可撼动的山。三名还魂者围着他，绿光闪烁，但他的岩石身躯像一堵墙，像一座堡垒。每当还魂者的攻击落在他身上，他都会遭受同样的诅咒回击，碎石从他的肩膀、手臂、胸口不断崩落，但他没有退缩。他的狂怒猛砸、巨力碾压、巨石打击像雨点一样落下，泰拉克斯之锤每一记都比岩石本身的分量更沉，锤头符文随挥击明灭，像岩浆在岩缝里呼吸。这样的重击无法真正杀死还魂者，却足以把它们牢牢钉在他身前。" },
      { kind: "p", text: "“来啊！”泰拉克斯低吼，“你们这些死不透的东西！”" },
      { kind: "p", text: "露娜拉站在泰拉克斯身后，旧盾护在身前，快速治疗像一道道温暖的光，落在泰拉克斯的岩石躯体上。她的英勇打击在关键时刻挥出，将试图绕过泰拉克斯的还魂者逼退。她能感觉到艾伊恩的恩赐在掌心跳动，像一颗随时可以被捏碎的心脏，但她忍住了——现在还不是最危急的时刻。" },
      { kind: "p", text: "乔奈在更后方，仪式之矛像一道银色的闪电，每一次出手都精准地落在还魂者的薄弱处。真实打击虽会引来诅咒的回击，米恩的守护者却总在最险的一刻替她扛住冲击，引导能量则源源不断地将温热的力量渡给同伴。以太王冠在她头顶闪烁，当还魂者的魔法反击袭来时，那顶虚幻的王冠会为她多抵挡一分冲击。" },
      { kind: "p", text: "祖法赛在战场边缘游走，他的符文投射和符文冲击不断削弱还魂者的力量，他的赋能则强化着队友的装备。他的心灵感应像一张网，捕捉着战场上的每一个细节。他注意到，每当还魂者受到重创，它们就会向金属圆盘方向退却，拖延时间，等待消散的身躯重新凝聚。" },
      { kind: "p", text: "当一名还魂者突然绕过泰拉克斯，直扑向正在引导能量的乔奈时，祖法赛没有时间多想。他抓起腰间的贝科拉的海螺，用力一吹。没有声音传出，但一圈深海般的蓝光从螺口扩散开来，将乔奈的身影像被潮水卷走般向后推出去很远。那名还魂者的利爪只抓到了空气。祖法赛喘着粗气，心想这备选方案果然贵得有理。" },
      { kind: "p", text: "“它们退回去重聚了！”祖法赛喊道，“别让它们逃回圆盘！”" },
      { kind: "p", text: "当一名还魂者的形体变得最为稀薄时，祖法赛知道，时候到了。" },
      { kind: "p", text: "“露娜拉——石板！”他喊道。" },
      { kind: "p", text: "露娜拉从角落里跃出，将那块刻有古老咒语的石板抛向他。咒语是她辨认出来的，每一个字符都刻在她的记忆里，但灌注意志发动它的人必须是他——四个人里，没有谁比心灵术士更懂得如何把意志拧成一击。" },
      { kind: "p", text: "祖法赛接住石板。他没有犹豫，将自己全部的精神灌入那些古老的刻痕。那不是用声音发出的咒语，而是用信念——用他逃离凡提·玛夏克时发过的誓，用他对劳役所铁栏后那些同胞的亏欠，用他每一步都计算过、却唯独这一次不计后果的决心。" },
      { kind: "p", text: "一道无形的波动从石板上扩散开来，像一颗石子投入平静的湖面。那波动穿过泰拉克斯，穿过乔奈，穿过露娜拉，最后漫过所有的还魂者。" },
      { kind: "p", text: "还魂者们同时发出一声无声的尖叫，它们的身体像被风吹散的沙一样，开始崩解。绿光熄灭，兜帽落下，阴影消散。金属圆盘上的黑影也暂时平息，像风暴过后的海面。" },
      { kind: "p", text: "“现在！”露娜拉喊道。" },
      { kind: "p", text: "祖法赛的鼻子在流血，蓝色的血珠滴落在黑白石板上。咒语几乎抽干了他，但他看向乔奈，乔奈立刻将引导能量渡入他的体内。" },
      { kind: "p", text: "一股温暖的力量涌入他的四肢百骸，他的意志变得前所未有的清晰。他走向中央的半球形容器，手中捧着艾伊恩宝珠。" },
      { kind: "p", text: "还魂者们重聚的那一刻，尚未到来。" },
      { kind: "p", text: "他把艾伊恩宝珠放入容器内。" },
      { kind: "hr", text: "" },
      { kind: "p", text: "随着一声仿佛透着欢愉的嗡鸣，容器自动关闭并缩回地下。光芒透过石壳映出，悠扬如钟鸣的回声在密室中久久荡漾。" },
      { kind: "p", text: "随着宝珠嵌入，三尊石首的双眼开始散发出蓝色的光芒。左侧石首的声音低沉而悲悯，右侧石首的声音冷峻而清晰，中央石首的声音悠远而庄严。它们齐声开口，三种音色交织在一起，像三重合唱，又像三个不同年代的风同时吹过裂天者的穹顶：" },
      { kind: "p", text: "**“汝等必须点亮信标，以庇护众生免受暗克苏的腐化。汝等已将‘光明’之球艾伊恩宝珠归位，但仍需两枚威力宝珠，两枚遁世之球。魔法之球奥古法宝珠的秘密，掌握在宝石切割师手中。自然之球菲洛森宝珠的奥秘，则为最睿智的术士所通晓。然而，汝等切不可寻觅黑暗之球暗克苏宝珠，因其乃邪秽之物。阿格莫尼亚的命运现系于汝等之手。”**" },
      { kind: "p", text: "语毕，石首重归沉寂，其眼中的光芒随之熄灭。传送装置因能量耗尽而关闭，金属圆盘缓缓降落，不再悬浮。" },
      { kind: "p", text: "四人精疲力竭，但心中满是慰藉。他们缓步走出裂天者，大门在身后轰然紧闭。所幸，钥匙仍在他们手中。" },
      { kind: "p", text: "“两枚威力宝珠。”祖法赛说，“奥古法宝珠在宝石切割师手中，菲洛森宝珠在最睿智的术士手中。”" },
      { kind: "p", text: "“宝石切割师。”露娜拉说，“紫晶教团？”" },
      { kind: "p", text: "“最睿智的术士。”乔奈说，“八贤议会？”" },
      { kind: "p", text: "“我们可能要去拜访一些老朋友了。”祖法赛说。" },
      { kind: "p", text: "“或者结交一些新朋友。”露娜拉说。" },
      { kind: "p", text: "泰拉克斯没有说话。他只是回头望了一眼裂天者，那座塔在夜色中沉默着，像一位完成了使命的老人。他的背脊上，那片光滑的岩石仍在隐隐作痛，但他第一次觉得，那片空白也许正在等待被新的符文填满。" },
      { kind: "p", text: "“我们做到了。”乔奈说。" },
      { kind: "p", text: "“我们只是开始。”露娜拉说。" },
      { kind: "p", text: "他们走下塔来，符文谷的灯火在他们脚下展开，像一片星海。双卫星阿塔与艾蒂悬在头顶，像两只巨大的、发光的眼睛，注视着这座城市的每一个角落。" },
      { kind: "p", text: "阿格莫尼亚的命运，现在真的掌握在他们手中了。" },
      { kind: "hr", text: "" },
    ],
    poem: ["裂天塔上啸声残，", "三尊石首谜局难。", "两真一假谁堪辨，", "还魂四起战未阑。", "一咒古传破幽暗，", "众志同摧敌胆寒。", "艾伊恩珠归正位，", "双珠未集意难安。"],
    battleReport: "（死亡物品清单：无。啊对对队，全员存活。额外收获：守护者长袍×1、艾伊恩宝珠×1（已归位）、古老咒语×1（已使用）。消耗：无。下一站：寻找奥古法宝珠与菲洛森宝珠。）",
  },
  "interlude2": {
    title: "幕间：月光银之月",
    endMark: "【幕间：月光银之月 完】",
    blocks: [
      { kind: "p", text: "月光银之月降临符文谷的那一夜，空气里浮满了馥郁的花粉与孢子。它们从崇高河岸的花园一路漫过白桥，飘进凡俗河岸的市集，再钻进北门区废墟的断墙缝里，像给这座三足鼎立的城市撒了一层发甜的尘埃。夜市上的摊贩一边咳嗽一边抱怨这甜腻的味道呛嗓子，暗地里却又都松了口气——花粉漫城的月份，连劫匪都懒得出门。" },
      { kind: "p", text: "在胜利公园与当地居民攀谈数日之后，啊对对队对统治此地的冠面客家族有了更深的了解。这个家族的势力根基并不稳固——中流砥柱星辰乌苏拉·冠面客与\"选侯\"科斯莫·冠面客都远在首都星港，维护家族在那里的利益，留在符文谷的族人镇不住场子。城里罪案横行，大部分治理权实则落在一个商业行会手中：**紫晶教团**。它的势力遍布整个阿格莫尼亚，从沉寂镇到克鲁索尔皆设有分支，而在符文谷的总部，便是凡俗河岸上那座森然的卡德法尔要塞。教团的唯一对手是八贤议会的术士——那个曾经伟大的学术与魔法团体，如今只剩昔日辉煌的残影，图书馆与实验室蜷缩在崇高河岸的白环之塔里，像一位抱着旧书不肯撒手的老学究。掌管符文谷八贤议会的，是一位人称\"无瑕者\"埃西利特的白发暗瞳格里术士，第一环的大师；而她的死敌，正是紫晶教团的当地主管，焰龙蜥人赫米特·一炎。公园里的老人们说，这两位大人物在街上相遇时，连空气都会结冰。" },
      { kind: "p", text: "崇高河岸还坐落着几座神殿与教堂，其中最令人称奇的，莫过于藏污纳垢的巢穴\"地渊\"，以及里亚博圣物堂。至于第三个区域北门区——那片废墟早已沦为乞丐、罪犯、瘾君子与孤儿的贫民窟，卫兵从不在那里过夜。更令人不安的是，近来磐怒家族频频派出劫掠队袭扰周边的村庄与农场，火光在远方的地平线上一次又一次亮起。有人担心，他们的兵锋甚至可能直指符文谷。" },
      { kind: "p", text: "先民宝库一行之后，四人都感觉到体内某种桎梏被打破了——技艺精进，门路洞开，仿佛有人在各自的修行上推开了一扇新的门。于是，属于他们的月光银之月，就在这座暗流涌动的城市里，各自拉开了序幕。" },
      { kind: "h2", text: "泰拉克斯：一杯遗忘" },
      { kind: "p", text: "五瞳教派的神殿里弥漫着陈香与蜡泪的气味。泰拉克斯效仿教徒的样子蒙住头颅、赤着双脚——岩石脚掌踏在冰凉石砖上，竟也觉出几分虔诚——走近负责铭文的盲眼祭司，蓄须的马顿修士。石头人想学制作卷轴的技艺。" },
      { kind: "p", text: "\"愿先民守护你。\"马顿修士开口，声音像从很深的井里传上来。盲眼祭司的手指抚过泰拉克斯的岩石手臂，在那些被磨平的旧痕上停留了片刻，什么也没问。\"在库提鸦丝绸上书写魔法文字，无需依赖凡俗的肉眼。当你与你的兄弟姐妹们一同唱响圣歌时，便能感受到符文在你体内流淌，然后……睁开你的第五只眼！\"" },
      { kind: "p", text: "第五只眼。泰拉克斯不知道自己的岩石脑门上还能不能长出第五只眼睛，但每当圣歌响起，那些符文的走向、转折、收束，他竟学得意外地快——符文本就刻在他的骨头里，只是被谁磨掉了而已。如今一笔一划重新学起，倒像一个不识字的人重新认回了自己的名字。神殿的日子安静得像一场长眠，而他也正式完成了从地卜师到**守护者**的蜕变：坚不可摧，不动如山，历经万难。奥古拉守护者宛如一道亘古石墙，素以守护盟友、粉碎强敌而闻名——从今往后，每一场战斗，都将化作他石肤上铭刻的一道新符文。挥击武器在他手中能及得更远，一锤递出，敌人要退到比想象中更远的地方才能站稳；他新领悟的**念动**之能，只需一个念头，便能让远处的物品越过战场飞入同伴手中；至于**擒抱**，则是把敌人拽到面前、再赏它一记岩石问候的朴素艺术。" },
      { kind: "p", text: "但学习只是这个月的表象。他真正在办的，是另一件事。" },
      { kind: "p", text: "他走遍了符文谷所有的玻璃吹制工和药剂师，一无所获。玻璃匠们听他描述完那种\"能蚀穿石头\"的酸，纷纷摇头后退，仿佛他口中的不是化学品而是某种诅咒。制革工坊和各色作坊里倒是有不少稀奇古怪的玩意儿，绿的冒烟，紫的起泡，但都不是氢氟酸。最终，他找到一位炼金术士——她的冰窖里恰好存着一些。价格不菲，他付了。结果发现用来保存的冰块更贵，他顿了顿，也付了。最后，他不得不额外雇佣一名北尤提冰霜法师，才把那块危险的东西一路冻着运到了苔石酒馆。这一趟下来花的月光银，够普通人过半年——好在石头人不需要吃饭。" },
      { kind: "p", text: "走进昏暗的奥古拉酒吧时，石灰岩躯体上嵌着化石的酒保奥莫克斯抬起了头。" },
      { kind: "p", text: "\"你找到了？\"他难以置信地问，随即恢复了那副见惯风浪的平静，\"好吧，那就让我来为你调制这杯溶液饮品。\"" },
      { kind: "p", text: "他将水倒入一只铅杯，磨碎一些奥古拉水晶撒了进去。水晶碎屑闪烁着虹彩，缓缓沉向杯底的黑暗，像一场逆向升起的星雨。随后奥莫克斯向冰霜法师点了点头，法师在阵阵寒气中将那块氢氟酸移到杯子上方，投了下去。杯中立刻嘶嘶作响，剧烈沸腾，白烟扭曲着升起，空气里顿时弥漫起一股刺鼻的恶臭。泰拉克斯付了钱，冰霜法师便迅速离开了这个古怪的地方，临走时还回头看了他一眼，眼神像在看一个自愿走上刑场的人。" },
      { kind: "p", text: "它终于出现在他面前：这杯能溶解他所有痛苦记忆的饮品。" },
      { kind: "p", text: "\"你确定要这么做吗？\"奥莫克斯问。" },
      { kind: "p", text: "\"我确定。\"" },
      { kind: "p", text: "他端起冒着热气的铅杯送到唇边。这股气味不知为何竟有些熟悉，仿佛他曾闻过。但这绝无可能。他张开嘴，准备喝下——" },
      { kind: "p", text: "随后，世界陷入一片漆黑。" },
      { kind: "p", text: "他仰面躺着，旧时的持光者导师哈洛克斯就站在身旁。阳光刺眼地照在脸上，刺得他想抬手遮挡，手臂却沉得像山。他感到精疲力竭，他的水晶脆弱而无力。他低头看见自己的身体——灰岩色，布满了原本生长奥古拉水晶的小坑，像一片被陨石反复砸过的荒原。他已经亲手除掉了它们。一颗一颗，亲手。" },
      { kind: "p", text: "有人在触碰他，他转头望去。" },
      { kind: "p", text: "奥莫克斯坐在他身边，凿击着他岩石般的血肉。凿子起落之间，石屑簌簌而落。一个接一个，他将那些刻在身上的记忆磨平。那些他沉睡万古、苏醒又刻下的过往，正变成一堆无名的粉末。" },
      { kind: "p", text: "\"时间到了。\"哈洛克斯说。" },
      { kind: "p", text: "奥莫克斯点点头，站起身，从包里拿出一只铅杯，在里面磨碎奥古拉水晶，哈洛克斯倒进水。一位身材魁梧的奥古拉人走近——肤如黑石，神情庄严，那是马索，另一位持光者。他手里拿着一块冰，里面包裹着某种冒着热气的东西。马索将其交给奥莫克斯，两人交换了一个他没有读懂的眼神。后者用铅钳夹起，投入杯中。杯中顿时沸腾，嘶嘶作响，白烟四溅。" },
      { kind: "p", text: "奥莫克斯小心翼翼地将酸液倒在他的皮肤上。伴随着剧烈的痛楚，它烧蚀掉了符文的最后残余。他没有喊。奥古拉人把疼痛刻进石头，而不是喊进风里。" },
      { kind: "p", text: "随后，他把杯子凑到他的嘴边。" },
      { kind: "p", text: "\"你确定要这么做吗？\"他问。" },
      { kind: "p", text: "\"我确定。\"他听见自己说。" },
      { kind: "p", text: "他喝下酸液，随后遗忘了一切。" },
      { kind: "p", text: "——泰拉克斯躺在苔石酒馆的地板上，空气里弥漫着刺鼻的恶臭。几名奥古拉人围在他身边，有的在清理地上的酸液，有的正试着弄醒他，七嘴八舌的声音像隔着一层深水传来。奥莫克斯就站在他身旁，脸上的表情被酒吧的昏暗灯光切成两半。" },
      { kind: "p", text: "他终于明白，自己第一次走进这间酒吧时，对方脸上那副若有所思的神情意味着什么了。奥莫克斯曾说，见过有同胞用这种混合物摧毁记忆——他只是忘了提，当年亲手摧毁泰拉克斯记忆的人，正是他。" },
      { kind: "p", text: "他挣扎着站起来，感到一阵眩晕。其他人扶着他，引导他坐到一张坚固的石凳上。石凳很凉，很稳，像一句迟到的安慰。" },
      { kind: "p", text: "试图遗忘，反而让他记起了更多。事情本不该是这样。阳光、铅杯、黑石皮肤的马索、还有那句\"时间到了\"——这些碎片如今卡在他的脑海里，比他背脊上残留的水晶碎屑还要锋利。他有一肚子问题想问奥莫克斯——是谁的决定？为什么是他？哈洛克斯说\"时间到了\"，究竟是什么的时间？" },
      { kind: "p", text: "但现在，还不是时候。石头人最擅长的，就是等。" },
      { kind: "h2", text: "祖法赛：隔墙之脑" },
      { kind: "p", text: "里亚博圣物堂里充满了怪异的魔导器、奇异的珍稀物件和无法解释的现象，而里亚博本身或许是这一切中最奇异的存在。它是符文谷唯一的系诺克族个体，这种植物般的生物被魔法缠绕得极深，以至于每句话都像一个谜语。尽管如此，它态度友善，而且显然生意兴隆。" },
      { kind: "p", text: "\"哦，里亚博可以教你们自己酿造药剂，\"它说，枝叶般的肢体在半空中划出一道弧线，\"但这很难！需要特定的原料，而且原料很是短缺。别担心，里亚博不会让你们去采花或摘蘑菇，里亚博有足够的存货。如果你们想学，里亚博可以展示给你们看。\"" },
      { kind: "p", text: "不去采蘑菇这点让祖法赛很是欣慰——队里已经有一个采蘑菇的了，再来一个，菇类迟早要在符文谷绝迹。他在圣物堂学下了炼金术的门道：哪种根茎遇热析出药性，哪种粉末见光失效，哪两种液体相隔三步就会互相污染。顺带，他把草药学也摸了个门儿清。与此同时，他完成了自己的抉择：从心灵法师与水法师之间，他选择了**水法师**。" },
      { kind: "p", text: "这个决定他想了很久。水系魔法对珂蓝安人而言是稀有而珍贵的天赋，天赋持有者往往能跻身近乎造物主的高位，甚至自身晋升为造物主——\"造物主\"三个字在他舌尖上滚了一圈，又被他咽了回去。他见过造物主治下的凡提·玛夏克是什么样子。如果有一天他真的站上那个位置，他希望自己至少记得，曾经有个审查员在深夜的符文谷，替那些排队领薪水的同胞数过铜板。水法师能操控水元素，制造激流、浪潮与风暴；他的法术如今能穿透遮蔽精准命中，再浓的烟也挡不住那条对准目标的细线；新学的**勇猛打击**让他近身也有了一搏之力；而**水流冲击**喷涌而出时，一条直线上的敌人都得尝尝泽布尔海邦的厉害。" },
      { kind: "p", text: "但跟泰拉克斯一样，学习只是表象。他真正在办的，也是另一件事。" },
      { kind: "p", text: "按例溜出劳役所，他去监视穆多克先生。这个肥胖的暗瞳格里商人住在一栋华美的石邸里，位于卡德法尔要塞附近的凡俗河岸，同住的还有他的家人与仆人。监视数日，祖法赛摸清了他何时入睡、卧室的位置——巧的是，他睡在靠外墙的地方。也许可以利用夜晚，在屋外施展精神力量潜入他的大脑？以前没试过这招，但或许行得通。成本近乎为零，收益可能是贝科拉之杖的下落——这笔账，怎么算都划算。" },
      { kind: "p", text: "他回到劳役所继续伪装，在有毒的烟雾里熬完换班，又在夜色掩护下离开。劳役所周围的街区到处是劫匪、娼妓和流浪汉，卫兵不让他们靠近两岸，那些呵斥声隔着两条街都能听见。城市卫兵企图上前盘查，他略施灵能戏法便脱了身——比起思缚者的手段，这些卫兵的脑子简直像没上锁的门。" },
      { kind: "p", text: "很快，他倚靠在墙边，与穆多克的脑袋只隔着一块石砖和一个枕头。夜风从河面上吹来，带着水汽和远处神殿的钟声。他凝神专注，感觉自己的意识游离出躯体，像一滴水银渗进石缝。穆多克睡着了，他能感知到他的思绪——那些梦境油腻而满足，满是一袋袋月光银过手的声响。他开始试探，小心翼翼地翻找，试图找出贝科拉之杖藏在哪里。" },
      { kind: "p", text: "奇怪的是，穆多克似乎确实拥有灵能——但那并非源自贝科拉。那是别的东西。那东西盘踞在意识深处，冰冷、黏腻、警觉，像一条盘在钱箱上的水蛭。当他试探时，那东西躁动起来——" },
      { kind: "p", text: "它发起了反击。" },
      { kind: "p", text: "祖法赛的意识被狠狠弹回躯体，像被人从深海里一把拽出水面。他贴着墙滑坐在地，鼻腔一热，蓝色的血珠滴在衣领上，耳朵里嗡鸣不止。他不敢停留，抹去血迹，沿着阴影一路逃回北门区，心脏狂跳得像是要替他喊出\"救命\"。在逃离的那一瞬间，他在脑海中看到了一幅画面：穆多克先生肥胖的肚子里，寄生着一只强大的灵能寄生虫。正是它赋予了他力量。显然，如果强行将其移除，两者都会丧命。" },
      { kind: "p", text: "那一夜他躺在劳役所的硬板床上，睁着眼睛算账，算到天亮。" },
      { kind: "p", text: "他意识到，自己的力量还不及穆多克强大——不，是不及那只虫子强大。这笔账他算得很清楚：如果已经拥有了贝科拉之杖的第二块碎片，情况就会大不相同。杠杆更长，砝码更重，到那时，连人带虫，一起清算。" },
      { kind: "p", text: "看来，得先找到第二块碎片。然后再来跟这位\"宿主\"先生，连本带利，好好算总账。" },
      { kind: "h2", text: "乔奈：三根手指的雕像" },
      { kind: "p", text: "卡德法尔要塞的符文匠工坊，是奥古拉大师夏克拉斯的匠心之所。工坊内陈列着各式武器、护甲与日常用品，其中不乏散发着魔法灵光的珍品，锤声与凿声日夜不绝，像一颗沉稳的石头心脏在跳。夏克拉斯的身体由灰岩构成，周身雕刻着华丽的印记、符文与马赛克图案，行走时图案随之流动，宛如一件活化的艺术珍品。" },
      { kind: "p", text: "\"无数个长眠之前，\"他用温和的口吻说道，\"我的师傅教会了我通过雕刻符文、为物品注入暂时魔法属性的技艺。我很乐意向你们展示这门手艺。\"" },
      { kind: "p", text: "乔奈在工坊里学会了附文锻造。看夏克拉斯下凿是一种奇异的体验：每一凿都极轻，符文却极深，仿佛不是在刻石头，而是在叫醒石头。她想起盲眼长者教剑时也是这样——最重的道理，都说得最轻。顺带，她把采矿的本事也入了门。而在剑圣与暗克苏猎手之间，她选择了**剑圣**。成长于琥珀门充斥着罪恶的贫民窟，她的生活本就是一场永无止境的生存之战；为了保护挚爱之人免受罪犯与仇敌的侵害，她苦练近身格斗，无论何种奇特的武器护甲，到她手中都能运用自如、如臂使指。她的近战如今愈发致命，新学的**反应攻击**让她能抓住同伴行动后的任何破绽瞬间出手，快得像她的影子替她补了一剑；而**愤怒之刃**挥出时，两记连斩只剩一道残影。" },
      { kind: "p", text: "学艺之余，她顺着里亚博给出的线索，摸到了那个买下她头盔的人。" },
      { kind: "p", text: "那是一名住在卡德法尔要塞附近的高大暗瞳格里女人，头发梳成角状的发髻，身穿带有流动图案的精美焰龙蜥织物，走过市集时，连丝绸商都要对她躬身。乔奈做了些调查：这个女人专门与梅吉亚帝国的焰龙蜥做生意，向圆形市场和符文谷的店主们供应焰龙蜥的产品，有时甚至包括零星的系诺克神器。据说她上个月本该为梅吉亚装备一艘船，却因某种原因推迟了。" },
      { kind: "p", text: "乔奈日夜监视着她的房子。蹲守的间隙，她在屋顶缝隙里种的一小丛蘑菇冒了头——算是意外之喜。一天晚上，女人溜去了\"地渊\"——那个地下世界的巢穴。地渊的空气里混着劣质灯油、汗臭和某种甜得发腻的烟气，乔奈压低头盔，跟了进去。她发现女人正在购买稀有的致幻剂\"梦之卵\"，而且当场吃下了一颗，随后靠着墙滑坐下去，瞳孔里翻涌着不属于这个世界的颜色。她是个瘾君子。当她踉踉跄跄地回家时，乔奈知道，机会来了。" },
      { kind: "p", text: "回去的路上，一个醉汉试图对这位意识不清的女士动手动脚。乔奈从阴影里伸出手，把他推进了墙边的污水沟，动作轻得像拂去一片落叶，然后在女人看见她之前，重新消失于黑暗。她一路护送女人走过卡德法尔要塞——她自己都说不清为什么要这么做，也许盲眼长者会知道答案，也许她已经在成为某种连导师都没教过的东西。仆人开了门，而她从后门潜入了屋内。" },
      { kind: "p", text: "这房子里堆满了奇怪的物品：金色的宗教面具、装着绿色液体的酒瓶、奇怪的小树和精致的挂毯——她完全不知道它们来自阿格莫尼亚的哪个角落。女人爬上楼梯走进办公室，将梦之卵锁进一个柜子，然后回卧室休息。不久，鼾声如雷。" },
      { kind: "p", text: "乔奈悄无声息地取下钥匙，打开柜子。她不想要梦之卵，只想要账本。果然，一张便条赫然在目：她从里亚博那里买下了那顶魔法头盔，并将其交给**恶人贝萨**，以换取禁药。" },
      { kind: "p", text: "就在这时，门外走廊里传来一只肥硕的觅奇兽轻微的脚步声。它会把仆人引来的！" },
      { kind: "p", text: "乔奈保持着纹丝不动，连呼吸都压进了披风的褶皱里。觅奇兽进了屋，五只眼睛在黑暗里扫视一圈，菌丝般的触须几乎擦过她的靴尖——她想起第一章那只叫小菌的同类，想起露娜拉说\"没事了\"的语气。觅奇兽歪了歪头，最终踱了出去。等它离开，她锁好柜子、放回钥匙，从窗户翻进夜色。没人会知道她来过。" },
      { kind: "p", text: "现在，她知道接下来该监视谁了：恶人贝萨。" },
      { kind: "p", text: "几天后，她再次拜访了那名商人——这次，对方清醒多了。" },
      { kind: "p", text: "\"天佑众生。\"身穿焰龙蜥风格长袍的女人说道，请她喝梅吉亚仙人掌酒。口感虽然糟糕——像把整座沙漠的烈日都酿了进去——但乔奈还是喝了。她问女人，以前是否见过像她这样的人。" },
      { kind: "p", text: "\"不完全是。\"女人说，\"我想你大概没去过吉兹吧？\"" },
      { kind: "p", text: "乔奈甚至不知道那是什么。那是系诺克人居住的大陆，部分被梅吉亚帝国征服了，但有些系诺克人成功抵抗了焰龙蜥和恶魔的双重侵袭。吉兹是个美丽的地方，到处是雨林和先民的装置。" },
      { kind: "p", text: "\"就是在那里，我见到了像你这样的女性雕像——只有三根手指和三个脚趾。其中一些，甚至戴着和我从里亚博那儿买来的一样的头盔。也许这就是我想要它的原因。\"女人看着她，目光在那顶发光的头盔上停留了很久，\"但你是我见过的第一个活人。你来自哪里？\"" },
      { kind: "p", text: "乔奈告诉她，自己来自琥珀门。" },
      { kind: "p", text: "\"啊，是的。\"女人笑着掩饰尴尬，\"问问也无妨嘛。\"" },
      { kind: "p", text: "乔奈喝完了酒，听她讲述旅行见闻，却没能了解到更多关于同类的信息。不过至少，她知道了一件事——" },
      { kind: "p", text: "这个世界上，确实还有其他同类。而在某片雨林深处的先民装置旁，立着和她们一模一样的、三根手指的雕像。她低头看了看自己的手。三根手指握拢，又松开。多年来她一直以为自己是一件没有出处的孤品，现在她知道了，自己其实是一尊雕像走失的原型。" },
      { kind: "h2", text: "露娜拉：星辰不负远行人" },
      { kind: "p", text: "偶尔，会有一位神秘的帕天甘女人走进贪食飞龙客栈。她手无寸铁，却让周遭之人无不感到心悸——赌咒发誓的佣兵会压低声音，摔碗的醉汉会自己把碗捡起来。四人很快打听到，她便是洛拉姆，乞丐女王。后来，当他们以为客栈里只剩自己人时，一个声音从阴影中传来：" },
      { kind: "p", text: "\"我听说你们一直在打听我。呵，我也打听过你们。如果你们想学，我可以教你们这游戏的真正玩法。\"" },
      { kind: "p", text: "露娜拉跟着洛拉姆，学会了街头智慧这门贵族教育里绝不会有的专精：哪条后巷的传言三个铜板一条，哪个守门人的软肋是他欠债的弟弟，如何用一枚扣子换一整晚的屋顶。星轮山的女儿学这些学得很快——洛拉姆说，这是因为她眼里有饿意。而在骑士与圣骑士之间，她正式选择了**圣骑士**之道。贝纳姆圣骑士专精于治疗、诗歌与智慧美德，据说他们能直接从星辰汲取特殊力量；也有传言称，他们与被遗忘的异教女神……甚至与艾伊恩本身，存在着某种特殊的联系。她掌心的烙印在那些夜晚隐隐温热，像有人隔着很远很远的地方，回握了她一下。她的治疗如今带着星辰的**祝福**，受她照拂的同伴出手时会如有神助；新学的**盾击**能将敌人连盾带人掀出去，而**正义之刃**挥落时，意志本身便是最锋利的部分。" },
      { kind: "p", text: "符文谷距离星轮山比琥珀门更远，到目前为止，她避开了家族的抓捕——除了表亲布琳娜，那位已背离家族、在符文谷做了女祭司的亲戚，并不构成威胁。她设法先给身在琥珀门的爱人——雷顿·海维德——寄了一封信，随后又在符文谷寄出一封。她无法留下回信地址，只是想让他知道自己很安全。信封封上火漆的那一刻，她盯着那枚没有落款的蜡印看了很久。她想他。这些日子她一直试图与可能了解黑貂王冠内情的地头蛇建立联系，但收效甚微，尽是些后来被证实为虚假的传闻——卖消息的人赚得盆满钵满，她买到的只有一肚子气。" },
      { kind: "p", text: "此外还有另一个问题：要是姐姐用魔法找到了她怎么办？二姐德丽希曾给过她一种违禁药剂，可以掩盖她的灵气，但药效只能维持一段有限的时间。瓶底所剩无多，像沙漏里最后的沙。在药效消退之前，她需要弄到更多。她在圆形市场寻找，一无所获；炼金术士们一听\"掩盖灵气\"四个字就纷纷摇头摆手，帮不上忙。后来，她听说里亚博圣物堂可能有她需要的东西。" },
      { kind: "p", text: "这家店里，墙壁便是地板，地板亦是墙壁。系诺克店主悬浮在半空，显得游刃有余，而要在引力将顾客拉向不同方向的环境里辨别方位，让她胃里一阵翻腾，尾巴都跟着失去了方向感。" },
      { kind: "p", text: "\"有什么能帮您的吗，我的孩子？\"里亚博嗡嗡地说道。" },
      { kind: "p", text: "她说出了自己要找的东西。\"噢，不，那可是违禁品，\"它大声说道，声量大得足以让三条街外都听见。接着，它压低声音，枝叶几乎贴上她的耳朵：\"下周再来。带一颗血水晶给我。\"" },
      { kind: "p", text: "血水晶。只有恶魔崇拜者手中才可能有这种东西——还有，第四章那个从仓库深处搬出来的禁忌木箱里。回客栈取东西的时候，祖法赛盯着那颗血水晶看了很久，嘴唇动了动，显然在心算它的市价，喉结上下滚了两滚，但最终什么也没说，只是摆了摆手，那意思是：记你账上。" },
      { kind: "p", text: "几天后，露娜拉再次进入里亚博圣物堂，将血水晶交给它。里亚博示意她跟上。她走在蜿蜒的楼梯上，当楼梯翻转、整个人倒悬于半空时，她担心自己会坠入深渊——但她依然稳稳地走着，仿佛楼梯真的在脚下，仿佛重力也愿意给这座圣物堂几分薄面。在另一段楼梯上，她与某人擦肩而过，那人竟是横踩在她头顶的墙面上行走的，两人礼貌地点头致意，仿佛这再正常不过。" },
      { kind: "p", text: "终于，她进入一个小房间。墙上摆满了书，中间的桌子上放着点心和酒。她坐了下来。" },
      { kind: "p", text: "\"那么，你拿到神器了吗？\"她焦急地问。" },
      { kind: "p", text: "\"没有，\"里亚博说，\"但我有别的东西。\"" },
      { kind: "p", text: "这是什么？又一次背叛？她转过身，看到了——" },
      { kind: "p", text: "雷顿。" },
      { kind: "p", text: "\"露娜拉。\"他轻声呼唤，拥入她的怀抱。" },
      { kind: "p", text: "她注视着他的眼睛，亲吻并拥抱他。她太想念他了，她一直如此孤独。流亡者的夜晚那么长，长到她几乎忘了被人抱住是什么感觉。噢，雷顿。" },
      { kind: "p", text: "\"里亚博就不打扰你们了。\"里亚博说完便悬浮着离开了，随手关上了身后的门。门关上前，她仿佛听见那株植物发出了一声类似欣慰的嗡嗡。" },
      { kind: "p", text: "他们相拥良久，一言不发。" },
      { kind: "p", text: "随后，她的好奇心占了上风：\"你是怎么找到我的？你又没有法力！\"" },
      { kind: "p", text: "\"我的力量在于头脑。\"他微笑着说，\"我猜你会想要隐藏踪迹，而且为了寻找盾牌，你会留在贝纳姆。所以我告诉那些贩卖魔法商品的小贩，留意任何符合你特征、且想要消失的人。\"" },
      { kind: "p", text: "\"还是你聪明。\"" },
      { kind: "p", text: "\"顺便给你这个。\"他说着递来一瓶违禁的掩饰药剂。她一口气喝了下去——药剂的苦味从舌根一直烧到胃里，但她喝出了甜味。现在，没有任何法师能找到她了。\"如果你还需要更多，里亚博已经答应帮你。那么，你打算如何证明你的清白？\"" },
      { kind: "p", text: "\"我得找到被黑貂王冠偷走的那面飞龙之鳞护盾。\"她告诉他。" },
      { kind: "p", text: "\"黑貂王冠拿走了它？真的吗？\"" },
      { kind: "p", text: "\"他们抢劫了我们整节单轨列车车厢。\"她说。那一天的风、铁轨的震颤、面具后的口令声，她全都记得。" },
      { kind: "p", text: "\"好吧，让我问问家族里有没有人能帮忙。\"" },
      { kind: "p", text: "\"你不觉得他们已经在寻找那些强盗了吗？\"" },
      { kind: "p", text: "雷顿陷入了沉思。\"也许你是对的。\"" },
      { kind: "p", text: "里亚博敲了敲门。\"有客人。\"它说。" },
      { kind: "p", text: "\"我得走了，\"雷顿说，\"我在一家河船旅店订了房间。我们在那里碰头。\"他翻窗离开了，动作利落得不像个没有法力的人。" },
      { kind: "p", text: "母亲身亡，父亲流放了她，如今连姐姐也在追捕她。但至少，雷顿回到了她身边。流亡者什么都没有，但至少，她有这个。" },
      { kind: "p", text: "第二天，她造访了雷顿居住的河船旅店。河水的湿气从窗缝里钻进来，船身随着水波轻轻摇晃。他们整整一天都在温存、用餐，然后再次缠绵。" },
      { kind: "p", text: "\"你知道被流放有什么好处吗？\"雷顿问。" },
      { kind: "p", text: "\"不知道，说给我听听。\"" },
      { kind: "p", text: "\"这样，我们就不必担心还要征求你家族的许可了。\"" },
      { kind: "p", text: "她轻声笑了。\"是啊，但我家那边的反对意见，恐怕比你家还要大。\"" },
      { kind: "p", text: "\"也许他们不必知道。我可以在符文谷买栋房子。他们什么都不会知道的。\"" },
      { kind: "p", text: "她吻了他。但他们都清楚，在她证明清白之前，这是不可能的。窗外，月光银之月的清辉洒在河面上，碎成一千片银子，又被水波一片片收走。" },
      { kind: "hr", text: "" },
      { kind: "p", text: "月光银之月渐渐走向尾声。贪食飞龙客栈的长桌旁，四人又一次聚齐：石头人揣着一肚子还没到时机的问题，指节在桌面上敲出极慢的节拍；心灵术士把目标锁定在了第二块碎片上，账本的下一页已经翻好了；蒙面的剑圣在地图尽头找到了族人存在过的证据，头盔下的目光比平时更亮；而圣骑士的指尖上，还残留着一个失而复得的拥抱的温度。" },
      { kind: "p", text: "城外的原野上，磐怒家族的劫掠队正在逼近；卡德法尔要塞里，恶人贝萨的名字刚刚被写上乔奈的名单；穆多克先生依旧每晚睡在靠外墙的卧室里，浑然不知隔墙有过访客；而在苔石酒馆昏暗的灯光下，奥莫克斯擦着杯子，像是在等一块石头回来问话。" },
      { kind: "p", text: "两颗宝珠仍无下落，裂隙守护者的使命仍在肩头。但这个月教会了他们另一件事——在拯救世界之前，每个人都得先面对自己的过去。" },
    ],
    poem: ["银辉漫洒夜初寒，", "四杰分途觅己难。", "石魄初尝消忆饮，", "灵识夜探隐虫蟠。", "千林石像知来处，", "万里人归诉肺肝。", "月满人间歧路远，", "明朝整旅向新峦。"],
    battleReport: "（死亡物品清单：无。啊对对队，全员存活。额外收获：铭文专精×1、炼金术专精×1（含草药学）、附文锻造专精×1（含采矿）、街头智慧专精×1；泰拉克斯进阶守护者（挥击武器、念动、擒抱）、祖法赛进阶水法师（法术狙击手、勇猛打击、水流冲击）、乔奈进阶剑圣（近战武器精通、反应攻击、愤怒之刃）、露娜拉进阶圣骑士（祝福、盾击、正义之刃）；氢氟酸遗忘之饮×1（已使用）；雷顿·海维德的掩饰药剂×1（已使用）。消耗：血水晶×1（交付里亚博）。新线索：恶人贝萨（乔奈头盔下落）、穆多克体内的灵能寄生虫、吉兹大陆的三指族裔、奥莫克斯的磨平记忆之谜。下一站：追踪恶人贝萨，继续寻找奥古法宝珠与菲洛森宝珠。）",
  },
  "ch6": {
    title: "第六章：极乐洞穴",
    endMark: "【第六章 完】",
    blocks: [
      { kind: "p", text: "垂钓者栈桥的白天比夜晚更热闹。河风裹着鱼腥、桐油和潮湿木料的气味，渔船在栈桥边挤挤挨挨，渔妇的叫卖声、水手的咒骂声、秤杆的敲击声搅成一锅滚粥。啊对对队很快就注意到，这片码头上的扒手、骗子和流氓们似乎都听命于同一个男人——一个帕天甘男子，长着醒目的红色长背鳍，手持一柄华丽长杖，腰带上装饰着细小的头骨。他的宠物宛如一道黏稠且不断游移的阴影，在他脚边爬行，朝每一个靠近的人发出低吼。" },
      { kind: "p", text: "出于某种原因，这名男子主动走近了他们。" },
      { kind: "p", text: "\"各位好汉看起来胆识过人，定能在这荒野险踪中自保！\"他自称谭·古纳吉尔，笑容像他的背鳍一样鲜亮，\"我需要有人从一座废弃的月光银矿里采些蘑菇回来——这城里的地痞流氓根本指望不上。意下如何？利润我们五五分成。噢对了，那些蘑菇个头可不小，最好带些结实的行囊。我记得莉安娜那里卖些便宜的背包。\"" },
      { kind: "p", text: "采蘑菇。祖法赛和露娜拉不约而同地看向乔奈，乔奈的头盔下传出一声轻咳，仿佛在说：专业对口。" },
      { kind: "p", text: "按照栈桥老板的指点，四人在莉安娜的摊上置办了行囊：泰拉克斯买了一只大型背包——反正石头人不在乎分量；露娜拉和乔奈各买了一只中型背包；祖法赛掂了掂自己的胳膊，又掂了掂背包的价格，最后两手空空地走出了店门。力量不够，脑力来凑，他心里自有计较。" },
      { kind: "p", text: "第二天清晨，四人从符文谷西门出城，沿路西行。告别了喧嚣都市，眼前被风拂过的广袤平原令人心旷神怡。空气清新，猎物丰饶，偶尔能遇见居住于此的帕天甘人和暗瞳格里人，彼此遥遥点头致意。他们此行的目的地是由塔巴特家族统治的斯罗伊尔省——境内湖泊与沼泽密布，而那座废弃的月光银矿，藏在省境南部的森林深处。" },
      { kind: "p", text: "林中百兽和鸣，草木芬芳。在第三天的午后，他们找到了极乐洞穴。" },
      { kind: "p", text: "虽不知其名由何而来，但直觉告诉他们，此地绝非听上去那般美好。洞口枯木倒伏，菌盖丛生，一股甜腻得令人反胃的气息扑面而来，像有人把一整季的烂果子埋在了这里。" },
      { kind: "p", text: "\"跟月光银之月的空气一个味儿，\"祖法赛捂住口鼻，\"但是浓了一百倍。\"" },
      { kind: "p", text: "洞窟内宛如梦境。色彩斑斓的律动光芒在岩壁上流淌，奇异的芬芳一层叠着一层。吸入这厚重的空气，一种令人沉醉的怀旧感油然而生——露娜拉闻到了星轮山夏夜的花香，乔奈闻到了渔村灶台上的鱼汤，祖法赛闻到了水下城市罕见的、不用排队的清晨，泰拉克斯闻到了一种他说不出名字、却让他背脊发痒的气息。四人瞬间便明白了\"极乐洞穴\"之名的由来。" },
      { kind: "p", text: "洞内随处可见各色发光的蘑菇与地衣，有的散发着浓郁的麝香味，有的则甜如蜜露。更奇异的是，洞中回荡着类似音乐的声音——细听之下，那节奏竟是由某些蘑菇一张一合发出的。整座城市大小的洞穴，像一支无人指挥的乐队，在演奏一首关于\"留下来\"的歌。" },
      { kind: "p", text: "他们唯一的任务，是寻找那些黑紫色的**夜指菇**。但在这美妙而无忧无虑之地，每个人都得咬着自己的舌尖，才不至于真的长醉于此。" },
      { kind: "p", text: "夜指菇很快找到了。它们的香气能唤起关于往昔的美好回忆，靠近它们本身就是一种喜悦；可伸手采摘时，四人心里却都升起一股负罪般的忧郁，仿佛摘下的不是蘑菇，而是某段再也回不去的时光。此物极为脆弱，必须用软布垫着、轻拿轻放——泰拉克斯的大型背包里垫了三层乔奈贡献出来的备用披风。" },
      { kind: "p", text: "采集分三个方向：南方的悬崖下方需要从正东绕路下去，正北方向的小山坡可以绕一圈回来，东北方向的高地同样需要从正东上去。" },
      { kind: "p", text: "乔奈独自去了正北。山坡背阴处，两株**蛇根草菇**静静立在苔藓里，伞盖上盘踞着蛇鳞般的纹路——剧毒，却是药剂师求之不得的好东西。她蹲下身，短剑贴着根部切入，手腕稳得像外科医师，两株毒菇完好无损地落进了她的草药小布袋。采蘑菇这件事，她可是专业的。" },
      { kind: "p", text: "其余三人从正东出发。行至岔路，祖法赛和泰拉克斯沿着山路往南方去，露娜拉则独自向东北方向的高地攀登。" },
      { kind: "p", text: "南方的悬崖下方，祖法赛先听见了一阵窸窸窣窣的响动——一处**觅奇兽巢穴**。拳头大小的觅奇兽们挤作一团，五只眼睛警惕地盯着来客。祖法赛没有掏武器，而是蹲下来，把意识轻轻递了过去。冰冷的回响在巢穴里荡开，他把意图摊成最简单的画面：蘑菇，搬动，报酬——一小袋从栈桥买的鱼干。为首的觅奇兽歪着头打量他半晌，又看了看他空空如也的双手和同样空空如也的肩膀——没有背包的人类，在觅奇兽的价值观里大约属于需要救济的对象。默契达成：它帮他们搬运夜指菇，他付鱼干，概不赊账。" },
      { kind: "p", text: "\"看见没有，\"祖法赛对泰拉克斯说，\"这就是不买背包的解决方案。\"" },
      { kind: "p", text: "\"外包。\"泰拉克斯总结道，石头人的用词精准得像一刀裁过。" },
      { kind: "p", text: "与此同时，泰拉克斯在悬崖侧壁上发现了别的东西——岩石的纹理里嵌着熟悉的暗色脉络，是**拉尼姆矿床**。地卜师的本能顺着石缝苏醒，他徒手抠进岩壁，两块沉甸甸的拉尼姆矿石落进掌心，断口处泛着冷冽的金属光。" },
      { kind: "p", text: "他继续往悬崖尽头走。然后，他看见了那两具尸体。" },
      { kind: "p", text: "两人静静地躺在菌毯上，脸上都带着欣喜若狂的表情，仿佛在此辞世是他们平生最美之事。一名女性帕天甘人的背心内塞着一卷卷轴——两个卷轴缠绕在同一根轴杆上。第一卷是魔法卷轴，诵读时能提供少量治疗；第二卷则是一封信。信是黑貂王冠的亡命徒留下的：他们在洞穴东北角藏匿了一批物资，但显然，他们宁愿选择极乐，而非财富。" },
      { kind: "p", text: "泰拉克斯把卷轴收好，替他们合上了眼睛。死者脸上的笑容太过幸福，让他这个石头人都觉得后背发凉。" },
      { kind: "hr", text: "" },
      { kind: "p", text: "东北方向的高地上，露娜拉正在经历她人生中最离奇的一次攀登。" },
      { kind: "p", text: "自从进入极乐洞穴，她已经产生过各种疯狂的幻觉：会飞的乌龟、倒着走路的星辰玛丽昂、还有一只开口背诵税则的蘑菇。她渐渐摸索出了对付它们的办法——不和幻觉讲道理。幻觉这东西，你越搭理，它越来劲。所以当她看见一只巨型蛞蝓正从背部的吸盘中喷出火焰时，她只是疲惫地叹了口气。" },
      { kind: "p", text: "又来了。" },
      { kind: "p", text: "等等。她能感受到那灼人的热浪。" },
      { kind: "p", text: "幻觉不会烤焦她的眉毛。" },
      { kind: "p", text: "**这只鸣炙蛞蝓是真的！**" },
      { kind: "p", text: "巨蛞蝓足有小船大小，灰褐色的躯体在菌毯上犁出一道冒着青烟的焦痕。它背部一圈吸盘次第张开，每一只都像烧红的炉口，张开时发出湿热的吸气声——她立刻记下了这个细节：吸气声，就是喷火的前兆。火焰喷涌而至，露娜拉举盾硬接，旧盾发出不堪重负的呻吟，盾面的飞龙纹章被热浪舔得发烫，她的掌心隔着盾带都感到了灼痛。" },
      { kind: "p", text: "她试着进攻。第一剑砍在蛞蝓的侧腹，像砍进浸透水的皮革，只留下一道白印。第二剑她用了**英勇打击**，剑刃终于没入半寸，蛞蝓却只是缓慢地转过头，仿佛那一剑只是替它挠了痒。紧接着，它背部三只吸盘同时张开——吸气声响起，她读懂了这个节奏，猛地向侧翼翻滚，火焰擦着她的斗篷扫过，把她方才立足的菌毯烧成了一片火海。" },
      { kind: "p", text: "不能力敌。她在一息之间完成了判断：凭她一人，绝无可能杀死这头怪物。但她也立刻明白了自己必须做什么——这条蛞蝓爬行的方向，正是祖法赛他们采集夜指菇的方向。她杀不死它，但她可以拖住它。她可以输，却不能让开这条路。" },
      { kind: "p", text: "于是她把自己变成了一根钉子。" },
      { kind: "p", text: "蛞蝓喷火，她就举盾硬顶；火焰停歇的间隙，她就用**盾击**砸向它最前排的吸盘，不求杀伤，只求激怒——让它眼里只有她。巨兽每一次调转躯体，她都抢先半步横移，用自己的身体重新堵住通往低洼处的坡道。它向左，她就向左；它试图绕开，她的剑就招呼在它的吸盘上，把它满腔的怒火重新勾回自己身上。热浪一波接着一波，她的旧盾烫得几乎握不住，盾带深深勒进小臂，锁甲的边缘开始卷曲、焦黑。**快速治疗**的暖光一次接一次在她肩头绽开，修复着灼伤，又立刻被下一波热浪逼退。" },
      { kind: "p", text: "汗水流进眼睛，她不敢抬手去擦。火光里，她想起了母亲。" },
      { kind: "p", text: "母亲从不教她怎么赢，母亲教她的是怎么站。星轮山骑士的第一课不是挥剑，而是列队——站在自己的位置上，哪怕整条战线都在后退。后来她流亡、被通缉、被全世界背叛，可只要她还站着，布林德利昂家就还有一个人没有倒下。这面补过三次的旧盾此刻烫得像块烙铁，她反而握得更紧了。盾在，位置就在。" },
      { kind: "p", text: "掌心的艾伊恩印记在绝境中隐隐发烫，那股温热诱惑着她——只要一次，只要一次，就能让这一身灼伤痊愈。她把那个念头狠狠按了下去。还不到时候。这场战斗才刚刚开始，她的同伴还散落在这片洞穴的某处，真正的绝境也许还在后面。流亡者最宝贵的品质不是勇敢，是忍耐。她要把最后的底牌，留到非翻开不可的那一刻。" },
      { kind: "p", text: "\"来啊。\"她吐掉嘴里的血腥味，银发被热浪烤得打卷，声音却稳得像在星轮山点兵，\"你的对手是我。只是我。\"" },
      { kind: "p", text: "蛞蝓似乎听懂了。它背部的吸盘齐刷刷张开，像一圈同时睁开的、燃烧的眼睛。" },
      { kind: "p", text: "它就这样在她的拖延中耗掉了宝贵的整整一刻。而远处，洞穴深处，第一声属于同伴的怒吼，终于顺着岩壁传了过来。" },
      { kind: "hr", text: "" },
      { kind: "p", text: "与此同时，西北方向的低洼处，祖法赛正盯着地面上一团冒着气泡的亮绿色真菌黏液出神。黏液之中包裹着一名暗瞳格里矿工的遗骸，身旁还有一把镐和一个行囊。他周围的磷光真菌为洞穴笼罩上一层诡异的光晕，把那张不知死了多久的脸照得忽明忽暗。" },
      { kind: "p", text: "祖法赛皱着眉伸出手，探向那团绿色胶状物，想够到那个行囊——指尖传来又湿又酸的触感，而且……" },
      { kind: "p", text: "它还在动。" },
      { kind: "p", text: "这根本不是什么真菌。黏液轰然立起，比他还高出一个头，矿工的骸骨在它透明的躯体里缓缓旋转——一只**浊涎怪**，直立于他面前。" },
      { kind: "p", text: "\"乔奈——！！\"祖法赛的喊声和心灵尖啸同时炸响。" },
      { kind: "p", text: "浊涎怪当头罩下，他狼狈地翻滚躲开，方才站立的岩石被酸液蚀出一道白烟。他抬手，**水流冲击**脱膛而出——激流像一杆水做的长枪，从黏液的正中贯穿而过，浊涎怪的躯体被冲得稀烂，却在两息之后重新聚拢，流动着、嘶鸣着，把骸骨又卷回了身体中央。" },
      { kind: "p", text: "物理意义上的\"打散\"对它毫无意义。祖法赛的心灵感应探过去，只触到一片空无——这东西没有心智，没有恐惧，没有任何可以讨价还价的念头。这是他这辈子遇到过的最不讲道理的谈判对象。" },
      { kind: "p", text: "\"左边！\"乔奈的声音从坡道方向传来。她采完蛇根草菇，循着喊声赶到，仪式之矛已擎在手中。" },
      { kind: "p", text: "浊涎怪分裂出的酸液触手横扫过来，乔奈矮身避过，矛尖在怪物体内一搅——没有骨骼，没有要害，只有搅不完的黏液。她旋身后撤，一滴酸液溅上披风，艾伊恩的微光嘶地暗了一小块。" },
      { kind: "p", text: "\"扎不透，砍不散，\"她快速说道，\"但它得贴着地面流动。\"" },
      { kind: "p", text: "\"地面……\"祖法赛的目光落在那圈磷光真菌上，落在矿道岩壁上渗水的裂缝上。他是水法师。这片洞穴里，水听他号令。" },
      { kind: "p", text: "\"把它抬起来。\"他说。" },
      { kind: "p", text: "乔奈没有再问。她挺矛上前，**真实打击**直取黏液最浓稠的核心，骸骨在她矛尖下咔啦作响，逼得浊涎怪把整个躯体都压向她这一侧——而就在它离地的瞬间，祖法赛双手猛然上提。岩缝里的水、菌毯下的潮气、空气里的湿意，全被拧成一股无形的力量，将这团酸液凭空托离了地面。" },
      { kind: "p", text: "没有凭依的黏液在半空中疯狂扭动。乔奈等的就是这一刻——**愤怒之刃**出鞘，两记连斩快得只剩一道残影，矛锋过处，浊涎怪的核心被搅得粉碎。绿色黏液如雨落地，这一次，再也没有聚起来。矿工的骸骨轻轻落在菌毯上，镐和行囊滚到一旁。" },
      { kind: "p", text: "乔奈用矛尖挑开行囊，把里面的东西归拢到骸骨手边。她没有说话，但那个动作本身就是一种安葬。" },
      { kind: "p", text: "战斗结束不久，泰拉克斯缓慢地从悬崖方向爬了上来——石头人的攀爬速度，懂的都懂。他把两具尸体和黑貂王冠密信的事共享给二人。乔奈展开信纸扫了一遍，目光立刻投向东北角。" },
      { kind: "p", text: "有了信上的指引，那处魔法幻象变得像个蹩脚的把戏：一片看起来平平无奇的岩壁，纹理的重复处多了一次不该有的重复。她径直走过去，手臂穿过幻象，后面藏着一处小洞穴——" },
      { kind: "p", text: "洞穴里，一尊工艺精湛的**拉尼莫拉雕像**静静矗立。异教女神的面容在微光中显得悲悯而傲慢，石料打磨得温润如玉，每一处衣褶都透着失传的匠心。雕像脚下，钱币堆得像一座小小的金山。" },
      { kind: "p", text: "只可惜，背包里塞满了夜指菇，再没有空间带走钱币。乔奈掂了掂那尊沉重的雕像，又看了看那座钱堆，果断抱起雕像就走。钱可以再赚，女神只有一个。" },
      { kind: "p", text: "就在此时，洞口方向传来一声闷响——他们进入极乐洞穴的入口，又出现了另一只巨大的鸣炙蛞蝓。" },
      { kind: "hr", text: "" },
      { kind: "p", text: "两只鸣炙蛞蝓，一只在东北高地被露娜拉死死牵制，一只正从入口向洞穴深处游来。腹背受敌，蘑菇还在地上。" },
      { kind: "p", text: "\"泰拉克斯——蘑菇！\"祖法赛喊道。" },
      { kind: "p", text: "石头人心念一动，**念动**催发。装满夜指菇的背包和竹篮凭空浮起，越过燃烧的菌毯，稳稳落进远处一处背火的石凹。觅奇兽叼着自己那一份，哧溜一下蹿进了缝隙。战场，清空了。" },
      { kind: "p", text: "\"乔奈，接好了。\"乔奈不等他说完，**引导能量**已经渡入泰拉克斯的岩石躯体。" },
      { kind: "p", text: "\"露娜拉，撑住，我们来了！\"祖法赛的心灵之音直抵东北高地。" },
      { kind: "p", text: "四人在洞穴中段完成汇合，又一起杀向东北——先解露娜拉之围。露娜拉的旧盾已经烫得握不住，锁甲边缘燎出了焦痕，但当她看见洞口方向冲来的同伴时，那个瞬间她几乎笑出声。" },
      { kind: "p", text: "\"泰拉克斯，左边顶住！\"她的指挥本能全线苏醒，\"乔奈策应！祖法赛，把它推回火里去！\"" },
      { kind: "p", text: "泰拉克斯轰然落位，像一堵石墙砸进两只蛞蝓之间。**擒抱**发动，岩石手臂扣住第二只蛞蝓的吸盘边缘，硬生生把这个喷火的庞然大物拖拽着转了个方向——火焰尽数喷向了空无一人的洞壁。引导能量在他体内奔流，**泰拉克斯之锤**裹挟着远超往常的沉重符文之力轰然砸落，一锤，又一锤，锤头的符文明灭如岩浆呼吸。蛞蝓坚韧的皮肤在这等重击下终于凹陷、撕裂。" },
      { kind: "p", text: "祖法赛的**水流冲击**贴着地面灌进蛞蝓身下，激流冲垮了它黏附的根基；乔奈的仪式之矛如银色闪电，**反应攻击**抓住露娜拉盾击逼退的每一个空当，矛矛都点在吸盘张开的瞬间。露娜拉的**祝福**落在每个人身上，受她治疗过的泰拉克斯出手愈发沉重，而她的**正义之刃**每一次挥落，都带着不容置疑的意志之力。" },
      { kind: "p", text: "第一只蛞蝓在围攻中瘫软下去，背部的吸盘一只接一只熄灭，像打烊的店铺次第关灯。第二只试图向洞口逃窜，被泰拉克斯一锤截住去路，四人的攻势随即合拢。" },
      { kind: "p", text: "然而，这场鏖战早已超出了这座废弃矿洞的承受极限。锤击的震颤顺着岩壁传进矿脉深处，火焰日夜炙烤的拱顶发出令人牙酸的呻吟。战斗结束的刹那，四人听见了那个声音——起初是细碎的崩裂，像踩碎的薄冰，随即连成一片，从洞穴最深处的黑暗里滚滚而来。" },
      { kind: "p", text: "\"洞要塌了！\"泰拉克斯吼道。" },
      { kind: "p", text: "蘑菇的音乐骤然走调。整支无人乐队在崩裂声里乱了节拍，那些发光的菌盖一片片黯淡下去，像被一只无形的手挨个掐灭的烛火。" },
      { kind: "p", text: "\"采！能拿多少拿多少！\"露娜拉一声令下。四人扑向石凹，把完好的夜指菇连同软布整篮整篮地塞进背包，觅奇兽叼着它那份鱼干和蘑菇，在乱石间蹿成一道灰影。落石开始在四周炸开，泰拉克斯用身体护住背包，碎石在他背脊上敲出密集的闷响。" },
      { kind: "p", text: "他们向着洞口狂奔。身后，东北角的方向传来一声闷雷般的轰响——乔奈回头望了一眼。那处藏着钱币金山的小洞穴，连同黑貂王冠的宝藏，永远地合上了。更深处，悬崖下那两具带着幸福笑容的亡命徒、低洼处那位无名矿工，也被这座洞穴一并收了回去。它给了他们极乐，如今连坟墓也一并施舍了。" },
      { kind: "p", text: "四人一马当先的觅奇兽冲出洞口的瞬间，整座极乐洞穴在身后轰然合拢。烟尘从岩缝里喷涌而出，又缓缓落定。蘑菇的歌声，永远地停了。" },
      { kind: "p", text: "他们瘫坐在洞外的草地上，胸膛剧烈起伏。代价是实实在在的：露娜拉的手臂起了大片水泡，乔奈的披风被燎穿了两个洞，泰拉克斯的肩上缺了一角碎石，祖法赛的鼻血把衣襟染成了深蓝色。而在最后的崩塌与奔逃中，有几篮夜指菇被掀翻、被落石砸碎，损毁了一些。觅奇兽围着破损的蘑菇转了两圈，发出一串惋惜的吱吱声。" },
      { kind: "p", text: "走出很远之后，四人才停下脚步，深深吸入了一口新鲜空气。离开那迷人的岩洞不免让人心生怅惘——那股甜腻的怀旧仍在血液里流连，像一场被强行叫醒的午觉。而直觉早已告诉过他们，久留于此绝非明智之举；如今洞穴选择了自我了断，把它的秘密、它的宝藏和它的死者，统统埋进了永恒的黑暗。返回符文谷的途中，他们悉心守护着采摘到的夜指菇。那些奇异的幻象与情绪在记忆中萦绕，几天之后，终于变得如同童年旧梦般遥不可及。" },
      { kind: "p", text: "在镇上的垂钓者栈桥，他们寻到了谭·古纳吉尔。靠近时，他那如影子般的宠物马佐格冲着他们狂吠不止。" },
      { kind: "p", text: "\"噢，是你们！马佐格还以为再也见不到各位了呢。\"谭·古纳吉尔笑着迎上来，红色背鳍在河风中微微抖动，\"但我知道你们有这份胆识。希望你们没吸入太多那种蘑菇迷瘴。夜指菇到手了吗？\"" },
      { kind: "p", text: "他们将那些深紫色的蘑菇递过去。谭仔细地端详了一番，指尖拂过伞盖，眼中闪过一丝行家的满意。" },
      { kind: "p", text: "\"初次采集能有这水准，还算不错。可惜最近夜指菇价格下跌，再加上我有些意外的开销……\"他话锋一转，把手伸进钱袋，\"不过，我仍会按约定付清欠你们的酬劳。拿着。\"他顿了顿，\"之后我或许还有别的差事找你们。回头见。\"" },
      { kind: "p", text: "报酬落袋，事情本该到此为止。但那尊从极乐洞穴里运出来的拉尼莫拉神像，还裹在粗布中，静静躺在泰拉克斯的背包旁。" },
      { kind: "p", text: "黑貂王冠曾将其藏匿于洞穴，想必他们会乐于见到神像回归。另一方面，异教是被明令禁止的——星象学会正严密监控并铲除一切迷信痕迹，且对上缴异教神像者提供奖赏。而在垂钓者栈桥周边的黑市卖给走私者，或许能换取最高报酬：某些珂蓝安人或焰龙蜥人收藏家，定会为了这尊极具异域风情的神像支付大笔月光银。" },
      { kind: "p", text: "三条路，三个价钱。祖法赛的算盘噼啪作响：星象学会的奖赏是公价，黑市的报价是行情，而凯隆的出价——多半是最低的。但有些东西不在价目表上。" },
      { kind: "p", text: "\"我知道黑貂王冠一向尊崇异教女神。\"露娜拉开口了，声音很平，平得像结了冰的河面。他们劫走的那节单轨列车车厢里，有她的飞龙之鳞。这笔账她一刻都没有忘。但也正因为如此，凯隆这条线，她比谁都舍不得断。" },
      { kind: "p", text: "于是，四人带着神像，前往贪食飞龙酒馆找到了凯隆。" },
      { kind: "p", text: "\"星辰在上，这东西你们是从哪儿弄来的？\"凯隆的目光落在拉尼莫拉悲悯而傲慢的面容上，整个人都怔住了，随即摆了摆手，\"算了，不提也罢。是的，我当然非常感兴趣。拉尼莫拉……也许是我们最敬爱的女神。我们手头并不宽裕，但我会尽我所能酬谢你们。\"" },
      { kind: "p", text: "酒馆里的烛火跳动着。露娜拉看着这位黑貂王冠头目小心翼翼地抚摸神像的衣褶，那神情近乎虔诚。她忽然意识到，女神回家的这条路，或许也正是通向她自己的盾牌的那条路。" },
    ],
    poem: ["夜指菇香洞里幽，", "酣歌醉影幻中流。", "悬崖寂骨抱残卷，", "四杰同心孽焰收。", "秘窟寻来神像古，", "菇归换得薄薪酬。", "人间极乐终非土，", "万里征程志未休。"],
    battleReport: "（死亡物品清单：夜指菇若干（战斗与崩塌中损毁）。啊对对队，全员存活。额外收获：夜指菇酬劳×1（五五分成）、拉尼姆矿石×2、治疗卷轴×1、剧毒蛇根草菇×2、拉尼莫拉雕像×1（已交付凯隆）、谭·古纳吉尔的后续差事意向×1、觅奇兽搬运工的友谊×1。极乐洞穴已在战斗中崩塌，黑貂王冠藏匿的钱币随之长埋，无法重返。下一站：静候谭·古纳吉尔的新差事，继续追踪恶人贝萨。）",
  },
}
